def _read_config_file(path):
    """Return a parsed dict from `path`, or None if missing / unreadable / not a dict.

    Treating a missing file the same as a corrupt one is intentional — load_config
    layers a .bak fallback on top so the caller never has to distinguish.
    """
    try:
        with open(path, "r") as f:
            data = json.load(f)
        if isinstance(data, dict):
            return data
    except Exception:
        pass
    return None


def load_config():
    """Read the live config, falling back to the .bak sibling if the primary
    file is missing, corrupt, or temporarily locked.

    The legacy implementation returned `{}` whenever the read failed for any
    reason. Combined with the merge-on-save flow, that meant a single read
    glitch (AV scan, partial write, transient lock) silently reset the config
    on the next `save_config` — wiping recent_* lists across every tab.
    """
    primary = _read_config_file(CONFIG_PATH)
    if primary is not None:
        return primary
    backup = _read_config_file(CONFIG_BAK_PATH)
    if backup is not None:
        return backup
    return {}


def save_config(data):
    """Merge `data` into the live config; never overwrites unrelated keys.

    The write goes through a sibling `.tmp` file + `os.replace` so a process
    kill or filesystem interruption mid-write can no longer leave a partial
    JSON on disk. After the live file is replaced, it is mirrored to `.bak`
    so a future read failure has a known-good fallback.
    """
    try:
        cfg = load_config()
        cfg.update(data)
        tmp_path = CONFIG_PATH + ".tmp"
        with open(tmp_path, "w") as f:
            json.dump(cfg, f, indent=2)
            try:
                f.flush()
                os.fsync(f.fileno())
            except Exception:
                pass
        os.replace(tmp_path, CONFIG_PATH)
        # Mirror the successful write to .bak so the next launch has a
        # fallback if the primary file becomes unreadable.
        try:
            shutil.copyfile(CONFIG_PATH, CONFIG_BAK_PATH)
        except Exception:
            pass
    except Exception:
        pass


