def _pretty_log_segments(text):
    """Split log text into themed token groups for Tk Text tags."""
    text = "" if text is None else str(text)
    specials = [
        ("WARNING", "log_warning"),
        ("ERROR", "log_error"),
        ("FAILED", "log_error"),
        ("SUCCESS", "log_success"),
        ("✓", "log_success"),
        ("✔", "log_success"),
        ("✗", "log_error"),
        ("⚠", "log_warning"),
        ("ℹ", "log_info"),
    ]
    out = []
    i = 0
    n = len(text)
    while i < n:
        matched = False
        for token, tag in specials:
            if text.startswith(token, i):
                out.append((tag, token))
                i += len(token)
                matched = True
                break
        if matched:
            continue
        ch = text[i]
        if ch.isdigit():
            j = i + 1
            while j < n and text[j].isdigit():
                j += 1
            out.append(("log_number", text[i:j]))
            i = j
        elif ch.isalpha():
            j = i + 1
            while j < n and (text[j].isalpha() or text[j] in "'’"):
                j += 1
            out.append(("log_text", text[i:j]))
            i = j
        elif ch.isspace():
            j = i + 1
            while j < n and text[j].isspace():
                j += 1
            out.append(("log_text", text[i:j]))
            i = j
        else:
            out.append(("log_flair", ch))
            i += 1
    return out


def _yt_resolve_js_runtimes(custom_node_path=""):
    """Detect installed JavaScript runtimes for yt-dlp's signature solver.

    yt-dlp v2025+ only auto-enables `deno`; Node.js (and others) have to be
    named via `--js-runtimes RUNTIME[:PATH]`. ParaKit detects both Node and
    Deno across four placement tiers:

        0. User-specified path (custom_node_path) — checked first.
        1. PATH (`shutil.which`) — the simplest case.
        2. Bundled inside ParaKit's `Requirements\\` folder. The "Get Deno"
           button on the YouTube tab drops `deno.exe` here.
        3. Standard system install paths (`C:\\Program Files\\nodejs\\`, etc.)
           so a fresh Node install registered in the registry is found even
           when the running process has a stale PATH.
        4. Per-user install paths (`~/.deno/bin/`, etc.).

    Returns a list of `(name, full_path)` tuples for whichever runtimes
    were found. Empty list = nothing detected.
    """
    found = []

    # Build node.exe candidates — user path (if set) is tried first.
    node_candidates = []
    if custom_node_path:
        p = custom_node_path.strip()
        # Accept either the exe itself or the directory containing it.
        if os.path.isdir(p):
            p = os.path.join(p, "node.exe")
        node_candidates.append(p)
    node_candidates += [
        shutil.which("node"),
        _external_path("node.exe"),
        _external_path(os.path.join("node", "node.exe")),
        r"C:\Program Files\nodejs\node.exe",
        r"C:\Program Files (x86)\nodejs\node.exe",
    ]
    for p in node_candidates:
        if p and os.path.isfile(p):
            found.append(("node", p))
            break

    deno_candidates = [shutil.which("deno")]
    deno_candidates += [
        _external_path("deno.exe"),
        os.path.join(os.path.expanduser("~"), ".deno", "bin", "deno.exe"),
        r"C:\Program Files\deno\deno.exe",
    ]
    for p in deno_candidates:
        if p and os.path.isfile(p):
            found.append(("deno", p))
            break

    return found


def _yt_extra_error_guidance(log_text):
    """Return extra user-facing guidance for known yt-dlp failure patterns."""
    text = (log_text or "").replace("\r\n", "\n")
    lower = text.lower()
    lines = []

    has_bot_challenge = (
        "sign in to confirm you" in lower and "not a bot" in lower
    ) or ("cookies-from-browser" in lower)
    has_js_warning = (
        "no supported javascript runtime could be found" in lower
        or "signature solving failed" in lower
        or "n challenge solving failed" in lower
        or "only deno is enabled by default" in lower
    )
    has_cookie_copy_lock = "could not copy chrome cookie database" in lower

    if has_bot_challenge:
        lines.extend([
            "",
            "  ParaKit note:",
            "    YouTube blocked this request before the download could start.",
            "    This is a YouTube / yt-dlp authentication challenge, not an audio conversion bug.",
            "    If this keeps happening, try the YouTube tab's Browser session or cookies.txt mode.",
            "    Workarounds: try the link again later, try a different source/video, or use a",
            "    signed-in browser session / cookies.txt file for this exact upload.",
            "    yt-dlp's FAQ says this workaround reportedly works best with Firefox, and",
            "    that some users have reported problems getting it to work with Edge.",
        ])

    if has_cookie_copy_lock:
        lines.extend([
            "",
            "  ParaKit note:",
            "    Chromium-based browser cookie database appears to be locked.",
            "    This is a known yt-dlp / Windows issue when Edge, Chrome, Brave, Opera,",
            "    or OperaGX is still open or left running in the background.",
            "    Close Edge completely, then retry. If needed, close all Chromium-based",
            "    browsers and wait a few seconds before trying again.",
            "    If it still fails, use cookies.txt mode instead of Browser session.",
        ])

    if has_js_warning:
        lines.extend([
            "",
            "  JavaScript runtime / signature-solver issue:",
            "    yt-dlp could not solve YouTube's signature challenge — usually",
            "    that means no supported JS runtime is reachable from this process.",
            "    Install Node.js (https://nodejs.org/) or Deno (https://deno.com/),",
            "    then fully close and relaunch ParaKit so the new install is",
            "    picked up. ParaKit auto-detects Node/Deno on launch and passes",
            "    the right --js-runtimes flag to yt-dlp.",
        ])

    return lines


def _yt_looks_like_path(value):
    value = (value or "").strip()
    if not value:
        return False
    return (
        "\\" in value or "/" in value or
        re.match(r"^[A-Za-z]:", value) is not None or
        value.startswith("~")
    )


def _yt_default_browser_profile(browser_choice, platform_name=None):
    platform_name = (platform_name or sys.platform or "").lower()
    if browser_choice == "OperaGX" and platform_name.startswith("win"):
        appdata = os.environ.get("APPDATA")
        if appdata:
            return os.path.join(appdata, "Opera Software", "Opera GX Stable")
    return ""


def _yt_cookie_args(cookie_mode, browser_choice, profile_value, cookies_path, platform_name=None):
    cookie_mode = (cookie_mode or "none").strip().lower()
    profile_value = (profile_value or "").strip()
    cookies_path = (cookies_path or "").strip()
    browser_map = {
        "Chrome": "chrome",
        "Edge": "edge",
        "Firefox": "firefox",
        "Brave": "brave",
        "Opera": "opera",
        "OperaGX": "opera",
    }

    if cookie_mode == "file":
        return ["--cookies", cookies_path] if cookies_path else []

    if cookie_mode != "browser":
        return []

    browser_name = browser_map.get(browser_choice or "")
    if not browser_name:
        return []

    profile_arg = profile_value
    if browser_choice == "OperaGX":
        if not profile_arg:
            profile_arg = _yt_default_browser_profile(browser_choice, platform_name)
        elif not _yt_looks_like_path(profile_arg):
            default_root = _yt_default_browser_profile(browser_choice, platform_name)
            if default_root:
                profile_arg = os.path.join(os.path.dirname(default_root), profile_arg)

    if browser_choice == "Opera" and profile_arg and not _yt_looks_like_path(profile_arg):
        profile_arg = ""

    if profile_arg:
        return ["--cookies-from-browser", f"{browser_name}:{profile_arg}"]
    return ["--cookies-from-browser", browser_name]

# ---------------------------------------------------------------------------
# External-file path resolver — supports both legacy "everything next to
# ParaKit.exe" layout and the optional "Requirements\" subfolder layout.
# ---------------------------------------------------------------------------
def _external_base_dir():
    """Return the folder ParaKit.exe (or ParaKit v4.0.py in source mode) lives in."""
    if getattr(sys, 'frozen', False):
        return os.path.dirname(sys.executable)
    return os.path.dirname(os.path.abspath(__file__))


def _external_search_dirs():
    """Return ordered list of directories to search for sibling files/dirs.

    Requirements\\ wins when present so a user with the new clean layout
    gets that path back; the legacy next-to-EXE folder is always also
    searched as a fallback.
    """
    base = _external_base_dir()
    out = []
    req = os.path.join(base, "Requirements")
    if os.path.isdir(req):
        out.append(req)
    out.append(base)
    return out


def _external_path(name, *, for_writing=False):
    """Resolve a file/dir that ships alongside ParaKit.

    Reading (default):
      Returns the existing path inside Requirements\\ if present, else the
      legacy path next to the EXE. The legacy path is returned even when
      nothing exists on disk so callers can show a "missing" status.

    Writing (for_writing=True):
      Returns the Requirements\\ path when Requirements/ exists, else the
      legacy next-to-EXE path. Used as a download/create target so new
      installs land in the clean folder while existing installs keep the
      legacy layout untouched.
    """
    dirs = _external_search_dirs()
    if for_writing:
        return os.path.join(dirs[0], name)
    for d in dirs:
        candidate = os.path.join(d, name)
        if os.path.exists(candidate):
            return candidate
    return os.path.join(dirs[-1], name)


def _adb_search_candidates(base_dir=None):
    """Return ParaKit's supported local adb.exe placements in priority order."""
    base = base_dir or _external_base_dir()
    return [
        os.path.join(base, "Requirements", "platform-tools", "adb.exe"),
        os.path.join(base, "Requirements", "adb.exe"),
        os.path.join(base, "adb.exe"),
    ]


def _resolve_adb_path(base_dir=None, path_lookup=shutil.which):
    """Resolve adb.exe from supported local layouts, then PATH."""
    for candidate in _adb_search_candidates(base_dir):
        if os.path.isfile(candidate):
            return candidate
    return path_lookup("adb")


# ---------------------------------------------------------------------------
# FFmpeg path helper — ensures pydub can find ffmpeg in both .py and .exe
# ---------------------------------------------------------------------------
def _setup_ffmpeg():
    """
    When running as a frozen .exe, ffmpeg won't be on PATH automatically.
    This checks common locations and tells pydub where to find it.

    Both layouts are supported: ffmpeg.exe / ffprobe.exe alongside ParaKit.exe
    (legacy) or inside a sibling Requirements\\ folder.
    """
    import shutil
    from pydub import AudioSegment

    # If ffmpeg is already on PATH, nothing to do
    if shutil.which("ffmpeg"):
        return

    # When frozen, look next to the .exe (or in Requirements\)
    if getattr(sys, 'frozen', False):
        ffmpeg_path  = _external_path("ffmpeg.exe")
        ffprobe_path = _external_path("ffprobe.exe")
        if os.path.exists(ffmpeg_path):
            AudioSegment.converter = ffmpeg_path
            AudioSegment.ffmpeg    = ffmpeg_path
            AudioSegment.ffprobe   = ffprobe_path

