    # ── Recent files helpers ──────────────────────────────────────────────────
    def _refresh_recent_combo(self):
        cfg = load_config()
        recent = cfg.get("recent_songs", [])
        labels = [f"{r['title']} — {r['artist']}" for r in recent]
        self.recent_combo["values"] = labels if labels else ["(no recent songs yet)"]

    def _load_recent(self):
        cfg = load_config()
        recent = cfg.get("recent_songs", [])
        idx = self.recent_combo.current()
        if idx < 0 or idx >= len(recent):
            return
        r = recent[idx]
        self.midi_var.set(r.get("midi", ""))
        self.audio_var.set(r.get("audio", ""))
        self.drum_audio_var.set(r.get("drum_audio", ""))
        self.cover_var.set(r.get("cover", ""))
        self.title_var.set(r.get("title", "Untitled"))
        self.artist_var.set(r.get("artist", "Unknown"))
        self.creator_var.set(r.get("creator", "ParaKit"))
        self.difficulty_var.set(r.get("difficulty", "Expert"))
        self.complexity_var.set(r.get("complexity", 3))

    def _save_recent(self, entry: dict):
        """Save a completed conversion to the recent-songs list (max 10)."""
        cfg  = load_config()
        recent = cfg.get("recent_songs", [])
        # Remove duplicate if same title+artist already exists
        recent = [r for r in recent if not (r.get("title") == entry["title"]
                                             and r.get("artist") == entry["artist"])]
        recent.insert(0, entry)
        recent = recent[:10]
        save_config({"recent_songs": recent})
        self._refresh_recent_combo()

    # ── Open output folder ────────────────────────────────────────────────────
    def _sc_convert_button_text(self):
        labels = {
            "paradiddle": "🎵  Convert to .rlrr",
            "clonehero":  "🎸  Export to Clone Hero",
            "both":       "🎵🎸  Export Both",
        }
        fmt_var = getattr(self, "sc_export_fmt", None)
        fmt = fmt_var.get() if fmt_var else "paradiddle"
        return labels.get(fmt, labels["paradiddle"])

    def _adb_push_to_quest(self):
        """Push the last converted song folder to a connected Meta Quest via ADB."""
        import threading
        # Find the output folder — use the last converted song folder if available
        out_folder = getattr(self, '_last_rlrr_folder', None) or self.output_folder_var.get().strip()
        if not out_folder or not os.path.isdir(out_folder):
            messagebox.showwarning("No Output Folder",
                                   "Convert a song first, or browse to the song folder to push.")
            return

        # Find adb — checked in order:
        #   1. Requirements\platform-tools\adb.exe  (recommended new layout —
        #      keeps the .dlls grouped with adb.exe in their own subfolder)
        #   2. Requirements\adb.exe                  (flat Requirements layout)
        #   3. <next-to-EXE>\adb.exe                 (legacy)
        #   4. system PATH
        adb = _resolve_adb_path()
        if not adb:
            messagebox.showerror("ADB Not Found",
                                  "adb.exe not found.\n\n"
                                  "Download the Android SDK Platform Tools from:\n"
                                  "https://developer.android.com/tools/releases/platform-tools\n\n"
                                  "Keep adb.exe with AdbWinApi.dll and AdbWinUsbApi.dll "
                                  "in one of these locations:\n"
                                  "  - Requirements\\platform-tools\\adb.exe (recommended)\n"
                                  "  - Requirements\\adb.exe (flat)\n"
                                  "  - next to ParaKit.exe (legacy)")
            return

        def _push():
            import subprocess
            quest_path = "/sdcard/Android/data/com.emuvr.paradiddle/files/Songs/"
            folder_name = os.path.basename(out_folder.rstrip("/\\"))
            dest = quest_path + folder_name

            def _log(msg):
                self.root.after(0, lambda m=msg: self.log(m))

            try:
                # Check device connected
                result = subprocess.run([adb, "devices"], capture_output=True, text=True, timeout=8,
                                   creationflags=subprocess.CREATE_NO_WINDOW if sys.platform=="win32" else 0)
                lines = [l for l in result.stdout.splitlines() if "\tdevice" in l]
                if not lines:
                    self.root.after(0, lambda: messagebox.showerror(
                        "No Quest Found",
                        "No Meta Quest detected via ADB.\n\n"
                        "Make sure:\n"
                        "  • The Quest is plugged in via USB\n"
                        "  • Developer mode is enabled on the Quest\n"
                        "  • You accepted the USB debugging prompt in the headset"))
                    return
                _log(f"📲  Quest found: {lines[0].split()[0]}")
                _log(f"  Pushing: {folder_name} → {dest}")
                result = subprocess.run(
                    [adb, "push", out_folder, dest],
                    capture_output=True, text=True, timeout=120)
                if result.returncode == 0:
                    _log(f"  ✓  Push complete! Song is ready in Paradiddle.")
                    self.root.after(0, lambda: messagebox.showinfo(
                        "Push Complete",
                        f"'{folder_name}' has been pushed to your Quest.\n\n"
                        f"Open Paradiddle and check Custom Songs."))
                else:
                    _log(f"  ✗  ADB error: {result.stderr}")
                    self.root.after(0, lambda: messagebox.showerror(
                        "Push Failed", f"ADB push failed:\n{result.stderr}"))
            except subprocess.TimeoutExpired:
                _log("  ✗  ADB timed out — check USB connection")
            except Exception as e:
                _log(f"  ✗  Error: {e}")

        threading.Thread(target=_push, daemon=True).start()

    def _on_cover_manual_change(self):
        """User manually changed the cover art field — clear auto-art indicator."""
        cur  = self.cover_var.get().strip()
        auto = getattr(self, '_am_auto_art_path', None)
        if auto and cur != auto:
            self._am_auto_art_path = None
            try: self.am_art_indicator_var.set("")
            except Exception: pass

    # ── "Use album art from audio metadata" toggle helpers ─────────────────────

    def _lock_cover_widgets(self, locked):
        """Disable / re-enable the Cover Image row when metadata-art mode is on."""
        cw = getattr(self, "_cover_widgets", None)
        if not cw:
            return
        # ttk.Entry uses "readonly" to grey-out while still showing the path;
        # buttons use "disabled".
        try:
            if cw.get("entry"):
                cw["entry"].configure(state="readonly" if locked else "normal")
            for key in ("browse", "recent", "clear"):
                w = cw.get(key)
                if w is not None:
                    w.configure(state="disabled" if locked else "normal")
        except Exception:
            pass

    def _on_metadata_art_toggle(self):
        """Called when the user clicks the 'Use album art from metadata' checkbox,
        and once on init via root.after to apply the persisted toggle state."""
        try:
            on = bool(self.use_metadata_art_var.get())
        except Exception:
            return
        self._lock_cover_widgets(on)
        if on:
            # Try to extract immediately if audio is already loaded
            self._apply_metadata_art()
        else:
            # Clear status; if cover_var is currently pointing at our temp file,
            # blank it so the user is not left with a dangling temp path.
            try:
                self.metadata_art_status_var.set("")
            except Exception:
                pass
            tmp = getattr(self, "_metadata_art_temp_path", None)
            if tmp and self.cover_var.get().strip() == tmp:
                self.cover_var.set("")
            # Best-effort cleanup of the temp file
            if tmp and os.path.exists(tmp):
                try: os.unlink(tmp)
                except Exception: pass
            self._metadata_art_temp_path = None

    def _refresh_metadata_art_if_active(self):
        """Re-extract metadata art when the user picks a new audio file
        and the toggle is currently on."""
        if getattr(self, "use_metadata_art_var", None) and self.use_metadata_art_var.get():
            # Slight defer so the audio_var trace settles before we read it
            self.root.after(10, self._apply_metadata_art)

    def _apply_metadata_art(self):
        """Extract embedded art from the current Song Audio file, center-crop
        to 512×512, save as a temp JPG, and point cover_var at it.

        Returns True on success (cover_var was updated), False otherwise.
        """
        try:
            audio_path = self.audio_var.get().strip()
        except Exception:
            return False

        if not audio_path:
            try: self.metadata_art_status_var.set("⚠  Load a Song Audio file to extract its album art")
            except Exception: pass
            return False
        if not os.path.isfile(audio_path):
            try: self.metadata_art_status_var.set("⚠  Song Audio file not found")
            except Exception: pass
            return False

        try: self.metadata_art_status_var.set("🔍  Extracting album art from audio metadata…")
        except Exception: pass

        # Snapshot old temp path before extraction so we can clear stale art if
        # the new audio file has no embedded picture (don't carry the previous
        # song's cover into the build).
        old_tmp = getattr(self, "_metadata_art_temp_path", None)

        def _clear_stale_temp():
            """Drop the previous temp art if cover_var still points at it."""
            if old_tmp and self.cover_var.get().strip() == old_tmp:
                self.cover_var.set("")
            if old_tmp and os.path.exists(old_tmp):
                try: os.unlink(old_tmp)
                except Exception: pass
            self._metadata_art_temp_path = None

        try:
            img_bytes, _mime = self._extract_album_art_from_audio(audio_path)
        except Exception as exc:
            _clear_stale_temp()
            try: self.metadata_art_status_var.set(f"⚠  Read error: {str(exc)[:70]}")
            except Exception: pass
            return False

        if not img_bytes:
            _clear_stale_temp()
            try: self.metadata_art_status_var.set(
                "⚠  No album art embedded in this audio file's metadata")
            except Exception: pass
            return False

        # Crop to square + resize, mirroring Asset Manager's _am_crop_art at line 16295
        try:
            from PIL import Image
            import io, tempfile, re as _re
            img = Image.open(io.BytesIO(img_bytes))
            if img.mode != "RGB":
                img = img.convert("RGB")
            iw, ih = img.size
            side = min(iw, ih)
            left = (iw - side) // 2
            top  = (ih - side) // 2
            img  = img.crop((left, top, left + side, top + side))
            img  = img.resize((512, 512), Image.LANCZOS)

            # Build a stable, recognisable temp filename based on the audio stem
            audio_stem = os.path.splitext(os.path.basename(audio_path))[0]
            safe_stem  = _re.sub(r'[<>:"/\\|?*]', '_', audio_stem)[:80] or "metadata_art"
            tmp_path   = os.path.join(tempfile.gettempdir(),
                                       f"{safe_stem}.parakit-cover.jpg")
            img.save(tmp_path, format="JPEG", quality=92)

            # Cleanup previous temp if it was a different file
            old = getattr(self, "_metadata_art_temp_path", None)
            if old and old != tmp_path and os.path.exists(old):
                try: os.unlink(old)
                except Exception: pass
            self._metadata_art_temp_path = tmp_path

            # Point cover_var at the temp file. This triggers the existing
            # _on_cover_manual_change callback, which only clears the AM
            # auto-art indicator — it does not affect our toggle state.
            self.cover_var.set(tmp_path)

            try: self.metadata_art_status_var.set(
                f"✓  Extracted from {os.path.basename(audio_path)} — cropped to 512×512")
            except Exception: pass
            return True

        except ImportError:
            try: self.metadata_art_status_var.set(
                "⚠  Pillow (PIL) is not installed — cannot crop album art")
            except Exception: pass
            return False
        except Exception as exc:
            try: self.metadata_art_status_var.set(f"⚠  Image error: {str(exc)[:70]}")
            except Exception: pass
            return False

    def _extract_album_art_from_audio(self, audio_path):
        """Return (image_bytes, mime_str) from the embedded album art of an
        audio file, or (None, None) if no art is embedded.

        Supports FLAC, MP3 (ID3v2 APIC), OGG Vorbis (METADATA_BLOCK_PICTURE),
        and MP4 / M4A (covr atom). WAV has no standard cover-art tag — returns
        (None, None) so the caller can show a clear "no art" message.

        Always prefers the front-cover picture (type 3) when more than one is
        embedded; falls back to the first picture otherwise.
        """
        ext = os.path.splitext(audio_path)[1].lower()

        if ext == ".flac":
            from mutagen.flac import FLAC
            f = FLAC(audio_path)
            pics = list(getattr(f, "pictures", []) or [])
            if not pics:
                return None, None
            for p in pics:
                if getattr(p, "type", None) == 3:  # 3 = front cover
                    return p.data, p.mime
            return pics[0].data, pics[0].mime

        if ext == ".mp3":
            from mutagen.id3 import ID3, ID3NoHeaderError
            try:
                tags = ID3(audio_path)
            except ID3NoHeaderError:
                return None, None
            apics = tags.getall("APIC")
            if not apics:
                return None, None
            for a in apics:
                if getattr(a, "type", None) == 3:
                    return a.data, a.mime
            return apics[0].data, apics[0].mime

        if ext == ".ogg":
            # OGG Vorbis embeds art as a base64-encoded FLAC Picture block
            # under the METADATA_BLOCK_PICTURE tag.
            from mutagen.oggvorbis import OggVorbis
            from mutagen.flac import Picture
            import base64
            try:
                f = OggVorbis(audio_path)
            except Exception:
                return None, None
            # Collect every picture across both key casings, then prefer the
            # front cover (type 3) before falling back to the first decodable
            # picture — same precedence as the FLAC and MP3 branches above.
            pictures = []
            for key in ("metadata_block_picture", "METADATA_BLOCK_PICTURE"):
                if key not in f:
                    continue
                raw_list = f[key]
                if not isinstance(raw_list, list):
                    raw_list = [raw_list]
                for raw in raw_list:
                    try:
                        pictures.append(Picture(base64.b64decode(raw)))
                    except Exception:
                        continue
            if not pictures:
                return None, None
            for p in pictures:
                if getattr(p, "type", None) == 3:
                    return p.data, p.mime
            return pictures[0].data, pictures[0].mime

        if ext in (".m4a", ".mp4"):
            from mutagen.mp4 import MP4
            f = MP4(audio_path)
            covr = (f.tags or {}).get("covr") if hasattr(f, "tags") else None
            if not covr:
                return None, None
            cover = covr[0]
            mime = "image/jpeg"
            try:
                from mutagen.mp4 import MP4Cover
                if getattr(cover, "imageformat", None) == MP4Cover.FORMAT_PNG:
                    mime = "image/png"
            except Exception:
                pass
            return bytes(cover), mime

        # WAV and anything else — no standard embedded cover art
        return None, None

    def _toggle_zip_folder(self):
        if self.zip_output_var.get():
            self.zip_folder_frame.pack(side=tk.LEFT)
        else:
            self.zip_folder_frame.pack_forget()

    def _zip_output_folder(self, folder_path):
        """Zip the converted output folder. Called after successful conversion."""
        import zipfile
        zip_dir = self.zip_folder_var.get().strip() or os.path.dirname(folder_path)
        folder_name = os.path.basename(folder_path.rstrip("/\\"))
        zip_path = os.path.join(zip_dir, f"{folder_name}.zip")
        try:
            with zipfile.ZipFile(zip_path, 'w', zipfile.ZIP_DEFLATED) as zf:
                for root, dirs, files in os.walk(folder_path):
                    for file in files:
                        fp = os.path.join(root, file)
                        arcname = os.path.relpath(fp, os.path.dirname(folder_path))
                        zf.write(fp, arcname)
            self.log(f"📦  Zip saved: {os.path.basename(zip_path)}")
            return zip_path
        except Exception as e:
            self.log(f"⚠  Zip failed: {e}")
            return None

    def _open_output_folder(self):
        folder = self.output_var.get() or os.getcwd()
        import subprocess, platform
        try:
            if platform.system() == "Windows":
                os.startfile(folder)
            elif platform.system() == "Darwin":
                subprocess.Popen(["open", folder])
            else:
                subprocess.Popen(["xdg-open", folder])
        except Exception as e:
            messagebox.showerror("Error", f"Could not open folder:\n{e}")

    # =========================================================================
    # Tab 4 — Stem Splitter
    # =========================================================================
    def _build_stem_tab(self, parent):
        """Drum/backing stem separator using Demucs."""
        # v4.4.53.5 — On 1080p displays in compact mode, this tab's content
        # exceeded the available vertical space and the Log section at the
        # bottom got crushed off-screen. Wrap in a scrollable canvas in
        # compact mode so the user can scroll down to reach the Log.
        # Roomy/auto modes on larger displays keep the original direct-pack
        # layout for unchanged behavior.
        if getattr(self, "_compact_layout", False):
            scroll_inner = self._make_scrollable_tab(parent)
            main = ttk.Frame(scroll_inner, padding=20)
        else:
            main = ttk.Frame(parent, padding=20)
        main.pack(fill=tk.BOTH, expand=True)

        ttk.Label(main, text="🥁  Stem Splitter",
                  style="Header.TLabel").pack(anchor="w")
        ttk.Label(main,
                  text="Split any song into drums/backing OGG files, plus a lossless drums stem for Audio → MIDI detection.",
                  style="Sub.TLabel").pack(anchor="w", pady=(2, 4))

        quick_frame = ttk.LabelFrame(main, text=" Quick Path ", padding=10)
        quick_frame.pack(fill=tk.X, pady=(8, 10))
        ttk.Label(
            quick_frame,
            text="1. Pick the song  ->  2. Use Standard Split  ->  3. Send the lossless drums split to Audio -> MIDI",
            font=("Segoe UI", 10, "bold"),
            foreground="#58a6ff"
        ).pack(anchor="w")
        ttk.Label(
            quick_frame,
            text="Standard split is the normal path. Custom Isolation and DrumSep are optional tools for special cases.",
            style="Sub.TLabel", foreground="#b388ff", wraplength=860,
            justify=tk.LEFT
        ).pack(anchor="w", pady=(3, 0))

        ttk.Label(main,
                  text="⚡  NEW (v4.4.58-12): RTX 50-series (Blackwell) GPUs are now supported "
                       "for GPU-accelerated splitting when a CUDA 12.8+ (cu128) PyTorch build "
                       "is installed. See the Hardware speed notes below for details.",
                  style="Sub.TLabel", foreground="#00e0e0", wraplength=860,
                  justify=tk.LEFT).pack(anchor="w", pady=(0, 6))

        _, hardware_content = self._make_collapsible_tips(
            main, title="Hardware speed notes", start_open=False,
            pack_kw={"pady": (0, 10)})
        ttk.Label(hardware_content,
                  text="NVIDIA GTX 10-series through RTX 40-series: full GPU acceleration "
                       "via CUDA. Splitting typically takes ~30 seconds.\n\n"
                       "NVIDIA RTX 50-series (5070, 5080, 5090): GPU-accelerated when a "
                       "CUDA 12.8+ (cu128) PyTorch build is installed (detects the Blackwell "
                       "sm_120 architecture); the default build falls back to CPU.\n\n"
                       "AMD and Intel GPUs: run on CPU only. Demucs requires CUDA, which is "
                       "an NVIDIA-exclusive technology. CPU splits typically take 45s to "
                       "~1m30s depending on your processor.",
                  style="Sub.TLabel", foreground="#e09a3a",
                  wraplength=860, justify=tk.LEFT).pack(anchor="w")

        # ── Input file ────────────────────────────────────────────────────────
        in_frame = ttk.LabelFrame(main, text=" Input File ", padding=10)
        in_frame.pack(fill=tk.X, pady=(0, 6))

        self.stem_input_var = tk.StringVar()
        stem_lbl = ttk.Label(in_frame, text="Audio File:")
        stem_lbl.grid(row=0, column=0, sticky="w", padx=(0, 5))
        stem_entry = ttk.Entry(in_frame, textvariable=self.stem_input_var, width=48)
        stem_entry.grid(row=0, column=1, sticky="ew", padx=(0, 5))
        stem_btn_frame = ttk.Frame(in_frame)
        stem_btn_frame.grid(row=0, column=2)
        stem_btn = ttk.Button(stem_btn_frame, text="Browse...", command=self._stem_browse_input)
        stem_btn.pack(side=tk.LEFT)
