    def _sm_open_search(self):
        """Open MuseScore.com search in the user's default browser."""
        import urllib.parse, webbrowser
        query = self.sm_search_var.get().strip()
        if not query:
            messagebox.showinfo("Search", "Enter a song or artist name to search for.")
            return
        filt = self.sm_search_filter_var.get().strip()
        # "Drums" appends the keyword; "Full Mix" searches unfiltered
        if filt == "Drums":
            query = query + " drums"
        url = "https://musescore.com/sheetmusic?text=" + urllib.parse.quote(query)
        webbrowser.open(url)

    def _sm_remap_to_paradiddle(self, midi_note):
        """Map any GM drum note to the nearest Paradiddle-compatible note.
        Returns (remapped_note, was_remapped, description) or (None, False, reason) if no match."""

        # Notes Paradiddle recognises natively — pass through unchanged
        PARADIDDLE_NATIVE = {
            35, 36,          # Kick
            37, 38, 40,      # Snare
            41, 43,          # Floor Tom
            42, 44, 46,      # Hi-Hat
            45, 47,          # Tom 2
            48, 50,          # Tom 1
            49, 55, 57,      # Crash
            51, 53, 59,      # Ride
        }

        if midi_note in PARADIDDLE_NATIVE:
            return midi_note, False, None

        # Remap non-native GM notes to nearest Paradiddle equivalent
        REMAP = {
            # Kick variants
            33: 35, 34: 35,
            # Snare variants
            27: 38, 28: 38, 29: 38, 30: 38, 31: 38,
            39: 38,   # hand clap → snare
            # Hi-hat variants
            54: 42,   # tambourine → hi-hat
            # Cymbal variants
            52: 49,   # chinese cymbal → crash
            56: 49,   # cowbell → crash (best available)
            58: 49,   # vibraslap → crash
            # Tom variants
            32: 41,   # bass drum pedal → floor tom
            # Ride variants
            # (most ride variants already in native set)
            # Misc percussion — map to nearest drum sound
            60: 48, 61: 48,   # high/low bongo → tom 1
            62: 45, 63: 45, 64: 45,   # conga → tom 2
            65: 45, 66: 45,   # high/low timbale → tom 2
            67: 42, 68: 42,   # agogo → hi-hat
            69: 42, 70: 42,   # cabasa/maracas → hi-hat
            71: 42, 72: 42,   # whistle → hi-hat
            73: 42, 74: 42,   # guiro → hi-hat
            75: 38,           # claves → snare
            76: 48, 77: 48,   # wood block → tom 1
            78: 38, 79: 38,   # cuica → snare
            80: 42, 81: 42,   # triangle → hi-hat
        }

        if midi_note in REMAP:
            return REMAP[midi_note], True, f"MIDI {midi_note} → {REMAP[midi_note]}"

        # No mapping available — drop it
        return None, False, f"MIDI {midi_note} has no Paradiddle equivalent — dropped"

    def _sm_log(self, msg):
        # While a conversion is running, prefix non-blank lines with [mm:ss]
        # elapsed since _sm_start_time was set. Leading newlines used for
        # spacing are preserved before the prefix.
        out = msg
        start = getattr(self, '_sm_start_time', None)
        if start is not None:
            import time as _t
            leading = ""
            body = msg
            while body.startswith("\n"):
                leading += "\n"
                body = body[1:]
            if body.strip():
                elapsed = _t.time() - start
                m = int(elapsed // 60)
                s = int(elapsed % 60)
                out = f"{leading}[{m:02d}:{s:02d}]  {body}"
        self.sm_log_text.configure(state="normal")
        self._pretty_log_insert(self.sm_log_text, out + "\n")
        self.sm_log_text.see(tk.END)
        self.sm_log_text.configure(state="disabled")
        self.root.update_idletasks()

    def _sm_clear_log(self):
        self.sm_log_text.configure(state="normal")
        self.sm_log_text.delete("1.0", tk.END)
        self.sm_log_text.configure(state="disabled")

    def _sm_toggle_advanced(self):
        if self.sm_adv_expanded.get():
            self.sm_adv_frame.pack(fill=tk.X, pady=(0, 10))
        else:
            self.sm_adv_frame.pack_forget()

    def _sm_browse_input(self):
        path = filedialog.askopenfilename(
            filetypes=[("MusicXML", "*.xml *.mxl *.musicxml"), ("All files", "*.*")])
        if path:
            self.sm_input_var.set(path)
            self._add_recent_file("recent_sm_input", path)

    def _sm_browse_output(self):
        path = filedialog.askdirectory()
        if path:
            self.sm_output_var.set(path)
            save_config({"output_folder_sm": path})

    def _sm_scan_parts(self):
        """Read the MusicXML file and populate the part selector Combobox."""
        import xml.etree.ElementTree as ET

        input_path = self.sm_input_var.get().strip()
        if not input_path or not os.path.exists(input_path):
            messagebox.showerror("No File", "Please select a MusicXML file first.")
            return

        try:
            # Read raw XML (handles both .mxl and .xml)
            if input_path.lower().endswith('.mxl'):
                import zipfile
                with zipfile.ZipFile(input_path, 'r') as z:
                    xml_content = None
                    for name in z.namelist():
                        if name.endswith('.xml') and not name.startswith('META'):
                            xml_content = z.read(name)
                            break
                if xml_content is None:
                    raise ValueError("Could not find XML content inside .mxl file.")
            else:
                with open(input_path, 'rb') as f:
                    xml_content = f.read()

            root = ET.fromstring(xml_content)

            def strip_ns(tag):
                return tag.split('}')[-1] if '}' in tag else tag

            # Collect all score-part names from the part-list header
            part_names = []
            for el in root.iter():
                if strip_ns(el.tag) == 'score-part':
                    pid = el.get('id', '')
                    pname = None
                    for child in el:
                        if strip_ns(child.tag) == 'part-name' and child.text:
                            pname = child.text.strip()
                            break
                    part_names.append(pname or pid)

            if not part_names:
                messagebox.showinfo("Scan Result", "No parts found in this file.")
                return

            values = ["Auto-detect (recommended)"] + part_names
            self.sm_part_combo["values"] = values
            self.sm_part_combo.set("Auto-detect (recommended)")

            # Open Advanced panel so user can see the dropdown
            if not self.sm_adv_expanded.get():
                self.sm_adv_expanded.set(True)
                self._sm_toggle_advanced()

            messagebox.showinfo(
                "Parts Found",
                f"Found {len(part_names)} part(s):\n\n"
                + "\n".join(f"  • {n}" for n in part_names)
                + "\n\nSelect the drum part from the dropdown above."
            )

        except Exception as e:
            messagebox.showerror("Scan Failed", f"Could not read file:\n{e}")

    def _sm_convert(self):
        """Parse MusicXML and convert to MIDI."""
        import threading
        input_path = self.sm_input_var.get().strip()
        if not input_path or not os.path.exists(input_path):
            messagebox.showerror("No Input", "Please select a MusicXML file.")
            return
        if self.sm_save_file_var.get() and not self.sm_output_var.get().strip():
            messagebox.showerror("No Output", "Please select an output folder.")
            return
        if (not self.sm_open_editor_var.get()
                and not self.sm_save_file_var.get()
                and not self.sm_send_creator_var.get()):
            messagebox.showerror("No Output", "Select at least one output option.")
            return

        mode = self.sm_mode_var.get()
        if mode == "music21" and not getattr(self, '_sm_music21_available', False):
            messagebox.showwarning("music21 Not Available",
                                   "music21 is not installed. Falling back to Standard XML parser.\n\n"
                                   "Install music21 from the command line to enable high accuracy mode.")
            mode = "standard"

        self.sm_btn.configure(state="disabled", text="Converting...")
        self._sm_clear_log()

        # Kick off elapsed timer + progress bar — set before the worker runs
        # so the very first log line carries an accurate [mm:ss] prefix.
        import time as _t
        self._sm_start_time = _t.time()
        self.sm_progress.start(12)
        self.sm_timer_lbl.configure(text="⏱  00:00")
        self._timer_start(self.sm_timer_lbl)

        if mode == "music21":
            threading.Thread(target=self._sm_do_convert_music21, daemon=True).start()
        else:
            threading.Thread(target=self._sm_do_convert, daemon=True).start()

    def _sm_do_convert(self):
        """Worker thread — parse MusicXML and build MIDI."""
        audio_offset_secs = 0.0  # v4.4.57.92-10 init for NameError-safety; populated below
        import xml.etree.ElementTree as ET
        import struct, math

        input_path = self.sm_input_var.get().strip()
        output_dir = self.sm_output_var.get().strip()

        # GM drum note → Paradiddle MIDI note map
        # Standard GM percussion uses channel 10 (0-indexed: 9)
        # We pass through GM drum notes directly since Paradiddle uses GM standard
        GM_DRUM_NOTES = {
            35, 36,          # Kick
            37, 38, 40,      # Snare
            41, 43,          # Floor Tom
            42, 44, 46,      # Hi-Hat
            45, 47,          # Tom 2
            48, 50,          # Tom 1
            49, 55, 57,      # Crash
            51, 53, 59,      # Ride
        }

        try:
            self._sm_log(f"=== Sheet Music → MIDI ===\n")
            self._sm_log(f"Input: {os.path.basename(input_path)}")

            # Handle .mxl (compressed MusicXML = zip file)
            xml_content = None
            if input_path.lower().endswith('.mxl'):
                import zipfile
                with zipfile.ZipFile(input_path, 'r') as z:
                    for name in z.namelist():
                        if name.endswith('.xml') and not name.startswith('META'):
                            xml_content = z.read(name)
                            break
                if xml_content is None:
                    raise ValueError("Could not find XML content inside .mxl file.")
            else:
                with open(input_path, 'rb') as f:
                    xml_content = f.read()

            root = ET.fromstring(xml_content)

            # Strip namespace prefixes if present
            def strip_ns(tag):
                return tag.split('}')[-1] if '}' in tag else tag

            def find_all(node, tag):
                return [c for c in node.iter() if strip_ns(c.tag) == tag]

            def find_first(node, tag):
                results = find_all(node, tag)
                return results[0] if results else None

            # ── Read tempo ─────────────────────────────────────────────────────
            bpm_override = self.sm_bpm_var.get().strip()
            if bpm_override:
                try:
                    bpm = float(bpm_override)
                    self._sm_log(f"BPM: {bpm:.1f}  (user override)")
                except ValueError:
                    bpm = 120.0
                    self._sm_log("BPM override invalid — using 120")
            else:
                bpm = 120.0
                sound = find_first(root, 'sound')
                if sound is not None and sound.get('tempo'):
                    bpm = float(sound.get('tempo'))
                else:
                    # Try metronome marking
                    per_min = find_first(root, 'per-minute')
                    if per_min is not None and per_min.text:
                        try:
                            bpm = float(per_min.text)
                        except ValueError:
                            pass
                self._sm_log(f"BPM: {bpm:.1f}  (from file)")

            # ── Read time signature ────────────────────────────────────────────
            ts_num_override = self.sm_timesig_num_var.get().strip()
            ts_den_override = self.sm_timesig_den_var.get().strip()
            if ts_num_override and ts_den_override:
                try:
                    ts_num = int(ts_num_override)
                    ts_den = int(ts_den_override)
                    self._sm_log(f"Time sig: {ts_num}/{ts_den}  (user override)")
                except ValueError:
                    ts_num, ts_den = 4, 4
                    self._sm_log("Time sig override invalid — using 4/4")
            else:
                ts_num, ts_den = 4, 4
                beats = find_first(root, 'beats')
                beat_type = find_first(root, 'beat-type')
                if beats is not None and beats.text:
                    ts_num = int(beats.text)
                if beat_type is not None and beat_type.text:
                    ts_den = int(beat_type.text)
                self._sm_log(f"Time sig: {ts_num}/{ts_den}  (from file)")

            # ── Read divisions (ticks per quarter note) ────────────────────────
            divisions = 1
            div_el = find_first(root, 'divisions')
            if div_el is not None and div_el.text:
                divisions = int(div_el.text)
            self._sm_log(f"Divisions per quarter: {divisions}")

            # ── Parse notes ────────────────────────────────────────────────────
            self._sm_log("\nParsing notes...")
            events = []           # (abs_tick, midi_note, velocity)
            skipped_notes = {}    # note_number -> count of skipped
            note_counts = {}      # instrument name -> count

            INST_NAMES = {
                35: 'Kick', 36: 'Kick',
                37: 'Snare (rim)', 38: 'Snare', 40: 'Snare',
                41: 'Floor Tom', 43: 'Floor Tom',
                42: 'Hi-Hat (closed)', 44: 'Hi-Hat (pedal)', 46: 'Hi-Hat (open)',
                45: 'Tom 2', 47: 'Tom 2',
                48: 'Tom 1', 50: 'Tom 1',
                49: 'Crash', 55: 'Crash', 57: 'Crash',
                51: 'Ride', 53: 'Ride (bell)', 59: 'Ride',
            }

            # ── Build instrument ID → MIDI note map from score header ──────────
            # Reads midi-unpitched values, then corrects them using instrument-name
            # strings via the shared SM_DRUM_NAME_TO_MIDI table — this fixes
            # transcribers who assigned the wrong MIDI note to a correctly-named
            # instrument (e.g. kick mapped to MIDI 37).

            # Step 1: raw midi-unpitched values from file
            raw_midi_map = {}
            for midi_inst in find_all(root, 'midi-instrument'):
                inst_id = midi_inst.get('id', '')
                midi_up = find_first(midi_inst, 'midi-unpitched')
                if midi_up is not None and midi_up.text:
                    try:
                        raw_midi_map[inst_id] = int(midi_up.text)
                    except ValueError:
                        pass

            # Step 2: instrument names from score-instrument elements
            inst_id_to_name_sm = {}
            for score_inst in find_all(root, 'score-instrument'):
                iid = score_inst.get('id', '')
                iname_el = find_first(score_inst, 'instrument-name')
                if iname_el is not None and iname_el.text:
                    inst_id_to_name_sm[iid] = iname_el.text.strip()

            # Step 3: build corrected map — name takes priority over raw note number
            # Uses the shared SM_DRUM_NAME_TO_MIDI table (module-level constant)
            inst_id_to_midi = {}
            corrected_sm = 0
            for iid, raw_note in raw_midi_map.items():
                iname = inst_id_to_name_sm.get(iid, '').lower()
                corrected_note = None
                best_len = 0
                for keyword, note in SM_DRUM_NAME_TO_MIDI.items():
                    if keyword in iname and len(keyword) > best_len:
                        corrected_note = note
                        best_len = len(keyword)
                if corrected_note is not None and corrected_note != raw_note:
                    inst_id_to_midi[iid] = corrected_note
                    corrected_sm += 1
                else:
                    inst_id_to_midi[iid] = raw_note

            if inst_id_to_midi:
                self._sm_log(f"  Instrument map built: {len(inst_id_to_midi)} entries"
                             + (f", {corrected_sm} corrected by name" if corrected_sm else ""))

            # Find percussion part — honour manual selection, otherwise auto-detect
            parts = find_all(root, 'part')

            # Build part id → name map from score header (needed for manual selection)
            part_list_els = find_all(root, 'score-part')
            part_id_to_name = {}
            for sp in part_list_els:
                pid = sp.get('id', '')
                pname_el = find_first(sp, 'part-name')
                part_id_to_name[pid] = (pname_el.text if pname_el is not None and pname_el.text else pid)

            selected_part_name = self.sm_part_var.get().strip()
            perc_part = None

            if selected_part_name and selected_part_name != "Auto-detect (recommended)":
                # User picked a specific part — match by name
                for part in parts:
                    pid = part.get('id', '')
                    if part_id_to_name.get(pid, '') == selected_part_name:
                        perc_part = part
                        self._sm_log(f"  Using selected part: {selected_part_name}")
                        break
                if perc_part is None:
                    self._sm_log(f"  ⚠  Selected part '{selected_part_name}' not found — falling back to auto-detect")

            if perc_part is None:
                # Auto-detect: prefer part with unpitched notes
                for part in parts:
                    unpitched = find_first(part, 'unpitched')
                    if unpitched is not None:
                        pid = part.get('id', '')
                        self._sm_log(f"  Auto-detected drum part: {part_id_to_name.get(pid, pid)}")
                        perc_part = part
                        break

            if perc_part is None and parts:
                pid = parts[0].get('id', '')
                perc_part = parts[0]
                self._sm_log(f"  No explicit percussion part found — using first part: {part_id_to_name.get(pid, pid)}")

            abs_tick = 0
            measures = find_all(perc_part, 'measure') if perc_part is not None else []
            self._sm_log(f"  Measures found: {len(measures)}")

            for measure in measures:
                for child in measure:
                    tag = strip_ns(child.tag)
                    if tag == 'note':
                        # Check for rest
                        if find_first(child, 'rest') is not None:
                            dur_el = find_first(child, 'duration')
                            if dur_el is not None and dur_el.text:
                                abs_tick += int(dur_el.text)
                            continue
                        # Check for chord (no tick advance)
                        is_chord = find_first(child, 'chord') is not None
                        dur_el   = find_first(child, 'duration')
                        duration = int(dur_el.text) if dur_el is not None and dur_el.text else 0

                        midi_note = None
                        unpitched = find_first(child, 'unpitched')
                        if unpitched is not None:
                            # Strategy 1: look up instrument id in our map (most reliable)
                            instrument_el = find_first(child, 'instrument')
                            if instrument_el is not None:
                                inst_id = instrument_el.get('id', '')
                                midi_note = inst_id_to_midi.get(inst_id)
                            # Strategy 2: display pitch fallback
                            if midi_note is None:
                                step_el   = find_first(unpitched, 'display-step')
                                octave_el = find_first(unpitched, 'display-octave')
                                if step_el is not None and octave_el is not None:
                                    steps = {'C':0,'D':2,'E':4,'F':5,'G':7,'A':9,'B':11}
                                    step   = steps.get(step_el.text, 0)
                                    octave = int(octave_el.text)
                                    midi_note = (octave + 1) * 12 + step
                        else:
                            pitch = find_first(child, 'pitch')
                            if pitch is not None:
                                step_el   = find_first(pitch, 'step')
                                octave_el = find_first(pitch, 'octave')
                                alter_el  = find_first(pitch, 'alter')
                                if step_el is not None and octave_el is not None:
                                    steps = {'C':0,'D':2,'E':4,'F':5,'G':7,'A':9,'B':11}
                                    step   = steps.get(step_el.text, 0)
                                    octave = int(octave_el.text)
                                    alter  = int(float(alter_el.text)) if alter_el is not None and alter_el.text else 0
                                    midi_note = (octave + 1) * 12 + step + alter

                        vel_el = find_first(child, 'dynamics')
                        velocity = 90
                        if vel_el is not None and vel_el.text:
                            try:
                                velocity = min(127, int(float(vel_el.text) * 127 / 100))
                            except ValueError:
                                pass

                        if midi_note is not None:
                            remapped, was_remapped, remap_desc = self._sm_remap_to_paradiddle(midi_note)
                            if remapped is not None:
                                if was_remapped:
                                    skipped_notes[remap_desc] = skipped_notes.get(remap_desc, 0) + 1
                                events.append((abs_tick, remapped, velocity))
                                name = INST_NAMES.get(remapped, f'Note {remapped}')
                                note_counts[name] = note_counts.get(name, 0) + 1
                            else:
                                skipped_notes[remap_desc] = skipped_notes.get(remap_desc, 0) + 1

                        if not is_chord:
                            abs_tick += duration

                    elif tag == 'backup':
                        dur_el = find_first(child, 'duration')
                        if dur_el is not None and dur_el.text:
                            abs_tick -= int(dur_el.text)
                    elif tag == 'forward':
                        dur_el = find_first(child, 'duration')
                        if dur_el is not None and dur_el.text:
                            abs_tick += int(dur_el.text)

            total_notes = len(events)
            self._sm_log(f"\n✓ Notes parsed: {total_notes}")
            if events:
                first_tick = sorted(events, key=lambda e: e[0])[0][0]
                first_secs = first_tick / divisions * (60.0 / bpm) if divisions and bpm else 0.0
                self._sm_log(f"  First note raw position: {first_secs:.3f}s (tick {first_tick})")
                self._sm_log(f"  With offset {audio_offset_secs:+.3f}s → lands at {first_secs + audio_offset_secs:.3f}s")
            for name, count in sorted(note_counts.items(), key=lambda x: -x[1]):
                self._sm_log(f"   {name:20s}: {count}")
            if skipped_notes:
                remaps  = {k: v for k, v in skipped_notes.items() if '→' in str(k)}
                dropped = {k: v for k, v in skipped_notes.items() if '→' not in str(k)}
                if remaps:
                    self._sm_log(f"\nℹ  Notes remapped to nearest Paradiddle equivalent:")
                    for desc, count in sorted(remaps.items()):
                        self._sm_log(f"   {desc}  ({count}x)")
                if dropped:
                    self._sm_log(f"\n⚠  Notes dropped (no Paradiddle equivalent):")
                    for desc, count in sorted(dropped.items()):
                        self._sm_log(f"   {desc}  ({count}x)")

            # ── Sanity check — warn about likely transcription errors ─────────
            if total_notes > 0:
                kick_count  = note_counts.get('Kick', 0)
                hihat_count = sum(note_counts.get(k, 0) for k in
                                  ('Hi-Hat (closed)', 'Hi-Hat (open)', 'Hi-Hat (pedal)'))
                crash_count = note_counts.get('Crash', 0)
                rim_count   = note_counts.get('Snare (rim)', 0)
                snare_count = note_counts.get('Snare', 0)
                warnings = []
                if kick_count == 0:
                    warnings.append("  ⚠  No kick drum notes found. The transcriber may have used the\n"
                                    "     wrong instrument for kick — check MIDI 37 (Snare rim) counts.\n"
                                    "     If 'Snare (rim)' count looks like a kick count, reclassify\n"
                                    "     that lane to Kick in the MIDI Editor.")
                if hihat_count < 10 and total_notes > 50:
                    warnings.append("  ⚠  Very few hi-hat notes detected. Hi-hats may have been assigned\n"
                                    "     to a Tom or other lane by the transcriber. Check Tom 1/2 counts\n"
                                    "     — if they look unusually high, reclassify in the MIDI Editor.")
                if crash_count < 2 and total_notes > 100:
                    warnings.append("  ⚠  Very few crash cymbal notes detected. Crashes may be encoded\n"
                                    "     as an unmapped note number — check the Dropped notes section.")
                if rim_count > snare_count * 2 and rim_count > 50:
                    warnings.append(f"  ⚠  Snare (rim) count ({rim_count}) is unusually high compared to\n"
                                    f"     Snare ({snare_count}). MIDI 37 is likely being used for kick or\n"
                                    f"     another voice by this transcriber. Reclassify in MIDI Editor.")
                if warnings:
                    self._sm_log("\n── Transcription Quality Warnings ──────────────────────────────")
                    for w in warnings:
                        self._sm_log(w)
                    self._sm_log("  These are not errors in ParaKit — they reflect how the original\n"
                                 "  sheet music was notated. Use the MIDI Editor to fix lane assignments.")

            if total_notes == 0:
                self._sm_log("\n⚠  No drum notes found. Check that your file contains "
                             "percussion/drum notation and try again.")
                self.root.after(0, lambda: self.sm_btn.configure(
                    state="normal", text="🎼  Convert Sheet Music to MIDI"))
                return

            # ── Build MIDI file ────────────────────────────────────────────────
            self._sm_log("\nBuilding MIDI file...")
            tpb = 480  # ticks per beat
            scale = tpb / divisions  # scale from file ticks to our ticks
            tempo_us = int(60_000_000 / bpm)

            try:
                audio_offset_secs = float(self.sm_offset_var.get().strip() or "0")
            except ValueError:
                audio_offset_secs = 0.0

            first_secs_raw = 0.0
            if events:
                first_tick_raw = sorted(events, key=lambda e: e[0])[0][0]
                first_secs_raw = first_tick_raw / divisions * (60.0 / bpm) if divisions and bpm else 0.0
                self._sm_last_first_note_time = first_secs_raw
                self.root.after(0, lambda t=first_secs_raw: self.sm_first_note_lbl.configure(
                    text=f"First note: {t:.3f}s"))

            normalize = getattr(self, 'sm_offset_normalize_var', None) and self.sm_offset_normalize_var.get()
            if normalize and events:
                first_tick_raw = sorted(events, key=lambda e: e[0])[0][0]
                # Shift in ticks: first note becomes offset_ticks exactly
                offset_ticks = int(audio_offset_secs * bpm / 60 * tpb)
                shift_ticks = offset_ticks - first_tick_raw
                events = [(max(0, tick + shift_ticks), note, vel) for tick, note, vel in events]
                self._sm_log(f"  Auto-align: first note tick {first_tick_raw} → {offset_ticks} "
                             f"(shift: {shift_ticks:+d} ticks)")
                offset_ticks = 0  # already baked in
            else:
                offset_ticks = int(audio_offset_secs * bpm / 60 * tpb)
                if audio_offset_secs != 0.0:
                    self._sm_log(f"  Audio offset: {audio_offset_secs:+.3f}s ({offset_ticks:+d} ticks)")

            def encode_varlen(value):
                result = []
                result.append(value & 0x7F)
                value >>= 7
                while value:
                    result.append((value & 0x7F) | 0x80)
                    value >>= 7
                return bytes(reversed(result))

            def midi_header(num_tracks):
                return b'MThd' + struct.pack('>IHHH', 6, 1, num_tracks, tpb)

            def midi_track(events_list):
                data = bytearray()
                # Tempo
                data += encode_varlen(0)
                data += b'\xFF\x51\x03' + struct.pack('>I', tempo_us)[1:]
                # Time sig
                data += encode_varlen(0)
                data += b'\xFF\x58\x04' + bytes([ts_num,
                                                  int(math.log2(ts_den)),
                                                  24, 8])
                # Notes — sort by tick
                sorted_events = sorted(events_list, key=lambda e: e[0])
                prev_tick = 0
                for tick, note, vel in sorted_events:
                    scaled_tick = max(0, int(tick * scale) + offset_ticks)
                    delta = max(0, scaled_tick - prev_tick)
                    # Note on (channel 10 = 0x99)
                    data += encode_varlen(delta)
                    data += bytes([0x99, note, vel])
                    # Note off 1 tick later
                    data += encode_varlen(1)
                    data += bytes([0x89, note, 0])
                    prev_tick = scaled_tick + 1
                # End of track
                data += encode_varlen(0)
                data += b'\xFF\x2F\x00'
                return b'MTrk' + struct.pack('>I', len(data)) + bytes(data)

            midi_bytes = midi_header(2) + midi_track([]) + midi_track(events)

            # ── Output ─────────────────────────────────────────────────────────
            song_name = os.path.splitext(os.path.basename(input_path))[0]
            midi_path = None

            if self.sm_save_file_var.get():
                os.makedirs(output_dir, exist_ok=True)
                midi_path = os.path.join(output_dir, f"{song_name}.mid")
                with open(midi_path, 'wb') as f:
                    f.write(midi_bytes)
                self._sm_log(f"\n✓ MIDI saved to: {midi_path}")

            if self.sm_open_editor_var.get():
                # Write to temp if not already saved
                if midi_path is None:
                    import tempfile
                    tmp = tempfile.NamedTemporaryFile(suffix='.mid', delete=False)
                    tmp.write(midi_bytes)
                    tmp.close()
                    midi_path = tmp.name
                self._sm_log("  Opening in MIDI Editor...")
                self.root.after(100, lambda p=midi_path: self._me_open_from_a2m(p))
                self.root.after(150, lambda: self.notebook.select(5))

            if self.sm_send_creator_var.get():
                if midi_path is None:
                    import tempfile
                    tmp = tempfile.NamedTemporaryFile(suffix='.mid', delete=False)
                    tmp.write(midi_bytes)
                    tmp.close()
                    midi_path = tmp.name
                self._sm_log("  Sending to Song Creator (Tab 1)...")
                self.root.after(200, lambda p=midi_path: self.midi_var.set(p))
                self.root.after(250, lambda: self.notebook.select(0))

            self._sm_log("\n✓ Done!")

        except Exception as e:
            import traceback
            self._sm_log(f"\nERROR: {e}")
            self._sm_log(traceback.format_exc())
            self.root.after(0, lambda: messagebox.showerror(
                "Conversion Failed", f"An error occurred:\n{e}\n\nCheck the log for details."))

        finally:
            self.root.after(0, lambda: self.sm_btn.configure(
                state="normal", text="🎼  Convert Sheet Music to MIDI"))
            self.root.after(0, self.sm_progress.stop)
            self.root.after(0, lambda: self._timer_stop(self.sm_timer_lbl))
            self._sm_start_time = None

    def _sm_do_convert_music21(self):
        """Worker thread — convert MusicXML to MIDI using music21."""
        audio_offset_secs = 0.0  # v4.4.57.92-10 init for NameError-safety; populated below
        try:
            import music21 as m21
            import xml.etree.ElementTree as ET
            import zipfile as zf

            input_path  = self.sm_input_var.get().strip()
            output_dir  = self.sm_output_var.get().strip()
            song_name   = os.path.splitext(os.path.basename(input_path))[0]

            self._sm_log("=== Sheet Music → MIDI  (music21 parser) ===\n")
            self._sm_log(f"Input: {os.path.basename(input_path)}")
            self._sm_log("Loading score...")

            # ── Pre-build inst_id → MIDI note map from raw XML ────────────────
            # MusicXML stores the actual MIDI note number in <midi-unpitched> per
            # instrument in the score header. We also read <instrument-name> to
            # override wrong note numbers using a name-based correction table —
            # this handles transcribers who assigned the wrong MIDI note to a drum.
            inst_id_to_midi = {}
            try:
                if input_path.lower().endswith('.mxl'):
                    with zf.ZipFile(input_path, 'r') as z:
                        for name in z.namelist():
                            if name.endswith('.xml') and not name.startswith('META'):
                                xml_bytes = z.read(name)
                                break
                else:
                    with open(input_path, 'rb') as f:
                        xml_bytes = f.read()
                xml_root = ET.fromstring(xml_bytes)
                def _strip_ns(tag): return tag.split('}')[-1] if '}' in tag else tag

                # Step 1: build id → raw midi-unpitched from the file
                raw_midi = {}
                for midi_inst in xml_root.iter():
                    if _strip_ns(midi_inst.tag) == 'midi-instrument':
                        inst_id = midi_inst.get('id', '')
                        for child in midi_inst:
                            if _strip_ns(child.tag) == 'midi-unpitched' and child.text:
                                try:
                                    raw_midi[inst_id] = int(child.text)
                                except ValueError:
                                    pass

                # Step 2: build id → instrument-name from score-instrument elements
                inst_id_to_name = {}
                for score_inst in xml_root.iter():
                    if _strip_ns(score_inst.tag) == 'score-instrument':
                        iid = score_inst.get('id', '')
                        for child in score_inst:
                            if _strip_ns(child.tag) == 'instrument-name' and child.text:
                                inst_id_to_name[iid] = child.text.strip()

                # Step 3: name-based correction using shared SM_DRUM_NAME_TO_MIDI table.
                # Longest match wins — more specific terms beat shorter ones.
                # Step 4: for each instrument, pick the best MIDI note —
                # name-based correction takes priority over the raw file value
                corrected = 0
                for iid, raw_note in raw_midi.items():
                    iname = inst_id_to_name.get(iid, '').lower()
                    corrected_note = None
                    best_len = 0
                    for keyword, note in SM_DRUM_NAME_TO_MIDI.items():
                        if keyword in iname and len(keyword) > best_len:
                            corrected_note = note
                            best_len = len(keyword)
                    if corrected_note is not None and corrected_note != raw_note:
                        inst_id_to_midi[iid] = corrected_note
                        corrected += 1
                    else:
                        inst_id_to_midi[iid] = raw_note

                note_inst_map = {}  # will be built per note below via xml_root
                self._sm_log(f"Instrument map: {len(inst_id_to_midi)} entries"
                             + (f", {corrected} corrected by name" if corrected else ""))
            except Exception as e:
                self._sm_log(f"  (instrument map skipped: {e})")

            score = m21.converter.parse(input_path)

            # ── Apply overrides ───────────────────────────────────────────────
            bpm_override = self.sm_bpm_var.get().strip()
            ts_num_override = self.sm_timesig_num_var.get().strip()
            ts_den_override = self.sm_timesig_den_var.get().strip()

            if bpm_override:
                try:
                    bpm = float(bpm_override)
                    self._sm_log(f"BPM override: {bpm:.1f}")
                    for mm in score.flat.getElementsByClass('MetronomeMark'):
                        mm.number = bpm
                    if not score.flat.getElementsByClass('MetronomeMark'):
                        mm = m21.tempo.MetronomeMark(number=bpm)
                        score.flat.insert(0, mm)
                except ValueError:
                    self._sm_log("BPM override invalid — ignored")

            if ts_num_override and ts_den_override:
                try:
                    ts = m21.meter.TimeSignature(f"{ts_num_override}/{ts_den_override}")
                    self._sm_log(f"Time sig override: {ts_num_override}/{ts_den_override}")
                    for existing in score.flat.getElementsByClass('TimeSignature'):
                        existing.activeSite.replace(existing, ts)
                        break
                except Exception:
                    self._sm_log("Time sig override invalid — ignored")

            # ── Extract tempo and time sig for log ────────────────────────────
            tempos = score.flat.getElementsByClass('MetronomeMark')
            bpm_log = f"{tempos[0].number:.1f}" if tempos else "120 (default)"
            self._sm_log(f"BPM: {bpm_log}")

            timesigs = score.flat.getElementsByClass('TimeSignature')
            ts_log = str(timesigs[0]) if timesigs else "4/4 (default)"
            self._sm_log(f"Time sig: {ts_log}")

            # ── Extract full tempo map from music21 (its key advantage over basic mode) ──
            bpm_val = 120.0
            tempo_map = []  # list of (offset_quarterLength, bpm)
            for mm in score.flat.getElementsByClass('MetronomeMark'):
                try:
                    offset_ql = float(mm.offset)
                    tempo_map.append((offset_ql, float(mm.number)))
                except Exception:
                    pass
            if not tempo_map:
                tempo_map = [(0.0, 120.0)]
            tempo_map.sort(key=lambda x: x[0])
            bpm_val = tempo_map[0][1]

            if bpm_override:
                try:
                    bpm_val = float(bpm_override)
                    tempo_map = [(0.0, bpm_val)]
                    self._sm_log(f"BPM override: {bpm_val:.1f}")
                except ValueError:
                    self._sm_log("BPM override invalid — ignored")

            self._sm_log(f"BPM: {bpm_val:.1f}" + (f"  ({len(tempo_map)} tempo sections)" if len(tempo_map) > 1 else ""))

            timesigs = score.flat.getElementsByClass('TimeSignature')
            ts_log = str(timesigs[0]) if timesigs else "4/4 (default)"
            self._sm_log(f"Time sig: {ts_log}")

            def ql_to_seconds(offset_ql):
                """Convert quarter-length offset to seconds using the tempo map."""
                t = 0.0
                prev_ql = 0.0
                prev_bpm = tempo_map[0][1]
                for change_ql, change_bpm in tempo_map:
                    if change_ql >= offset_ql:
                        break
                    t += (change_ql - prev_ql) * 60.0 / prev_bpm
                    prev_ql = change_ql
                    prev_bpm = change_bpm
                t += (offset_ql - prev_ql) * 60.0 / prev_bpm
                return t

            # ── Parse notes from raw XML using inst_id_to_midi map ───────────────
            # This is far more reliable than music21's note resolution for percussion.
            # music21 is used above only for tempo extraction.
            INST_NAMES = {
                35:'Kick', 36:'Kick',
                37:'Snare (rim)', 38:'Snare', 40:'Snare',
                41:'Floor Tom', 43:'Floor Tom',
                42:'Hi-Hat (closed)', 44:'Hi-Hat (pedal)', 46:'Hi-Hat (open)',
                45:'Tom 2', 47:'Tom 2', 48:'Tom 1', 50:'Tom 1',
                49:'Crash', 55:'Crash', 57:'Crash',
                51:'Ride', 53:'Ride (bell)', 59:'Ride',
            }
            note_counts = {}
            skipped     = {}
            perc_notes  = []  # (offset_seconds, midi_pitch, velocity)

            def _strip(tag): return tag.split('}')[-1] if '}' in tag else tag
            def _find_all(node, tag):
                return [c for c in node.iter() if _strip(c.tag) == tag]
            def _find_first(node, tag):
                r = _find_all(node, tag)
                return r[0] if r else None

            # Identify the drum part from the XML — same keywords + unpitched heuristic
            selected_part_name = self.sm_part_var.get().strip()
            manual_selection = (selected_part_name and
                                selected_part_name != "Auto-detect (recommended)")

            xml_parts = _find_all(xml_root, 'part')
            part_list_els = _find_all(xml_root, 'score-part')
            part_id_to_name = {}
            for sp in part_list_els:
                pid = sp.get('id', '')
                pname_el = _find_first(sp, 'part-name')
                part_id_to_name[pid] = (pname_el.text if pname_el is not None and pname_el.text else pid)

            self._sm_log(f"\nParts found: {len(xml_parts)}")

            PERC_KEYWORDS = {'drum', 'perc', 'kit', 'snare', 'kick', 'cymbal',
                             'hihat', 'hi-hat', 'tom', 'bass drum', 'trap', 'batterie', 'schlagzeug'}

            drum_part_xml = None
            if manual_selection:
                for p in xml_parts:
                    pid = p.get('id', '')
                    if part_id_to_name.get(pid, '') == selected_part_name:
                        drum_part_xml = p
                        self._sm_log(f"  Using selected part: {selected_part_name}")
                        break
                if drum_part_xml is None:
                    self._sm_log(f"  ⚠  Selected part not found — falling back to auto-detect")

            if drum_part_xml is None:
                # Auto-detect: prefer part with unpitched notes or drum keyword
                for p in xml_parts:
                    pid = p.get('id', '')
                    pname = part_id_to_name.get(pid, '').lower()
                    if any(kw in pname for kw in PERC_KEYWORDS):
                        drum_part_xml = p
                        self._sm_log(f"  ✓ Auto-detected drum part: {part_id_to_name[pid]}")
                        break
                    if _find_first(p, 'unpitched') is not None:
                        drum_part_xml = p
                        self._sm_log(f"  ✓ Detected by unpitched notes: {part_id_to_name.get(pid, pid)}")
                        break

            if drum_part_xml is None and xml_parts:
                drum_part_xml = xml_parts[0]
                pid = drum_part_xml.get('id', '')
                self._sm_log(f"  No drum part detected — using first part: {part_id_to_name.get(pid, pid)}")

            if drum_part_xml is None:
                raise ValueError("No parts found in MusicXML file.")

            # ── Read divisions ────────────────────────────────────────────────
            divisions = 1
            div_el = _find_first(drum_part_xml, 'divisions')
            if div_el is not None and div_el.text:
                try:
                    divisions = int(div_el.text)
                except ValueError:
                    pass

            # ── Parse notes measure by measure ───────────────────────────────
            ts_num, ts_den = 4, 4
            abs_tick = 0
            measures = _find_all(drum_part_xml, 'measure')
            self._sm_log(f"  Measures: {len(measures)}")

            # ── Diagnostic: dump instrument map so we can verify corrections ──
            self._sm_log(f"  Instrument ID map ({len(inst_id_to_midi)} entries):")
            for iid, mnote in sorted(inst_id_to_midi.items(), key=lambda x: x[1]):
                iname_disp = inst_id_to_name.get(iid, '')
                raw_note   = raw_midi.get(iid, mnote)
                pd_name    = INST_NAMES.get(mnote, f'MIDI {mnote}')
                correction = f"  ← corrected from {raw_note}" if raw_note != mnote else ""
                self._sm_log(f"    {iid:20s} → {mnote:3d}  ({pd_name})"
                             + (f"  [{iname_disp}]{correction}" if iname_disp else correction))

            strategy_hits = {1: 0, 2: 0}  # track which strategy resolved each note

            for measure in measures:
                measure_start_tick = abs_tick
                note_tick = abs_tick

                for child in measure:
                    ctag = _strip(child.tag)

                    if ctag == 'attributes':
                        # Update divisions if changed mid-score
                        d = _find_first(child, 'divisions')
                        if d is not None and d.text:
                            try: divisions = int(d.text)
                            except ValueError: pass
                        b = _find_first(child, 'beats')
                        bt = _find_first(child, 'beat-type')
                        if b is not None and bt is not None:
                            try:
                                ts_num = int(b.text)
                                ts_den = int(bt.text)
                            except (ValueError, TypeError): pass

                    elif ctag == 'note':
                        dur_el = _find_first(child, 'duration')
                        dur_xml = int(dur_el.text) if dur_el is not None and dur_el.text else 0
                        # Quarter lengths for this note
                        dur_ql = dur_xml / divisions if divisions else dur_xml

                        is_chord = _find_first(child, 'chord') is not None
                        is_rest  = _find_first(child, 'rest') is not None

                        if is_rest:
                            if not is_chord:
                                note_tick += dur_xml
                            continue

                        midi_note = None
                        unpitched = _find_first(child, 'unpitched')
                        if unpitched is not None:
                            # Strategy 1: instrument id → midi-unpitched map (most reliable)
                            inst_el = _find_first(child, 'instrument')
                            if inst_el is not None:
                                iid = inst_el.get('id', '')
                                midi_note = inst_id_to_midi.get(iid)
                                if midi_note is not None:
                                    strategy_hits[1] += 1
                            # Strategy 2: display pitch fallback
                            if midi_note is None:
                                strategy_hits[2] += 1
                            if midi_note is None:
                                step_el   = _find_first(unpitched, 'display-step')
                                octave_el = _find_first(unpitched, 'display-octave')
                                if step_el is not None and octave_el is not None:
                                    steps = {'C':0,'D':2,'E':4,'F':5,'G':7,'A':9,'B':11}
                                    midi_note = (int(octave_el.text) + 1) * 12 + steps.get(step_el.text, 0)
                        else:
                            pitch = _find_first(child, 'pitch')
                            if pitch is not None:
                                step_el   = _find_first(pitch, 'step')
                                octave_el = _find_first(pitch, 'octave')
                                alter_el  = _find_first(pitch, 'alter')
                                if step_el is not None and octave_el is not None:
                                    steps = {'C':0,'D':2,'E':4,'F':5,'G':7,'A':9,'B':11}
                                    alter = int(float(alter_el.text)) if alter_el is not None and alter_el.text else 0
                                    midi_note = (int(octave_el.text) + 1) * 12 + steps.get(step_el.text, 0) + alter

                        if midi_note is not None:
                            # Convert tick position to quarter lengths then to seconds
                            offset_ql = note_tick / divisions if divisions else 0.0
                            offset_secs = ql_to_seconds(offset_ql)

                            vel_el = _find_first(child, 'dynamics')
                            velocity = 90
                            if vel_el is not None and vel_el.text:
                                try: velocity = min(127, int(float(vel_el.text) * 127 / 100))
                                except ValueError: pass

                            remapped, was_remapped, remap_desc = self._sm_remap_to_paradiddle(midi_note)
                            if remapped is not None:
                                if was_remapped:
                                    skipped[remap_desc] = skipped.get(remap_desc, 0) + 1
                                perc_notes.append((offset_secs, remapped, velocity))
                                name = INST_NAMES.get(remapped, f'Note {remapped}')
                                note_counts[name] = note_counts.get(name, 0) + 1
                            else:
                                skipped[remap_desc] = skipped.get(remap_desc, 0) + 1

                        if not is_chord:
                            note_tick += dur_xml

                    elif ctag == 'backup':
                        d = _find_first(child, 'duration')
                        if d is not None and d.text:
                            note_tick -= int(d.text)
                    elif ctag == 'forward':
                        d = _find_first(child, 'duration')
                        if d is not None and d.text:
                            note_tick += int(d.text)

                # Advance to next measure
                measure_dur = int(ts_num * (4.0 / ts_den) * divisions)
                abs_tick = measure_start_tick + measure_dur

            total = len(perc_notes)
            self._sm_log(f"\n  Note resolution: {strategy_hits[1]} via instrument ID map, "
                         f"{strategy_hits[2]} via display pitch fallback")
            self._sm_log(f"✓ Notes parsed: {total}")
            for name, count in sorted(note_counts.items(), key=lambda x: -x[1]):
                self._sm_log(f"   {name:20s}: {count}")

            # ── Sanity check — warn about likely transcription errors ─────────
            if total > 0:
                kick_count   = note_counts.get('Kick', 0)
                hihat_count  = sum(note_counts.get(k, 0) for k in
                                   ('Hi-Hat (closed)', 'Hi-Hat (open)', 'Hi-Hat (pedal)'))
                crash_count  = note_counts.get('Crash', 0)
                rim_count    = note_counts.get('Snare (rim)', 0)
                snare_count  = note_counts.get('Snare', 0)
                tom1_count   = note_counts.get('Tom 1', 0)
                warnings = []
                if kick_count == 0:
                    warnings.append("  ⚠  No kick drum notes found. The transcriber may have used the\n"
                                    "     wrong instrument for kick — check MIDI 37 (Snare rim) counts.\n"
                                    "     If 'Snare (rim)' count looks like a kick count, reclassify\n"
                                    "     that lane to Kick in the MIDI Editor.")
                if hihat_count < 10 and total > 50:
                    warnings.append("  ⚠  Very few hi-hat notes detected. Hi-hats may have been assigned\n"
                                    "     to a Tom or other lane by the transcriber. Check Tom 1/2 counts\n"
                                    "     — if they look unusually high, reclassify in the MIDI Editor.")
                if crash_count < 2 and total > 100:
                    warnings.append("  ⚠  Very few crash cymbal notes detected. Crashes may be encoded\n"
                                    "     as an unmapped note number (52, 56, 60) — check the Dropped\n"
                                    "     notes section above and the instrument map in the log.")
                if rim_count > snare_count * 2 and rim_count > 50:
                    warnings.append(f"  ⚠  Snare (rim) count ({rim_count}) is unusually high compared to\n"
                                    f"     Snare ({snare_count}). MIDI 37 is likely being used for kick or\n"
                                    f"     another voice by this transcriber. Reclassify in MIDI Editor.")
                if warnings:
                    self._sm_log("\n── Transcription Quality Warnings ──────────────────────────────")
                    for w in warnings:
                        self._sm_log(w)
                    self._sm_log("  These are not errors in ParaKit — they reflect how the original\n"
                                 "  sheet music was notated. Use the MIDI Editor to fix lane assignments.")
                self._sm_log(f"   {name:20s}: {count}")
            if skipped:
                remaps  = {k: v for k, v in skipped.items() if '→' in str(k)}
                dropped = {k: v for k, v in skipped.items() if '→' not in str(k)}
                if remaps:
                    self._sm_log(f"\nℹ  Notes remapped to nearest Paradiddle equivalent:")
                    for desc, count in sorted(remaps.items()):
                        self._sm_log(f"   {desc}  ({count}x)")
                if dropped:
                    self._sm_log(f"\n⚠  Notes dropped (no Paradiddle equivalent):")
                    for desc, count in sorted(dropped.items()):
                        self._sm_log(f"   {desc}  ({count}x)")

            if total == 0:
                self._sm_log("\n⚠  No drum notes found. Check your file has a percussion "
                             "staff and try again, or switch to Standard XML parser.")
                self.root.after(0, lambda: self.sm_btn.configure(
                    state="normal", text="🎼  Convert Sheet Music to MIDI"))
                return

            # ── Write MIDI ────────────────────────────────────────────────────
            self._sm_log("\nBuilding MIDI file...")
            import tempfile, struct, math

            # Use a fixed reference BPM for the MIDI file tick grid.
            # Note times are already accurate in seconds from ql_to_seconds().
            ref_bpm = bpm_val
            tpb = 480
            tempo_us = int(60_000_000 / ref_bpm)

            # Audio offset — offset means "first drum hit lands at this second in the audio".
            # Subtract the first note's natural position so it lands exactly at offset_secs.
            try:
                audio_offset_secs = float(self.sm_offset_var.get().strip() or "0")
            except ValueError:
                audio_offset_secs = 0.0

            first_secs_raw = 0.0
            if perc_notes:
                first_secs_raw = sorted(perc_notes, key=lambda n: n[0])[0][0]
                self._sm_last_first_note_time = first_secs_raw
                self.root.after(0, lambda t=first_secs_raw: self.sm_first_note_lbl.configure(
                    text=f"First note: {t:.3f}s"))

            normalize = getattr(self, 'sm_offset_normalize_var', None) and self.sm_offset_normalize_var.get()
            if normalize and first_secs_raw != 0.0:
                # Shift all note times so first note lands at exactly audio_offset_secs.
                # Done in seconds before tick conversion to avoid BPM rounding error.
                shift = audio_offset_secs - first_secs_raw
                perc_notes = [(secs + shift, note, vel) for secs, note, vel in perc_notes]
                self._sm_log(f"  Auto-align: first note {first_secs_raw:.3f}s → {audio_offset_secs:.3f}s "
                             f"(shift: {shift:+.3f}s)")
                audio_offset_secs = 0.0  # already baked into note times
            elif audio_offset_secs != 0.0:
                perc_notes = [(secs + audio_offset_secs, note, vel) for secs, note, vel in perc_notes]
                self._sm_log(f"  Audio offset: {audio_offset_secs:+.3f}s")
                audio_offset_secs = 0.0

            def encode_varlen(v):
                r = []
                r.append(v & 0x7F)
                v >>= 7
                while v:
                    r.append((v & 0x7F) | 0x80)
                    v >>= 7
                return bytes(reversed(r))

            def midi_header():
                return b'MThd' + struct.pack('>IHHH', 6, 1, 2, tpb)

            def midi_track(events_list):
                data = bytearray()
                data += encode_varlen(0)
                data += b'\xFF\x51\x03' + struct.pack('>I', tempo_us)[1:]
                data += encode_varlen(0)
                data += b'\xFF\x58\x04' + bytes([4, 2, 24, 8])
                sorted_evts = sorted(events_list, key=lambda e: e[0])
                prev_tick = 0
                for secs, note, vel in sorted_evts:
                    tick = max(0, int(secs * ref_bpm / 60 * tpb))
                    delta = max(0, tick - prev_tick)
                    data += encode_varlen(delta)
                    data += bytes([0x99, note, vel])
                    data += encode_varlen(1)
                    data += bytes([0x89, note, 0])
                    prev_tick = tick + 1
                data += encode_varlen(0)
                data += b'\xFF\x2F\x00'
                return b'MTrk' + struct.pack('>I', len(data)) + bytes(data)

            midi_bytes = midi_header() + midi_track([]) + midi_track(perc_notes)

            # ── Output ────────────────────────────────────────────────────────
            midi_path = None
            if self.sm_save_file_var.get():
                os.makedirs(output_dir, exist_ok=True)
                midi_path = os.path.join(output_dir, f"{song_name}.mid")
                with open(midi_path, 'wb') as f:
                    f.write(midi_bytes)
                self._sm_log(f"\n✓ MIDI saved to: {midi_path}")

            if self.sm_open_editor_var.get():
                if midi_path is None:
                    tmp = tempfile.NamedTemporaryFile(suffix='.mid', delete=False)
                    tmp.write(midi_bytes)
                    tmp.close()
                    midi_path = tmp.name
                self._sm_log("  Opening in MIDI Editor...")
                self.root.after(100, lambda p=midi_path: self._me_open_from_a2m(p))
                self.root.after(150, lambda: self.notebook.select(5))

            if self.sm_send_creator_var.get():
                if midi_path is None:
                    tmp = tempfile.NamedTemporaryFile(suffix='.mid', delete=False)
                    tmp.write(midi_bytes)
                    tmp.close()
                    midi_path = tmp.name
                self._sm_log("  Sending to Song Creator (Tab 1)...")
                self.root.after(200, lambda p=midi_path: self.midi_var.set(p))
                self.root.after(250, lambda: self.notebook.select(0))

            self._sm_log("\n✓ Done!")

        except Exception as e:
            import traceback
            self._sm_log(f"\nERROR: {e}")
            self._sm_log(traceback.format_exc())
            self.root.after(0, lambda: messagebox.showerror(
                "Conversion Failed", f"An error occurred:\n{e}\n\nCheck the log for details."))
        finally:
            self.root.after(0, lambda: self.sm_btn.configure(
                state="normal", text="🎼  Convert Sheet Music to MIDI"))
            self.root.after(0, self.sm_progress.stop)
            self.root.after(0, lambda: self._timer_stop(self.sm_timer_lbl))
            self._sm_start_time = None

    def _build_youtube_tab(self, parent):
        """YouTube → FLAC downloader tab using yt-dlp."""
        import os, sys, threading

        # v4.4.53.5 — Same 1080p compact-mode fix as Stem Splitter. This tab
        # has notice/warning labels + URL field + thumbnail preview + output
        # folder + format radios + cookies controls + JS runtime row +
        # progress + log — at 1080p the log got crushed off-screen. Wrap
        # in a scrollable canvas in compact mode.
        if getattr(self, "_compact_layout", False):
            scroll_inner = self._make_scrollable_tab(parent)
            main = ttk.Frame(scroll_inner, padding=16)
        else:
            main = ttk.Frame(parent, padding=16)
        main.pack(fill=tk.BOTH, expand=True)

        # Header
        ttk.Label(main, text="▶  YouTube → FLAC Converter",
                  font=("Segoe UI", 13, "bold"), foreground="#b388ff").pack(anchor="w")
        ttk.Label(main,
                  text="Paste a YouTube URL to download and convert the audio to a high-quality FLAC file.",
                  style="Sub.TLabel").pack(anchor="w", pady=(2, 12))

        # Notices
        notice_frame = ttk.Frame(main)
        notice_frame.pack(fill=tk.X, pady=(0, 12))
        ttk.Label(notice_frame,
                  text="ℹ  FLAC is recommended for the Stem Splitter — better quality than .ogg or .mp3.",
                  style="Sub.TLabel", foreground="#e09a3a",
                  justify=tk.LEFT, wraplength=800).pack(anchor="w")

        tos_row = ttk.Frame(notice_frame)
        tos_row.pack(anchor="w")
        ttk.Label(tos_row,
                  text="⚠  Only download audio you have the right to use. Downloading copyrighted content "
                       "without permission may violate YouTube's Terms of Service.",
                  style="Sub.TLabel", foreground="#e09a3a",
                  justify=tk.LEFT, wraplength=700).pack(side=tk.LEFT)

        ttk.Label(notice_frame,
                  text="⚠  Age-restricted or private videos cannot be downloaded.",
                  style="Sub.TLabel", foreground="#e09a3a",
                  justify=tk.LEFT, wraplength=800).pack(anchor="w")

        ttk.Label(notice_frame,
                  text="Note: YouTube Music links (music.youtube.com) are not directly supported "
                       "by yt-dlp, but you can still paste them here. They usually reroute to "
                       "the matching supported YouTube video automatically. If yt-dlp keeps "
                       "failing even after Deno is installed, install Node.js too; that fixes "
                       "YouTube download failures for most users.",
                  style="Sub.TLabel", foreground="#58a6ff",
                  justify=tk.LEFT, wraplength=800).pack(anchor="w", pady=(4, 0))

        # URL input
        url_frame = ttk.LabelFrame(main, text=" YouTube URL ", padding=8)
        url_frame.pack(fill=tk.X, pady=(0, 8))
        url_row = ttk.Frame(url_frame)
        url_row.pack(fill=tk.X)
        self.yt_url_var = tk.StringVar()
        ttk.Entry(url_row, textvariable=self.yt_url_var, width=70).pack(side=tk.LEFT, padx=(0, 8))
        ttk.Button(url_row, text="✕", width=2,
                   command=lambda: self.yt_url_var.set("")).pack(side=tk.LEFT)

        # v4.4.61-1 (owner layout revision) — TOP BAND. The asset preview sits at
        # the left; the Format, JS-Runtime and Cookies boxes move UP beside it,
        # into the empty space that used to sit right of the thumbnail. This
        # collapses ~4 stacked sections into one band so the bottom [log|library]
        # split reclaims the vertical space. _yt_relayout_band (defined after the
        # boxes exist) reflows to a 2×2 grid when the tab is narrow (compact/1080p)
        # so the Runtime/Cookies boxes never overflow their column.
        top_band = ttk.Frame(main)
        top_band.pack(fill=tk.X, pady=(0, 8))

        # ── Asset preview (band col 0) — gridded by _yt_relayout_band ─────────
        thumb_outer = ttk.Frame(top_band)

        # v4.4.62-1 — larger 16:9 preview box (was 240×135) with a CYAN border
        # (was a gray groove) so it fills col 0 and reads closer in size to the
        # Format/Runtime/Cookies cards beside it. At 180px tall it's the tallest
        # band element, so it drives the band height and those cards stretch to
        # match it.
        thumb_img_box = tk.Frame(thumb_outer, width=320, height=180,
                                  bg="#0d0d1a", relief="flat", bd=0,
                                  highlightthickness=2,
                                  highlightbackground="#00d4d4",
                                  highlightcolor="#00d4d4")
        thumb_img_box.pack(side=tk.LEFT, padx=(0, 12))
        thumb_img_box.pack_propagate(False)
        self.yt_thumb_lbl = tk.Label(thumb_img_box, bg="#0d0d1a", text="",
                                      borderwidth=0)
        self.yt_thumb_lbl.pack(fill=tk.BOTH, expand=True)

        thumb_text_col = ttk.Frame(thumb_outer)
        thumb_text_col.pack(side=tk.LEFT, fill=tk.BOTH, expand=True, anchor="n")
        self.yt_thumb_status_var = tk.StringVar(value="Paste a URL above to preview")
        ttk.Label(thumb_text_col, textvariable=self.yt_thumb_status_var,
                  style="Sub.TLabel", foreground="#555555").pack(anchor="w")
        self.yt_thumb_title_var = tk.StringVar(value="")
        ttk.Label(thumb_text_col, textvariable=self.yt_thumb_title_var,
                  foreground="#e0e0ff", font=("Segoe UI", 10, "bold"),
                  wraplength=180, justify=tk.LEFT).pack(anchor="w", pady=(6, 0))

        self._yt_thumb_image   = None   # keep PhotoImage reference (prevents GC)
        self._yt_thumb_after_id = None  # debounce timer ID

        def _on_yt_url_change(*_):
            prev = getattr(self, '_yt_thumb_after_id', None)
            if prev:
                self.root.after_cancel(prev)
            self._yt_thumb_after_id = self.root.after(700, self._yt_fetch_thumbnail)

        self.yt_url_var.trace_add("write", _on_yt_url_change)

        # Output folder
        out_frame = ttk.LabelFrame(main, text=" Output Folder ", padding=8)
        out_frame.pack(fill=tk.X, pady=(0, 8))
        out_row = ttk.Frame(out_frame)
        out_row.pack(fill=tk.X)
        self.yt_out_var = tk.StringVar(
            value=load_config().get("output_folder_yt") or os.path.expanduser("~/Music"))
        yt_out_entry = ttk.Entry(out_row, textvariable=self.yt_out_var, width=60)
        yt_out_entry.pack(side=tk.LEFT, padx=(0, 8))
        ttk.Button(out_row, text="Browse...",
                   command=lambda: (
                       self.yt_out_var.set(
                           filedialog.askdirectory(title="Select output folder")
                           or self.yt_out_var.get()),
                       save_config({"output_folder_yt": self.yt_out_var.get()}))
                   ).pack(side=tk.LEFT)
        self.yt_out_var.trace_add("write",
            lambda *_: save_config({"output_folder_yt": self.yt_out_var.get()}))

        # Format options (band col 1) — gridded by _yt_relayout_band. Radios
        # stack vertically since this is now a narrower band column, not a
        # full-width row.
        fmt_frame = ttk.LabelFrame(top_band, text=" Format ", padding=8)
        fmt_row = ttk.Frame(fmt_frame)
        fmt_row.pack(anchor="w")
        self.yt_fmt_var = tk.StringVar(value="flac")
        # v4.4.57.92-10 (re-applied v.79-8): MP3 removed from YT format selector — source-acquisition
        # tab limited to lossless formats. Defensive migration: if config holds legacy "mp3", reset to "flac".
        if self.yt_fmt_var.get() == "mp3":
            self.yt_fmt_var.set("flac")
        for fmt, lbl in [("flac", "FLAC (recommended — best quality)"),
                          ("wav",  "WAV (uncompressed, large files)")]:
            ttk.Radiobutton(fmt_row, text=lbl,
                            variable=self.yt_fmt_var, value=fmt).pack(anchor="w")
        ttk.Label(fmt_frame,
                  text="💡  FLAC is the best choice for Stem Splitter input — lossless and compact.",
                  style="Sub.TLabel", foreground="#b388ff",
                  wraplength=220, justify=tk.LEFT).pack(anchor="w", pady=(4, 0))

        # Custom filename — opt-in override of the default video-title basename.
        # Off by default: the file is saved as the YouTube video title (the
        # behavior every prior v4.4.x release shipped). Toggle on to type your
        # own name; the file extension (.flac / .wav / .mp3) is added
        # automatically based on the Format choice above.
        custom_name_outer = ttk.Frame(main)
        custom_name_outer.pack(fill=tk.X, pady=(0, 8))

        self.yt_custom_name_enabled_var = tk.BooleanVar(value=False)
        self.yt_custom_name_var = tk.StringVar(value="")

        custom_name_top = ttk.Frame(custom_name_outer)
        custom_name_top.pack(fill=tk.X, anchor="w")
        ttk.Checkbutton(
            custom_name_top,
            text="Name file other than video title",
            variable=self.yt_custom_name_enabled_var,
        ).pack(side=tk.LEFT)

        # The Entry + preview live in this hidden-by-default container so
        # they appear/disappear together based on the toggle.
        self._yt_custom_name_body = ttk.Frame(custom_name_outer)

        entry_row = ttk.Frame(self._yt_custom_name_body)
        entry_row.pack(fill=tk.X, pady=(4, 0))
        ttk.Label(entry_row, text="Filename",
                  style="Sub.TLabel").pack(side=tk.LEFT, padx=(0, 8))
        self._yt_custom_name_entry = ttk.Entry(
            entry_row, textvariable=self.yt_custom_name_var, width=50)
        self._yt_custom_name_entry.pack(side=tk.LEFT, padx=(0, 8))
        ttk.Label(entry_row,
                  text="(no extension — added automatically)",
                  style="Sub.TLabel", foreground="#888").pack(side=tk.LEFT)

        self.yt_custom_name_preview_var = tk.StringVar(
            value="Type a name above to see how it will be saved.")
        ttk.Label(self._yt_custom_name_body,
                  textvariable=self.yt_custom_name_preview_var,
                  style="Sub.TLabel", foreground="#aaaaaa",
                  wraplength=700, justify=tk.LEFT).pack(anchor="w", pady=(2, 0))

        def _yt_refresh_custom_name_preview(*_):
            raw = self.yt_custom_name_var.get()
            sanitized = self._youtube_sanitize_filename(raw)
            ext = (self.yt_fmt_var.get() or "flac").lower()
            if sanitized is None:
                # Empty / whitespace / wiped-out after sanitization
                if raw and raw.strip():
                    self.yt_custom_name_preview_var.set(
                        "Name is invalid after cleanup — file will save as the "
                        "YouTube video title instead.")
                else:
                    self.yt_custom_name_preview_var.set(
                        "Type a name above to see how it will be saved.")
            else:
                self.yt_custom_name_preview_var.set(
                    f"Will save as: {sanitized}.{ext}")

        def _yt_refresh_custom_name_visibility(*_):
            if self.yt_custom_name_enabled_var.get():
                if not self._yt_custom_name_body.winfo_manager():
                    self._yt_custom_name_body.pack(fill=tk.X, pady=(4, 0))
                _yt_refresh_custom_name_preview()
            else:
                if self._yt_custom_name_body.winfo_manager():
                    self._yt_custom_name_body.pack_forget()

        self.yt_custom_name_enabled_var.trace_add(
            "write", _yt_refresh_custom_name_visibility)
        self.yt_custom_name_var.trace_add(
            "write", _yt_refresh_custom_name_preview)
        # Keep the preview in sync if the user changes Format mid-session.
        self.yt_fmt_var.trace_add(
            "write", _yt_refresh_custom_name_preview)
        # Initial layout pass — hidden because the toggle defaults to False.
        _yt_refresh_custom_name_visibility()

        # yt-dlp update toggle
        upd_row = ttk.Frame(main)
        upd_row.pack(anchor="w", pady=(0, 8))
        self.yt_autoupdate_var = tk.BooleanVar(value=True)
        ttk.Checkbutton(upd_row, text="Auto-update yt-dlp before downloading",
                        variable=self.yt_autoupdate_var).pack(side=tk.LEFT)
        ttk.Label(upd_row,
                  text="  (keeps YouTube compatibility — recommended)",
                  style="Sub.TLabel", foreground="#555").pack(side=tk.LEFT)

        # Cookie options + Node.js custom path (loaded once from shared config)
        cookie_cfg = load_config()
        self.yt_node_path_var = tk.StringVar(value=cookie_cfg.get("yt_node_path", ""))
        # Cookies (band col 3 wide / row 1 narrow) — gridded by _yt_relayout_band
        cookie_frame = ttk.LabelFrame(top_band, text=" YouTube Login / Cookies ", padding=8)

        self.yt_cookie_mode_var = tk.StringVar(value=cookie_cfg.get("yt_cookie_mode", "none"))
