    # =====================================================================
    # v4.4.61-1 — YouTube → FLAC: Send-to-Stem + Downloaded-Songs Library
    # UI + file-management glue only. No protected functions, no download /
    # Demucs logic change. Split / MIDI pairing is computed live from disk;
    # the registry stores only the list of downloads.
    # =====================================================================

    @staticmethod
    def _yt_ellipsize(text, n):
        """Approximate single-line ellipsis (Tk labels have no native one)."""
        text = text or ""
        return text if len(text) <= n else text[:max(1, n - 1)].rstrip() + "…"

    def _yt_fmt_duration(self, sec):
        try:
            if sec is None:
                return ""
            sec = int(round(float(sec)))
            m, s = divmod(sec, 60)
            if m >= 60:
                h, m = divmod(m, 60)
                return f"{h}:{m:02d}:{s:02d}"
            return f"{m}:{s:02d}"
        except Exception:
            return ""

    def _open_folder_crossplatform(self, folder):
        """Open a folder in the OS file browser (mirror of _stem_open_output)."""
        import subprocess, platform
        try:
            if platform.system() == "Windows":
                os.startfile(folder)
            elif platform.system() == "Darwin":
                subprocess.Popen(["open", folder])
            else:
                subprocess.Popen(["xdg-open", folder])
        except Exception as e:
            messagebox.showerror("Error", f"Could not open folder:\n{e}")

    # ── Split / MIDI detection (path-based, guarded, ISO-aware) ──────────────
    def _stem_is_split(self, audio_path):
        """True if ParaKit can see split drum stems for this song on disk.

        Best-effort + path-based (D1). Probes the standard DRUMS ONLY/ folder
        and the ISO DRUMS/ folder under both the main stem-output base and the
        dedicated ISO output base. Renamed outputs can still evade this — a
        documented limitation, not a guarantee.
        """
        try:
            song = os.path.splitext(os.path.basename(audio_path))[0]
        except Exception:
            return False
        candidates = []
        base_var = getattr(self, "stem_output_var", None)
        base = base_var.get().strip() if base_var else ""
        if base and os.path.isdir(base):
            candidates.append(os.path.join(base, "DRUMS ONLY", f"{song}_drums.ogg"))
            candidates.append(os.path.join(base, "DRUMS", f"{song}_drums.ogg"))
        iso_var = getattr(self, "stem_iso_output_var", None)
        iso_base = iso_var.get().strip() if iso_var else ""
        if iso_base and os.path.isdir(iso_base):
            candidates.append(os.path.join(iso_base, "DRUMS", f"{song}_drums.ogg"))
        for c in candidates:
            try:
                if os.path.isfile(c):
                    return True
            except Exception:
                pass
        return False

    def _midi_paired(self, audio_path):
        """True if an A2M MIDI exists for this song (D4).

        A2M writes <out>/MIDIs/<song> MIDI.mid; the Stem→A2M flow feeds the
        DRUMS stem so the real file is often <song>_drums MIDI.mid — scan both.
        Guards empty a2m_output_var. A custom output folder or a moved MIDI
        defeats it (documented limitation).
        """
        out_var = getattr(self, "a2m_output_var", None)
        out = out_var.get().strip() if out_var else ""
        if not out:
            return False
        try:
            song = os.path.splitext(os.path.basename(audio_path))[0]
        except Exception:
            return False
        for name in (f"{song} MIDI.mid", f"{song}_drums MIDI.mid"):
            try:
                if os.path.isfile(os.path.join(out, "MIDIs", name)):
                    return True
            except Exception:
                pass
        return False

    def _ogg_paired(self, audio_path):
        """True if an .ogg for this song exists where the Stem Splitter sends them.

        The Stem Splitter writes its .ogg stems (``<song>_drums.ogg`` /
        ``<song>_backing.ogg`` / per-part ``<song>_<part>.ogg``) into per-stem
        SUBFOLDERS of the stem-output base(s) (DRUMS ONLY / BACKINGS / DRUMS /
        BASS / VOCALS / …) — while the lossless detector copy goes out as .flac to
        a SEPARATE ``LOSSLESS SPLITS (DRUMS)`` folder. So the .ogg is NOT next to
        the song's FLAC download. Two name-scoped passes (match ``<song>.ogg`` or
        ``<song>_*.ogg`` only, so a neighbouring song's .ogg never
        false-positives):

          1. PRIMARY — the configured stem-output base(s) (same `stem_output_var`
             / `stem_iso_output_var` the Stem tab + `_stem_is_split` use), their
             immediate subfolders, and the bases themselves.
          2. FALLBACK — a bounded recursive scan of the project folder (≤4000
             dirs / ≤5 levels, skips hidden/system), memoised for the lifetime of
             one library refresh so the rows share ONE walk (see
             `_yt_ogg_project_oggs`).
        """
        try:
            song = os.path.splitext(os.path.basename(audio_path))[0]
        except Exception:
            return False
        if not song:
            return False
        song_l = song.lower()

        def _is_song_ogg(fn_lower):
            return fn_lower.endswith(".ogg") and (
                fn_lower == song_l + ".ogg" or fn_lower.startswith(song_l + "_"))

        # 1) PRIMARY — the Stem Splitter's .ogg output base(s) (vars, like
        #    _stem_is_split). Scan each base's immediate subfolders (where the
        #    per-stem .ogg live) plus any .ogg sitting directly in the base.
        bases = []
        for var_name in ("stem_output_var", "stem_iso_output_var"):
            vv = getattr(self, var_name, None)
            try:
                b = vv.get().strip() if vv is not None else ""
            except Exception:
                b = ""
            if b and os.path.isdir(b) and b not in bases:
                bases.append(b)
        for base in bases:
            try:
                for entry in os.listdir(base):
                    full = os.path.join(base, entry)
                    if os.path.isdir(full):
                        for fn in os.listdir(full):
                            if _is_song_ogg(fn.lower()):
                                return True
                    elif _is_song_ogg(entry.lower()):
                        return True
            except Exception:
                pass

        # 2) FALLBACK — bounded, memoised recursive project scan (miss-only).
        try:
            for fn in self._yt_ogg_project_oggs(audio_path, bases):
                if _is_song_ogg(fn):
                    return True
        except Exception:
            pass
        return False

    def _yt_ogg_project_oggs(self, audio_path, bases):
        """Lazily build + cache the lowercase set of every .ogg basename under the
        project folder, for the OGG-badge fallback (`_ogg_paired`). Roots = the
        common ancestor of the song's download folder + the stem-output base(s),
        plus those folders themselves. Bounded (≤4000 dirs / ≤5 levels, skips
        hidden/system, mirrors the Auto-Fetch recursive fallback) and memoised on
        `self` for the lifetime of one library refresh (cleared at the top of
        `_yt_library_do_refresh`) so the rows share ONE walk."""
        cached = getattr(self, "_yt_ogg_scan_set", None)
        if cached is not None:
            return cached
        known = [os.path.abspath(d) for d in
                 ([os.path.dirname(audio_path)] + list(bases)) if d and os.path.isdir(d)]
        roots = []
        try:
            if len(known) >= 2:
                home = os.path.commonpath(known)
                if (home and os.path.isdir(home)
                        and os.path.splitdrive(home)[1].strip("\\/").count(os.sep) >= 1):
                    roots.append(home)
        except Exception:
            pass
        roots.extend(known)
        uniq = []
        for r in sorted(set(roots), key=len):
            if not any(r == p or r.startswith(p + os.sep) for p in uniq):
                uniq.append(r)
        SKIP = {"$recycle.bin", "system volume information", "node_modules",
                ".git", "__pycache__"}
        found, seen, stop = set(), 0, False
        for root in uniq:
            base_depth = root.rstrip("\\/").count(os.sep)
            for dp, dns, fns in os.walk(root):
                seen += 1
                if seen > 4000:                        # hard dir-count cap
                    stop = True
                    break
                if dp.count(os.sep) - base_depth > 5:  # depth cap
                    dns[:] = []
                    continue
                dns[:] = [d for d in dns
                          if not d.startswith(".") and d.lower() not in SKIP]
                for fn in fns:
                    if fn.lower().endswith(".ogg"):
                        found.add(fn.lower())
            if stop:
                break
        self._yt_ogg_scan_set = found
        return found

    def _open_stems_folder(self, audio_path):
        """Open whichever split folder actually holds this song's drums."""
        try:
            song = os.path.splitext(os.path.basename(audio_path))[0]
        except Exception:
            song = ""
        base_var = getattr(self, "stem_output_var", None)
        base = base_var.get().strip() if base_var else ""
        iso_var = getattr(self, "stem_iso_output_var", None)
        iso_base = iso_var.get().strip() if iso_var else ""
        probes = []
        if base:
            probes.append((os.path.join(base, "DRUMS ONLY"), f"{song}_drums.ogg"))
            probes.append((os.path.join(base, "DRUMS"), f"{song}_drums.ogg"))
        if iso_base:
            probes.append((os.path.join(iso_base, "DRUMS"), f"{song}_drums.ogg"))
        target = None
        for folder, fname in probes:
            try:
                if os.path.isfile(os.path.join(folder, fname)):
                    target = folder
                    break
            except Exception:
                pass
        if not target:
            # Don't fall back to os.getcwd() — for a frozen exe that can be the
            # install dir / System32. Use a real existing stem base, else tell
            # the user the stems are gone (race: deleted after the badge showed).
            for fallback in (base, iso_base):
                if fallback and os.path.isdir(fallback):
                    target = fallback
                    break
            if not target:
                messagebox.showinfo(
                    "Stems not found",
                    "Couldn't find this song's split stems — they may have been "
                    "moved or deleted.")
                return
        self._open_folder_crossplatform(target)

    # ── Send-to-Stem (shared by header button + library rows) ───────────────
    def _send_audio_to_stem(self, path):
        if not path or not os.path.isfile(path):
            messagebox.showwarning(
                "File not found",
                "That download is no longer on disk:\n" + str(path))
            return
        try:
            self.stem_input_var.set(path)        # no trace → inert, just sets text
        except Exception:
            pass
        try:
            self._add_recent_file("recent_stem_audio", path)
        except Exception:
            pass
        try:
            self.notebook.select(self._tab_indexes["stem"])
        except Exception:
            pass
        try:
            self._stem_log(f"Loaded from YouTube library: {os.path.basename(path)}")
        except Exception:
            pass

    def _yt_send_last_to_stem(self):
        path = getattr(self, "_yt_last_downloaded", None)
        if not path:
            messagebox.showinfo("Nothing to send", "Download a song first.")
            return
        self._send_audio_to_stem(path)

    # ── Full-song preview player (v4.4.62-1) ─────────────────────────────────
    # Plays the WHOLE song (no cap) through the shared pygame.mixer.music stream
    # the rest of the app already uses. We only ever touch that stream while OUR
    # preview is active, and we stop on leaving the YouTube tab, so it can't get
    # in the way of other tabs' audio (by user mistake or a glitch).
    def _yt_preview_ensure_mixer(self):
        import pygame
        if not pygame.mixer.get_init():
            pygame.mixer.init(frequency=44100, size=-16, channels=2, buffer=512)

    def _yt_preview_toggle(self, path):
        if not path or not os.path.isfile(path):
            messagebox.showwarning(
                "File not found",
                "That download is no longer on disk:\n" + str(path))
            return
        try:
            import pygame
        except Exception:
            messagebox.showinfo(
                "Preview unavailable",
                "Audio preview needs pygame, which isn't available in this build.")
            return
        try:
            self._yt_preview_ensure_mixer()
        except Exception as e:
            messagebox.showerror("Preview failed", f"Could not start audio:\n{e}")
            return
        cur = getattr(self, "_yt_preview_path", None)
        state = getattr(self, "_yt_preview_state", None)
        if cur == path and state == "playing":
            try:
                pygame.mixer.music.pause()
            except Exception:
                pass
            self._yt_preview_state = "paused"
        elif cur == path and state == "paused":
            try:
                pygame.mixer.music.unpause()
            except Exception:
                pass
            self._yt_preview_state = "playing"
            self._yt_preview_schedule_poll()
        else:
            try:
                pygame.mixer.music.stop()
                pygame.mixer.music.load(path)
                pygame.mixer.music.play()   # whole song, no length cap
            except Exception as e:
                self._yt_preview_path = None
                self._yt_preview_state = None
                self._yt_preview_update_chips()
                messagebox.showerror("Preview failed", f"Could not play this file:\n{e}")
                return
            self._yt_preview_path = path
            self._yt_preview_state = "playing"
            self._yt_preview_schedule_poll()
        self._yt_preview_update_chips()

    def _yt_preview_stop(self):
        """Stop the preview — but only if OUR preview is what's playing, so we
        never yank the shared mixer out from under another tab."""
        if (getattr(self, "_yt_preview_state", None) is None
                and getattr(self, "_yt_preview_path", None) is None):
            return
        try:
            import pygame
            if pygame.mixer.get_init():
                pygame.mixer.music.stop()
                try:
                    # Release the file handle (pygame 2.0+) so a delete-from-disk
                    # of the just-previewed song isn't blocked by an open handle
                    # on Windows.
                    pygame.mixer.music.unload()
                except Exception:
                    pass
        except Exception:
            pass
        self._yt_preview_path = None
        self._yt_preview_state = None
        self._yt_preview_update_chips()

    def _yt_preview_schedule_poll(self):
        """Schedule the end-of-song poll, cancelling any prior one so rapid
        play/pause/unpause can't spawn overlapping (multiplying) poll loops."""
        prev = getattr(self, "_yt_preview_poll_after", None)
        if prev:
            try:
                self.root.after_cancel(prev)
            except Exception:
                pass
        self._yt_preview_poll_after = self.root.after(600, self._yt_preview_poll)

    def _yt_preview_poll(self):
        """While playing, detect natural end-of-song and reset the chip."""
        self._yt_preview_poll_after = None
        if getattr(self, "_yt_preview_state", None) != "playing":
            return
        try:
            import pygame
            if pygame.mixer.get_init() and not pygame.mixer.music.get_busy():
                try:
                    # Release the file handle on natural end too (not only in
                    # _yt_preview_stop) so a song that played to completion does
                    # not leave the file locked against a later art re-embed.
                    pygame.mixer.music.unload()
                except Exception:
                    pass
                self._yt_preview_path = None
                self._yt_preview_state = None
                self._yt_preview_update_chips()
                return
        except Exception:
            pass
        self._yt_preview_schedule_poll()

    def _yt_preview_update_chips(self):
        cur = getattr(self, "_yt_preview_path", None)
        state = getattr(self, "_yt_preview_state", None)
        for r in getattr(self, "_yt_lib_rows", []):
            chip = getattr(r, "_yt_play_chip", None)
            if chip is None:
                continue
            try:
                playing = (getattr(r, "_yt_path", None) == cur and state == "playing")
                _bg = YT_PAUSE_CHIP_BG if playing else YT_PLAY_CHIP_BG
                chip.configure(text="⏸  Pause" if playing else "▶  Play",
                               bg=_bg, highlightbackground=_bg, highlightcolor=_bg)
            except Exception:
                pass

    def _yt_on_tab_changed_stop_preview(self, _e=None):
        """Stop the preview whenever the user leaves the YouTube tab."""
        try:
            if self.notebook.index("current") != self._tab_indexes.get("youtube"):
                self._yt_preview_stop()
        except Exception:
            pass

    # ── Delete a library entry (v4.4.62-1) ───────────────────────────────────
    def _yt_delete_entry(self, path):
        """Row Delete chip. Honours a remembered choice once the user ticked
        'don't show again'; otherwise asks remove-from-list vs delete-from-disk."""
        cfg = load_config()
        if cfg.get("yt_library_delete_warn_dismissed"):
            self._yt_do_delete(path, cfg.get("yt_library_delete_action", "list"))
            return
        self._yt_delete_confirm(path)

    def _yt_delete_confirm(self, path):
        """Modal 'Are you sure?' with the list-vs-disk choice + don't-show-again."""
        try:
            song = os.path.splitext(os.path.basename(path))[0]
        except Exception:
            song = os.path.basename(path)
        dlg = tk.Toplevel(self.root)
        dlg.title("Are you sure?")
        dlg.configure(bg="#222222")
        dlg.resizable(False, False)
        dlg.transient(self.root)
        dlg.grab_set()
        pw, ph = 520, 250
        try:
            px = self.root.winfo_x() + (self.root.winfo_width() - pw) // 2
            py = self.root.winfo_y() + (self.root.winfo_height() - ph) // 2
            dlg.geometry(f"{pw}x{ph}+{px}+{py}")
        except Exception:
            dlg.geometry(f"{pw}x{ph}")

        frame = ttk.Frame(dlg, padding=18)
        frame.pack(fill=tk.BOTH, expand=True)
        ttk.Label(frame, text="Are you sure?",
                  font=("Segoe UI", 12, "bold"),
                  foreground="#e05650").pack(anchor="w", pady=(0, 8))
        ttk.Label(frame, text=f"Delete '{song}' from your library?",
                  style="TLabel", wraplength=480, justify=tk.LEFT).pack(anchor="w")
        ttk.Label(frame,
                  text="- Remove from list keeps the audio file on your disk.\n"
                       "- Delete from disk permanently deletes the file (no Recycle Bin).",
                  style="Sub.TLabel", foreground="#9a9ab0",
                  wraplength=480, justify=tk.LEFT).pack(anchor="w", pady=(8, 0))

        dismiss_var = tk.BooleanVar(value=False)
        ttk.Checkbutton(frame, text="Don't show me this again (remember my choice)",
                        variable=dismiss_var).pack(anchor="w", pady=(12, 0))

        btn_row = ttk.Frame(frame)
        btn_row.pack(anchor="e", pady=(16, 0))

        def _finish(action):
            if dismiss_var.get():
                save_config({"yt_library_delete_warn_dismissed": True,
                             "yt_library_delete_action": action})
            dlg.destroy()
            self._yt_do_delete(path, action)

        ttk.Button(btn_row, text="Cancel", command=dlg.destroy).pack(
            side=tk.LEFT, padx=(0, 8))
        ttk.Button(btn_row, text="Remove from list",
                   command=lambda: _finish("list")).pack(side=tk.LEFT, padx=(0, 8))
        ttk.Button(btn_row, text="Delete from disk",
                   command=lambda: _finish("disk")).pack(side=tk.LEFT)
        dlg.protocol("WM_DELETE_WINDOW", dlg.destroy)

    def _yt_do_delete(self, path, action):
        """Remove the library entry; if action=='disk' also PERMANENTLY delete
        the audio file (no Recycle Bin, per owner). Stops the preview first if
        this is the song playing."""
        try:
            norm = os.path.normcase(os.path.abspath(path))
        except Exception:
            norm = path
        if getattr(self, "_yt_preview_path", None) == path:
            self._yt_preview_stop()
        # Drop the registry entry (locked) + clean up its cached art PNG.
        with YT_LIBRARY_LOCK:
            entries = self._yt_library_load()
            kept, removed = [], []
            for e in entries:
                try:
                    is_match = os.path.normcase(
                        os.path.abspath(e.get("path", ""))) == norm
                except Exception:
                    is_match = False
                (removed if is_match else kept).append(e)
            for e in removed:
                ac = e.get("art_cache")
                if ac and os.path.isfile(ac):
                    try:
                        os.remove(ac)
                    except Exception:
                        pass
            if removed:
                self._yt_library_save(kept)
        try:
            self._yt_lib_art_refs.pop(path, None)
        except Exception:
            pass
        if action == "disk":
            try:
                if os.path.isfile(path):
                    os.remove(path)   # permanent — owner chose no Recycle Bin
            except Exception as e:
                messagebox.showerror(
                    "Delete failed",
                    "Removed it from the library, but the file itself could not "
                    f"be deleted:\n{e}")
        self._yt_library_refresh()

    # ── Registry (standalone, atomic — clone of save_config discipline) ──────
    def _yt_library_load(self):
        for p in (YT_LIBRARY_PATH, YT_LIBRARY_BAK_PATH):
            try:
                with open(p, "r", encoding="utf-8") as f:
                    data = json.load(f)
                if isinstance(data, list):
                    return data
            except Exception:
                continue
        return []

    def _yt_library_save(self, entries):
        try:
            tmp = YT_LIBRARY_PATH + ".tmp"
            with open(tmp, "w", encoding="utf-8") as f:
                json.dump(entries, f, indent=2)
                try:
                    f.flush()
                    os.fsync(f.fileno())
                except Exception:
                    pass
            os.replace(tmp, YT_LIBRARY_PATH)
            try:
                shutil.copyfile(YT_LIBRARY_PATH, YT_LIBRARY_BAK_PATH)
            except Exception:
                pass
        except Exception:
            pass

    def _yt_library_add(self, path, fmt, duration, art, title=None, artist=None):
        """Upsert one download by path, then persist (atomic). Fast (no slow
        I/O), so it holds YT_LIBRARY_LOCK for its whole load-modify-save."""
        import time as _t
        try:
            norm = os.path.normcase(os.path.abspath(path))
        except Exception:
            norm = path
        with YT_LIBRARY_LOCK:
            entries = self._yt_library_load()
            found = None
            for e in entries:
                try:
                    if os.path.normcase(os.path.abspath(e.get("path", ""))) == norm:
                        found = e
                        break
                except Exception:
                    continue
            if found is None:
                entries.append({
                    "path": path,
                    "title": title or os.path.splitext(os.path.basename(path))[0],
                    "artist": artist or "",
                    "fmt": (fmt or "").lower(),
                    "duration_sec": duration,
                    "art_cache": art,
                    "added_ts": _t.time(),
                })
            else:
                if title:
                    found["title"] = title
                if artist:
                    found["artist"] = artist
                if fmt:
                    found["fmt"] = fmt.lower()
                if duration is not None:
                    found["duration_sec"] = duration
                if art:
                    found["art_cache"] = art
            self._yt_library_save(entries)

    # ── Duration + art + metadata helpers (worker-thread safe) ───────────────
    def _yt_audio_duration(self, path):
        try:
            ext = os.path.splitext(path)[1].lower()
            if ext == ".flac":
                from mutagen.flac import FLAC
                return float(FLAC(path).info.length)
            if ext == ".wav":
                try:
                    from mutagen.wave import WAVE
                    return float(WAVE(path).info.length)
                except Exception:
                    import wave, contextlib
                    with contextlib.closing(wave.open(path, "rb")) as w:
                        return w.getnframes() / float(w.getframerate())
            from mutagen import File as _MF
            mf = _MF(path)
            if mf is not None and getattr(mf, "info", None) is not None:
                return float(mf.info.length)
        except Exception:
            pass
        return None

    def _yt_lib_oembed_meta(self, video_id):
        """Best-effort title + author (channel) via YouTube oEmbed."""
        try:
            import urllib.request, urllib.parse, json as _json
            watch = f"https://www.youtube.com/watch?v={video_id}"
            oembed = ("https://www.youtube.com/oembed?"
                      f"url={urllib.parse.quote(watch, safe='')}&format=json")
            with urllib.request.urlopen(oembed, timeout=8) as resp:
                info = _json.loads(resp.read().decode("utf-8"))
            return {"title": info.get("title", ""),
                    "author": info.get("author_name", "")}
        except Exception:
            return None

    def _yt_fetch_art_cache(self, path, video_id):
        """Cache a 44px rounded PNG for a library row → returns the PNG path.

        Prefers the cover art ALREADY EMBEDDED in the audio file — ParaKit bakes
        the YouTube thumbnail into each download via "Embed thumbnail as album
        art", so this works offline AND for backfilled songs (no video id). Falls
        back to fetching the YouTube thumbnail by video_id only when the file has
        no embedded art (e.g. WAV, or art-embed was off). Worker-thread safe;
        returns None on any failure. Never touches Tk.
        """
        try:
            import hashlib, io
            os.makedirs(YT_ART_CACHE_DIR, exist_ok=True)
            key = hashlib.sha1(path.encode("utf-8")).hexdigest()
            out_png = os.path.join(YT_ART_CACHE_DIR, key + ".png")
            if os.path.isfile(out_png):
                return out_png
            data = None
            # 1) Embedded cover art (the common case for ParaKit FLAC downloads).
            try:
                art_bytes, _mime = self._extract_album_art_from_audio(path)
                if art_bytes and len(art_bytes) > 200:
                    data = art_bytes
            except Exception:
                data = None
            # 2) Fall back to the YouTube thumbnail when there's no embedded art.
            if not data and video_id:
                import urllib.request
                for q in ("mqdefault", "hqdefault", "default"):
                    try:
                        with urllib.request.urlopen(
                                f"https://img.youtube.com/vi/{video_id}/{q}.jpg",
                                timeout=8) as r:
                            d = r.read()
                        if len(d) > 1500:
                            data = d
                            break
                    except Exception:
                        continue
            if not data:
                return None
            from PIL import Image, ImageDraw
            img = Image.open(io.BytesIO(data)).convert("RGBA")
            iw, ih = img.size
            side = min(iw, ih)
            left, top = (iw - side) // 2, (ih - side) // 2
            img = img.crop((left, top, left + side, top + side)).resize(
                (44, 44), Image.LANCZOS)
            mask = Image.new("L", (44, 44), 0)
            ImageDraw.Draw(mask).rounded_rectangle([0, 0, 43, 43], radius=8, fill=255)
            img.putalpha(mask)
            img.save(out_png, format="PNG")
            return out_png
        except Exception:
            return None

    # ── Download-completion hook (called via root.after from the worker) ─────
    def _yt_newest_audio_in(self, out_dir, fmt):
        try:
            import glob
            exts = set([(fmt or "").lower(), "flac", "wav"])
            exts.discard("")
            cands = []
            for ext in exts:
                cands.extend(glob.glob(os.path.join(out_dir, f"*.{ext}")))
            if not cands:
                return None
            return max(cands, key=lambda p: os.path.getmtime(p))
        except Exception:
            return None

    def _yt_on_download_complete(self, path, fmt, out_dir, video_id=None):
        """Record the download, enable Send-to-Stem, add it to the library.

        `path` comes from yt-dlp's [ExtractAudio] Destination line but can be
        None even on success → fall back to the newest matching file in out_dir.
        """
        final = path
        if not final or not os.path.isfile(final):
            final = self._yt_newest_audio_in(out_dir, fmt)
        if not final or not os.path.isfile(final):
            try:
                self._yt_log("Library: couldn't locate the downloaded file to add it.")
            except Exception:
                pass
            return
        self._yt_last_downloaded = final
        try:
            if hasattr(self, "yt_send_stem_btn"):
                self.yt_send_stem_btn.configure(state="normal")
        except Exception:
            pass

        def _meta_worker(p=final, f=fmt, vid=video_id):
            dur = self._yt_audio_duration(p)
            title = os.path.splitext(os.path.basename(p))[0]
            artist = ""
            if vid:
                meta = self._yt_lib_oembed_meta(vid)
                if meta:
                    title = meta.get("title") or title
                    artist = meta.get("author", "") or ""
            # Art: embedded cover first (always available on FLAC downloads),
            # then the YouTube thumbnail by id — so art shows even without vid.
            art = self._yt_fetch_art_cache(p, vid)
            self.root.after(0, lambda: (
                self._yt_library_add(p, f, dur, art, title, artist),
                self._yt_library_refresh()))

        import threading
        threading.Thread(target=_meta_worker, daemon=True).start()

    def _yt_library_maybe_backfill(self):
        """D5b — one-time scan of the YT output folder for pre-existing
        FLAC/WAV files, on a worker thread, guarded by a config flag."""
        cfg = load_config()
        if cfg.get("yt_library_backfilled"):
            return
        out_dir = ""
        try:
            out_dir = self.yt_out_var.get().strip()
        except Exception:
            pass

        def _worker(folder=out_dir):
            added = 0
            try:
                if folder and os.path.isdir(folder):
                    import glob
                    # 1) Slow phase (NO lock): scan files + probe durations,
                    # building candidate rows. De-dup against a snapshot.
                    snap_existing = set()
                    for e in self._yt_library_load():
                        try:
                            snap_existing.add(os.path.normcase(
                                os.path.abspath(e.get("path", ""))))
                        except Exception:
                            pass
                    files = []
                    for ext in ("flac", "wav"):
                        files.extend(glob.glob(os.path.join(folder, f"*.{ext}")))
                    candidates = []
                    for fp in files:
                        try:
                            npath = os.path.normcase(os.path.abspath(fp))
                        except Exception:
                            npath = fp
                        if npath in snap_existing:
                            continue
                        snap_existing.add(npath)
                        candidates.append({
                            "path": fp,
                            "title": os.path.splitext(os.path.basename(fp))[0],
                            "artist": "",
                            "fmt": os.path.splitext(fp)[1].lstrip(".").lower(),
                            "duration_sec": self._yt_audio_duration(fp),
                            "art_cache": None,
                            "added_ts": os.path.getmtime(fp),
                        })
                    # 2) Fast phase (LOCKED): reload + re-dedup + merge + save,
                    # so rows added by a concurrent download aren't clobbered.
                    if candidates:
                        with YT_LIBRARY_LOCK:
                            entries = self._yt_library_load()
                            have = set()
                            for e in entries:
                                try:
                                    have.add(os.path.normcase(
                                        os.path.abspath(e.get("path", ""))))
                                except Exception:
                                    pass
                            for c in candidates:
                                try:
                                    cp = os.path.normcase(os.path.abspath(c["path"]))
                                except Exception:
                                    cp = c["path"]
                                if cp not in have:
                                    entries.append(c)
                                    have.add(cp)
                                    added += 1
                            if added:
                                self._yt_library_save(entries)
            except Exception:
                pass
            # Mark done regardless so we don't rescan every launch.
            save_config({"yt_library_backfilled": True})
            if added:
                self.root.after(0, self._yt_library_refresh)

        import threading
        threading.Thread(target=_worker, daemon=True).start()

    def _yt_library_ensure_art(self):
        """Backfill missing row art from EMBEDDED cover art, on a worker thread.

        Runs each launch but only touches entries that still lack a valid
        art_cache — so registry rows added before this fix (or via the file
        backfill, which stores art_cache=None) get their cover art populated
        from the art ParaKit already embedded in the file. Idempotent + cheap.
        """
        def _worker():
            try:
                # 1) Slow phase (NO lock): extract embedded art for entries that
                # still lack it, into a {path: art_png} map.
                updates = {}
                for e in self._yt_library_load():
                    p = e.get("path")
                    if not p or not os.path.isfile(p):
                        continue
                    ac = e.get("art_cache")
                    if ac and os.path.isfile(ac):
                        continue  # already has art
                    art = self._yt_fetch_art_cache(p, None)  # embedded art
                    if art:
                        updates[p] = art
                if not updates:
                    return
                # 2) Fast phase (LOCKED): reload + apply + save so a concurrent
                # download add / file-backfill isn't clobbered.
                with YT_LIBRARY_LOCK:
                    entries = self._yt_library_load()
                    changed = False
                    for e in entries:
                        p = e.get("path")
                        ac = e.get("art_cache")
                        if p in updates and not (ac and os.path.isfile(ac)):
                            e["art_cache"] = updates[p]
                            changed = True
                    if changed:
                        self._yt_library_save(entries)
                self.root.after(0, self._yt_library_refresh)
            except Exception:
                pass
        import threading
        threading.Thread(target=_worker, daemon=True).start()

    # ── Library UI ───────────────────────────────────────────────────────────
    def _yt_library_build(self, parent):
        self._yt_lib_art_refs = getattr(self, "_yt_lib_art_refs", {})
        self._yt_lib_rows = []
        self._yt_lib_selected_path = None
        self._yt_lib_show_all = False
        self._yt_lib_refresh_after = None
        # Per-row full-song preview state (single shared pygame.mixer.music stream)
        self._yt_preview_path = getattr(self, "_yt_preview_path", None)
        self._yt_preview_state = getattr(self, "_yt_preview_state", None)

        ttk.Label(parent, text="YOUR DOWNLOADS",
                  font=("Segoe UI", 8, "bold"), foreground="#9a9ab0").pack(anchor="w")

        bar = ttk.Frame(parent)
        bar.pack(fill=tk.X, pady=(2, 4))
        self._yt_lib_search_var = tk.StringVar()
        search_entry = ttk.Entry(bar, textvariable=self._yt_lib_search_var)
        search_entry.pack(side=tk.LEFT, fill=tk.X, expand=True)
        self._yt_lib_search_var.trace_add("write", self._yt_library_refresh)
        # Lightweight placeholder shim (ttk.Entry has no native placeholder):
        # show a grey cue when empty+unfocused, clear it on focus. A sentinel
        # flag distinguishes the cue from a real query so search ignores it.
        self._yt_lib_search_placeholder = "Search downloads…"
        self._yt_lib_search_is_placeholder = True

        def _yt_search_show_placeholder():
            self._yt_lib_search_is_placeholder = True
            search_entry.configure(foreground="#7e7e96")
            self._yt_lib_search_var.set(self._yt_lib_search_placeholder)

        def _yt_search_on_focus_in(_e):
            if self._yt_lib_search_is_placeholder:
                self._yt_lib_search_is_placeholder = False
                self._yt_lib_search_var.set("")
                search_entry.configure(foreground="#e8e8f0")

        def _yt_search_on_focus_out(_e):
            if not self._yt_lib_search_var.get().strip():
                _yt_search_show_placeholder()
        search_entry.bind("<FocusIn>", _yt_search_on_focus_in)
        search_entry.bind("<FocusOut>", _yt_search_on_focus_out)
        _yt_search_show_placeholder()
        ttk.Label(bar, text="Sort:", style="Sub.TLabel").pack(side=tk.LEFT, padx=(6, 2))
        self._yt_lib_sort_var = tk.StringVar(value="Newest")
        sort_combo = ttk.Combobox(bar, textvariable=self._yt_lib_sort_var,
                                  values=("Newest", "Title", "Not-split first"),
                                  width=14, state="readonly")
        sort_combo.pack(side=tk.LEFT)
        sort_combo.bind("<<ComboboxSelected>>", self._yt_library_refresh)

        canvas_wrap = ttk.Frame(parent)
        canvas_wrap.pack(fill=tk.BOTH, expand=True)
        self._yt_lib_canvas = tk.Canvas(canvas_wrap, bg="#15152a",
                                        highlightthickness=0, bd=0)
        vsb = ttk.Scrollbar(canvas_wrap, orient="vertical",
                            command=self._yt_lib_canvas.yview)
        self._yt_lib_canvas.configure(yscrollcommand=vsb.set)
        self._yt_lib_canvas.pack(side=tk.LEFT, fill=tk.BOTH, expand=True)
        vsb.pack(side=tk.RIGHT, fill=tk.Y)
        self._yt_lib_inner = tk.Frame(self._yt_lib_canvas, bg="#15152a")
        self._yt_lib_inner_id = self._yt_lib_canvas.create_window(
            (0, 0), window=self._yt_lib_inner, anchor="nw")

        def _on_inner_cfg(_e):
            try:
                self._yt_lib_canvas.configure(
                    scrollregion=self._yt_lib_canvas.bbox("all"))
            except Exception:
                pass
        self._yt_lib_inner.bind("<Configure>", _on_inner_cfg)

        def _on_canvas_cfg(e):
            try:
                self._yt_lib_canvas.itemconfigure(self._yt_lib_inner_id, width=e.width)
            except Exception:
                pass
        self._yt_lib_canvas.bind("<Configure>", _on_canvas_cfg)
        # No <MouseWheel> binding here on purpose: the app-level global
        # _on_mousewheel walker (bound via bind_all at init, ~line 6452) walks up
        # from the event widget to the first Canvas/Text and scrolls it — so it
        # already scrolls THIS canvas when the cursor is over a row, in both
        # roomy and compact mode (where this canvas nests inside the tab's
        # scroll-canvas). Adding a local canvas.bind would double-scroll against
        # the walker; bind_all would re-introduce the v4.4.53.7 regression.
        # One exception: the scrollbar (vsb) is a SIBLING of the canvas, so the
        # walker would climb past it to the outer tab canvas. Bind the wheel
        # LOCALLY on vsb (not bind_all) to forward it to this canvas.
        def _vsb_wheel(e):
            try:
                self._yt_lib_canvas.yview_scroll(int(-1 * (e.delta / 120)), "units")
            except Exception:
                pass
            return "break"
        vsb.bind("<MouseWheel>", _vsb_wheel)

        self._yt_library_refresh()
        self.root.after(600, self._yt_library_maybe_backfill)
        # Fill any missing row art from the files' embedded cover art (covers
        # rows added before this fix + file-backfilled rows). Worker-thread.
        self.root.after(900, self._yt_library_ensure_art)

    def _yt_library_refresh(self, *_):
        """Debounced entry point (search keystrokes / sort / completion)."""
        if not hasattr(self, "_yt_lib_inner"):
            return
        prev = getattr(self, "_yt_lib_refresh_after", None)
        if prev:
            try:
                self.root.after_cancel(prev)
            except Exception:
                pass
        self._yt_lib_refresh_after = self.root.after(200, self._yt_library_do_refresh)

    def _yt_library_do_refresh(self):
        self._yt_lib_refresh_after = None
        self._yt_ogg_scan_set = None   # invalidate the OGG-badge project scan (rebuilt lazily, once)
        if not hasattr(self, "_yt_lib_inner"):
            return
        try:
            if not self._yt_lib_inner.winfo_exists():
                return
        except Exception:
            return

        for child in list(self._yt_lib_inner.winfo_children()):
            try:
                child.destroy()
            except Exception:
                pass
        self._yt_lib_rows = []

        entries = self._yt_library_load()
        live = []
        for e in entries:
            try:
                if e.get("path") and os.path.isfile(e["path"]):
                    live.append(e)
            except Exception:
                pass

        # Ignore the grey placeholder cue — it is not a real query.
        if getattr(self, "_yt_lib_search_is_placeholder", False):
            q = ""
        else:
            q = (self._yt_lib_search_var.get() or "").strip().lower()
        if q:
            live = [e for e in live
                    if q in (e.get("title", "") or "").lower()
                    or q in (e.get("artist", "") or "").lower()]

        sort_mode = self._yt_lib_sort_var.get()
        if sort_mode == "Title":
            live.sort(key=lambda e: (e.get("title", "") or "").lower())
        elif sort_mode == "Not-split first":
            live.sort(key=lambda e: (self._stem_is_split(e.get("path", "")),
                                     (e.get("title", "") or "").lower()))
        else:
            live.sort(key=lambda e: e.get("added_ts", 0), reverse=True)

        if not live:
            msg = ("No downloads yet — grab one above." if not q
                   else "No matches.")
            tk.Label(self._yt_lib_inner, text=msg, bg="#15152a",
                     fg="#7e7e96", font=("Segoe UI", 9),
                     padx=10, pady=14).pack(anchor="w")
        else:
            cap = 60
            show = live if self._yt_lib_show_all else live[:cap]
            for i, e in enumerate(show):
                split = self._stem_is_split(e.get("path", ""))
                midi = self._midi_paired(e.get("path", ""))
                self._yt_lib_row(self._yt_lib_inner, e, split, midi, i)
            if (not self._yt_lib_show_all) and len(live) > cap:
                more = tk.Label(self._yt_lib_inner,
                                text=f"▾  Show all {len(live)} downloads",
                                bg="#15152a", fg="#b388ff", cursor="hand2",
                                font=("Segoe UI", 9, "bold"), pady=6)
                more.pack(fill=tk.X)

                def _show_all(_e):
                    self._yt_lib_show_all = True
                    self._yt_library_do_refresh()
                more.bind("<Button-1>", _show_all)

        # Prune cached PhotoImage refs to currently-rendered rows so the dict
        # doesn't grow unbounded across refreshes/sessions (UI-audit MINOR).
        try:
            rendered = {getattr(r, "_yt_path", None) for r in self._yt_lib_rows}
            self._yt_lib_art_refs = {
                p: v for p, v in self._yt_lib_art_refs.items() if p in rendered}
        except Exception:
            pass

        try:
            self._yt_lib_canvas.update_idletasks()
            self._yt_lib_canvas.configure(
                scrollregion=self._yt_lib_canvas.bbox("all"))
        except Exception:
            pass

    def _yt_make_badge(self, parent, text, present, neutral=False, row=None):
        """Outlined pill. Neutral = format; present = green; absent = dim.

        Contrast (UI-audit fix): absent text #8a8aa2 clears 4.5:1 on the rest/
        odd/hover bands and is ~4.18:1 on the transient selected band only —
        kept intentionally dimmer than the neutral #9a9ab0 per the plan's
        dim-absent intent (the old #7e7e96 failed on odd/hover/select too).
        Border #4a4a6b is perceptible vs the old near-invisible #3a3a55 (~1.6:1).

        v4.4.62-1: the neutral FORMAT badge (FLAC/WAV) is CYAN, not gray — gray
        made it read like a dim "missing" status (like the absent STEMS/MIDI
        badges) when it's actually always-present format info.
        """
        if neutral:
            border, fg = "#00d4d4", "#00d4d4"   # cyan = present format info
        elif text == "OGG":
            border, fg = "#b388ff", "#b388ff"   # purple = .ogg files present (checker)
        elif present:
            border, fg = "#46d18a", "#46d18a"
        else:
            border, fg = "#4a4a6b", "#8a8aa2"
        b = tk.Label(parent, text=text, bg=parent["bg"], fg=fg,
                     font=("Segoe UI", 8), padx=4, pady=0, bd=0,
                     highlightthickness=1, highlightbackground=border,
                     highlightcolor=border)
        b.pack(side=tk.LEFT, padx=2)
        # v4.4.64.1-1 — hover tooltip per badge, reflecting its present/absent
        # state (present = ✔; grayed-out/absent = "<name> file not found ✖").
        # Attached here (before _yt_lib_row's _bind_recursive, which uses add="+")
        # so the tooltip's <Enter>/<Leave> coexist with the row-hover bindings.
        if neutral:
            _tip = "Audio file exists ✔" if present else f"{text} file not found ✖"
        elif text == "OGG":
            _tip = ".ogg files exist"
        elif text == "STEMS":
            _tip = "Split drum stems exist ✔" if present else "STEMS file not found ✖"
        elif text == "MIDI":
            _tip = "MIDI file exists ✔" if present else "MIDI file not found ✖"
        else:
            _tip = None
        if _tip:
            self._add_tooltip(b, _tip)
        if row is not None:
            row._yt_color_targets.append(b)
        return b

    def _yt_lib_select_path(self, path):
        self._yt_lib_selected_path = path
        for r in self._yt_lib_rows:
            try:
                r._yt_set_state("selected" if getattr(r, "_yt_path", None) == path
                                else "rest")
            except Exception:
                pass

    def _yt_lib_row(self, parent, entry, split, midi, idx):
        path = entry.get("path", "")
        rest_bg = "#181830" if (idx % 2) else "#15152a"
        HOVER_BG, SEL_BG, ACCENT = "#22203c", "#2c2748", "#b388ff"

        row = tk.Frame(parent, bg=rest_bg)
        row.pack(fill=tk.X)
        # v4.4.62-1 (owner): only the text column (col 2) expands, so the whole
        # right cluster (Delete · | · badges · duration · Send · Open · Play) is
        # right-aligned at a CONSISTENT position → the Delete chips line up in a
        # column across rows. Open Stems (col 8) + Play (col 9) get a reserved
        # minsize so a non-split row (no Open Stems) or the wider "Pause" glyph
        # can't shift the cluster and break that alignment.
        row.columnconfigure(2, weight=1)
        row.columnconfigure(8, minsize=96)
        row.columnconfigure(9, minsize=80)
        row._yt_path = path
        row._yt_split = split
        row._yt_color_targets = []

        accent = tk.Frame(row, bg=rest_bg, width=3)
        accent.grid(row=0, column=0, sticky="ns")
        row._yt_accent = accent

        # Art (col 1) — never recolored on hover (it's the artwork tile).
        art_path = entry.get("art_cache")
        photo = None
        if art_path and os.path.isfile(art_path):
            try:
                from PIL import Image, ImageTk
                if path in self._yt_lib_art_refs:
                    photo = self._yt_lib_art_refs[path]
                else:
                    photo = ImageTk.PhotoImage(Image.open(art_path))
                    self._yt_lib_art_refs[path] = photo
            except Exception:
                photo = None
        if photo is not None:
            art_lbl = tk.Label(row, image=photo, bg=rest_bg, bd=0)
        else:
            art_lbl = tk.Label(row, text="♪", bg="#0d0d1a", fg="#6f6f8f",
                               font=("Segoe UI", 15), width=3, height=2)
        art_lbl.grid(row=0, column=1, padx=(6, 8), pady=4)

        textcol = tk.Frame(row, bg=rest_bg)
        textcol.grid(row=0, column=2, sticky="ew")
        row._yt_color_targets.append(textcol)
        title = entry.get("title") or os.path.splitext(os.path.basename(path))[0]
        title_lbl = tk.Label(textcol, text=self._yt_ellipsize(title, 42),
                             bg=rest_bg, fg="#e8e8f0",
                             font=("Segoe UI", 10, "bold"), anchor="w", justify="left")
        title_lbl.pack(fill=tk.X, anchor="w")
        row._yt_color_targets.append(title_lbl)
        artist = entry.get("artist") or ""
        if artist:
            art_sub = tk.Label(textcol, text=self._yt_ellipsize(artist, 42),
                               bg=rest_bg, fg="#9a9ab0",
                               font=("Segoe UI", 9), anchor="w", justify="left")
            art_sub.pack(fill=tk.X, anchor="w")
            row._yt_color_targets.append(art_sub)

        # Right-side cluster (cols 5+): badges, duration, then the action chips.
        badges = tk.Frame(row, bg=rest_bg)
        badges.grid(row=0, column=5, padx=(6, 6))
        row._yt_color_targets.append(badges)
        self._yt_make_badge(badges, (entry.get("fmt") or "flac").upper(),
                            present=True, neutral=True, row=row)
        # v4.4.68-1 — purple ".ogg files exist" checker, right next to the format
        # badge; only rendered when an .ogg counterpart of the song is on disk.
        if self._ogg_paired(path):
            self._yt_make_badge(badges, "OGG", present=True, row=row)
        self._yt_make_badge(badges, "STEMS", present=split, row=row)
        self._yt_make_badge(badges, "MIDI", present=midi, row=row)

        dur_lbl = tk.Label(row, text=self._yt_fmt_duration(entry.get("duration_sec")),
                           bg=rest_bg, fg="#9a9ab0", font=("Segoe UI", 9))
        dur_lbl.grid(row=0, column=6, padx=(0, 8))
        row._yt_color_targets.append(dur_lbl)

        # v4.4.61-1 (UI-audit fix) — PERSISTENT bordered action chips, not
        # hover-only ~18px labels. The Practice-v3 reference shows always-visible
        # right-side controls; hover-only tiny targets were a precision-click
        # hazard. padx=8/pady=4 + a 1px border give a ~28px tappable chip; the
        # chip bg tracks the row band (in _yt_color_targets) so the band stays
        # continuous. "Open Stems" only when a split exists.
        def _mk_chip(text, fg, cmd, col, border="#4a4a6b", bg=None, track=True):
            # bg=None → chip rides the row band (added to _yt_color_targets so the
            # band stays continuous on hover). A filled chip (e.g. the purple/pink
            # Play/Pause button) passes its own bg + track=False so the row-hover
            # recolor never repaints over its fill.
            chip = tk.Label(row, text=text, bg=(rest_bg if bg is None else bg), fg=fg,
                            font=("Segoe UI", 9, "bold"), cursor="hand2",
                            padx=8, pady=4, bd=0, highlightthickness=1,
                            highlightbackground=border, highlightcolor=border)
            chip.bind("<Button-1>", lambda _e, p=path: cmd(p))
            chip.grid(row=0, column=col, padx=(0, 4), sticky="e")
            if track:
                row._yt_color_targets.append(chip)
            return chip

        # v4.4.62-1 — Delete chip (red), at col 3 right next to the badges, with a
        # "|" divider (col 4) between them — all right-aligned so they line up.
        _mk_chip("Delete", "#e05650", self._yt_delete_entry, 3, border="#e05650")
        _divider = tk.Label(row, text="|", bg=rest_bg, fg="#5a5a75",
                            font=("Segoe UI", 12))
        _divider.grid(row=0, column=4, padx=(6, 2), sticky="e")
        row._yt_color_targets.append(_divider)

        send_chip = _mk_chip("Send →", ACCENT, self._send_audio_to_stem, 7)
        self._add_tooltip(send_chip, "Sends this song to the Stem Splitter")
        if split:
            open_chip = _mk_chip("Open Stems", "#46d18a", self._open_stems_folder, 8)
            # Tooltip — attach BEFORE _bind_recursive (which uses add="+") so the
            # tooltip's <Enter>/<Leave> and the row-hover bindings coexist.
            self._add_tooltip(open_chip, "Opens your folder containing your drum stems")
        # Full-song play/pause preview, to the RIGHT of Open Stems (col 9). Glyph
        # reflects the live preview state so it stays correct across library
        # refreshes; stored on the row so _yt_preview_update_chips can flip it.
        # Filled brand-colour chip (owner): PURPLE "▶ Play" matches the app's
        # purple buttons, PINK/magenta "⏸ Pause" matches the logo. White text,
        # bg set directly (track=False) so the row-hover recolor leaves it alone.
        _playing = (path == getattr(self, "_yt_preview_path", None)
                    and getattr(self, "_yt_preview_state", None) == "playing")
        _play_bg = YT_PAUSE_CHIP_BG if _playing else YT_PLAY_CHIP_BG
        row._yt_play_chip = _mk_chip(
            "⏸  Pause" if _playing else "▶  Play",
            "#ffffff", self._yt_preview_toggle, 9,
            border=_play_bg, bg=_play_bg, track=False)

        sep = tk.Frame(parent, bg="#222238", height=1)
        sep.pack(fill=tk.X)

        def _set_state(state):
            if state == "selected":
                bg = SEL_BG
                accent.configure(bg=ACCENT)
            elif state == "hover":
                bg = HOVER_BG
                accent.configure(bg=ACCENT)
            else:
                bg = rest_bg
                accent.configure(bg=rest_bg)
            try:
                row.configure(bg=bg)
            except Exception:
                pass
            for w in row._yt_color_targets:
                try:
                    w.configure(bg=bg)
                except Exception:
                    pass
        row._yt_set_state = _set_state

        def _is_selected():
            return self._yt_lib_selected_path == path

        def _on_enter(_e):
            _set_state("selected" if _is_selected() else "hover")

        def _on_leave(_e):
            # Child-crossing guard: a child <Enter> fires <Leave> on the parent.
            # Only collapse if the pointer truly left the row's widget subtree.
            try:
                x, y = self.root.winfo_pointerxy()
                w = row.winfo_containing(x, y)
            except Exception:
                w = None
            inside = False
            while w is not None:
                if w is row:
                    inside = True
                    break
                w = getattr(w, "master", None)
            if inside:
                return
            _set_state("selected" if _is_selected() else "rest")

        def _on_click(_e):
            self._yt_lib_select_path(path)

        def _on_right_click(e):
            # Select the row, then pop a Windows-style context menu.
            self._yt_lib_select_path(path)
            self._yt_lib_context_menu(e, path)
            return "break"

        def _bind_recursive(w):
            w.bind("<Enter>", _on_enter, add="+")
            w.bind("<Leave>", _on_leave, add="+")
            w.bind("<Button-1>", _on_click, add="+")
            w.bind("<Button-3>", _on_right_click, add="+")
            for c in w.winfo_children():
                _bind_recursive(c)
        _bind_recursive(row)

        self._yt_lib_rows.append(row)
        _set_state("selected" if _is_selected() else "rest")

    # ── Library row right-click menu (v4.4.62-1) ─────────────────────────────
    def _yt_lib_context_menu(self, event, path):
        """Windows-style right-click menu for a library row."""
        menu = tk.Menu(self.root, tearoff=0)
        menu.add_command(label="Rename",
                         command=lambda: self._yt_lib_rename(path))
        menu.add_command(label="Open file location",
                         command=lambda: self._yt_lib_open_location(path))
        menu.add_separator()
        menu.add_command(label="Search for missing album art",
                         command=lambda: self._yt_lib_search_art(path))
        menu.add_command(label="Send to Stem Splitter",
                         command=lambda: self._send_audio_to_stem(path))
        try:
            menu.tk_popup(event.x_root, event.y_root)
        finally:
            menu.grab_release()

    def _yt_lib_rename(self, path):
        """Rename the song's LIBRARY LABEL (the registry title) — deliberately NOT
        the file on disk, because renaming the file would break the name-based
        links to its stems (<song>_drums.*) and MIDI (<song> MIDI.mid)."""
        from tkinter import simpledialog
        try:
            norm = os.path.normcase(os.path.abspath(path))
        except Exception:
            norm = path
        cur = ""
        for e in self._yt_library_load():
            try:
                if os.path.normcase(os.path.abspath(e.get("path", ""))) == norm:
                    cur = e.get("title", "") or ""
                    break
            except Exception:
                pass
        new = simpledialog.askstring(
            "Rename", "New name for this song in the library:",
            initialvalue=cur, parent=self.root)
        if new is None:
            return
        new = new.strip()
        if not new:
            return
        with YT_LIBRARY_LOCK:
            entries = self._yt_library_load()
            for e in entries:
                try:
                    if os.path.normcase(os.path.abspath(e.get("path", ""))) == norm:
                        e["title"] = new
                except Exception:
                    pass
            self._yt_library_save(entries)
        self._yt_library_refresh()

    def _yt_lib_open_location(self, path):
        """Open the song's folder, selecting the file where the OS supports it."""
        if not path or not os.path.isfile(path):
            messagebox.showwarning(
                "File not found",
                "That download is no longer on disk:\n" + str(path))
            return
        import subprocess, platform
        try:
            if platform.system() == "Windows":
                subprocess.Popen(["explorer", "/select,", os.path.normpath(path)])
            elif platform.system() == "Darwin":
                subprocess.Popen(["open", "-R", path])
            else:
                subprocess.Popen(["xdg-open", os.path.dirname(path)])
        except Exception as e:
            messagebox.showerror("Error", f"Could not open the file location:\n{e}")

    # ── Right-click → "Search for missing album art" (owner, 2026-06-16) ──────
    def _yt_lib_search_art(self, path):
        """Search iTunes for cover art by the song's LIBRARY NAME (title) and
        embed the first match into the file, then refresh its library thumbnail.

        Lets the user fill in (or overwrite) a song's album art without leaving
        the YouTube tab — the same iTunes lookup the Asset Manager uses, applied
        straight to the library file. Repeatable: each run re-searches by the
        song's CURRENT library name (title) and overwrites whatever art is
        already there, so a user can right-click → Rename and re-run to swap in
        different art."""
        if not path or not os.path.isfile(path):
            messagebox.showwarning(
                "File not found",
                "That download is no longer on disk:\n" + str(path))
            return
        fmt_l = os.path.splitext(path)[1].lower().lstrip(".")
        if fmt_l not in ("flac", "mp3", "ogg", "m4a", "mp4"):
            messagebox.showinfo(
                "Can't embed art in this format",
                (f"Cover art can't be embedded in .{fmt_l} files"
                 if fmt_l else "This file has no extension")
                + (" — WAV has no standard cover-art tag." if fmt_l == "wav"
                   else ".")
                + "\n\nSupported: FLAC, MP3, OGG, and M4A.")
            return
        import re as _re
        # Owner 2026-06-16: search by the song's DISPLAY name — the registry
        # `title` that right-click Rename edits — NOT the on-disk file name.
        # Rename deliberately never renames the file (it would break the
        # name-based links to <song>_drums.* / <song> MIDI.mid), so the file
        # name can stay stale ("Home Soon") after the user renamed the row to
        # "Issues - Headspace". Match the row label (_yt_lib_row): title first,
        # file-name stem only as a fallback.
        raw_name = ""
        try:
            _norm = os.path.normcase(os.path.abspath(path))
        except Exception:
            _norm = path
        for _e in self._yt_library_load():
            try:
                if os.path.normcase(os.path.abspath(_e.get("path", ""))) == _norm:
                    raw_name = (_e.get("title") or "").strip()
                    break
            except Exception:
                pass
        if not raw_name:
            raw_name = os.path.splitext(os.path.basename(path))[0]
        # Names are usually "Song - Artist (extra info / cover / version /
        # live / …)" — the bracketed tail is almost always noise for a
        # cover-art lookup, so drop (...) and [...] groups before searching
        # iTunes. Fall back to the raw name if stripping leaves nothing.
        cleaned = _re.sub(r"\([^()]*\)", " ", raw_name)
        cleaned = _re.sub(r"\[[^\[\]]*\]", " ", cleaned)
        cleaned = _re.sub(r"\s{2,}", " ", cleaned)
        # Collapse separator runs left when a bracket sat between dashes
        # ("Song - (Live) - 2024" -> "Song - 2024", not "Song - - 2024").
        cleaned = _re.sub(r"(?:\s*[-–—·]\s*){2,}", " - ", cleaned)
        cleaned = _re.sub(r"\s{2,}", " ", cleaned).strip(" -_·–—")
        query = cleaned or raw_name.strip()
        if not query:
            messagebox.showinfo(
                "No song name", "This file has no name to search album art with.")
            return
        # If THIS song is the one loaded in the preview player, stop + unload it
        # first: pygame keeps the file handle open while playing OR paused, and
        # Windows won't let mutagen rewrite a file that still has an open handle
        # (the "[Errno 13] Permission denied" the owner hit). No-op otherwise.
        if getattr(self, "_yt_preview_path", None) == path:
            try:
                self._yt_preview_stop()
            except Exception:
                pass
        self._yt_log(f"\n\U0001F50D  Searching album art for “{query}”…")
        import threading
        threading.Thread(
            target=self._yt_lib_search_art_worker,
            args=(path, fmt_l, query), daemon=True).start()

    def _yt_lib_search_art_worker(self, path, fmt_l, query):
        """Worker thread: iTunes lookup -> crop/resize -> embed -> refresh row.
        All Tk touches go back through root.after per the app's threading rule."""
        def _log(m):
            self.root.after(0, lambda: self._yt_log(m))
        try:
            result = _itunes_fetch_album_art(query, "", getattr(self, "VERSION", ""))
            if not result:
                _log(f"   ⚠  No album art found for “{query}”.")
                self.root.after(0, lambda: messagebox.showinfo(
                    "No album art found",
                    f"iTunes returned no cover art for:\n\n   {query}\n\n"
                    "Tip: right-click → Rename to give it a cleaner "
                    "“Artist - Title” name, then search again — the search "
                    "uses the song's library name."))
                return
            art_bytes, _mime, _url = result

            # Center-crop to square + resize, matching the download embed path.
            from PIL import Image
            import io
            img = Image.open(io.BytesIO(art_bytes))
            iw, ih = img.size
            side = min(iw, ih)
            left, top = (iw - side) // 2, (ih - side) // 2
            img = img.crop((left, top, left + side, top + side))
            img = img.resize((600, 600), Image.LANCZOS)
            if img.mode != "RGB":
                img = img.convert("RGB")
            buf = io.BytesIO()
            img.save(buf, format="JPEG", quality=92)
            jpeg_bytes = buf.getvalue()

            if not self._embed_album_art_bytes(path, fmt_l, jpeg_bytes, _log):
                return  # helper logged the reason

            # The cached row thumbnail (keyed by sha1(path)) is now stale -> drop
            # it so _yt_fetch_art_cache regenerates from the freshly embedded art.
            try:
                import hashlib
                key = hashlib.sha1(path.encode("utf-8")).hexdigest()
                old_png = os.path.join(YT_ART_CACHE_DIR, key + ".png")
                if os.path.isfile(old_png):
                    os.remove(old_png)
            except Exception:
                pass
            new_png = self._yt_fetch_art_cache(path, None)

            # Persist the (re)generated art_cache path onto the registry entry.
            if new_png:
                try:
                    norm = os.path.normcase(os.path.abspath(path))
                except Exception:
                    norm = path
                with YT_LIBRARY_LOCK:
                    entries = self._yt_library_load()
                    for e in entries:
                        try:
                            if os.path.normcase(
                                    os.path.abspath(e.get("path", ""))) == norm:
                                e["art_cache"] = new_png
                        except Exception:
                            pass
                    self._yt_library_save(entries)

            # Evict the in-memory PhotoImage so the refresh reloads from disk,
            # then refresh (FIFO: pop runs before refresh).
            self.root.after(0, lambda: self._yt_lib_art_refs.pop(path, None))
            _log(f"   ✓  Album art applied to “{query}”.")
            self.root.after(0, self._yt_library_refresh)
        except Exception as exc:
            _log(f"   ⚠  Album art search failed: {exc}")

    def _embed_album_art_bytes(self, audio_path, fmt_l, jpeg_bytes, log):
        """Embed JPEG cover-art bytes into an audio file via mutagen. Returns
        True on success. Supports FLAC, MP3, OGG Vorbis, and M4A/MP4 (the FLAC
        and MP3 writes mirror the download-time embed in _yt_embed_thumbnail)."""
        try:
            if fmt_l == "flac":
                from mutagen.flac import FLAC, Picture
                audio = FLAC(audio_path)
                pic = Picture()
                pic.type, pic.mime, pic.desc = 3, "image/jpeg", "Cover"
                pic.width = pic.height = 600
                pic.depth = 24
                pic.data = jpeg_bytes
                audio.clear_pictures()
                audio.add_picture(pic)
                audio.save()
            elif fmt_l == "mp3":
                from mutagen.id3 import ID3, APIC, ID3NoHeaderError
                try:
                    audio = ID3(audio_path)
                except ID3NoHeaderError:
                    audio = ID3()
                audio.delall("APIC")
                audio.add(APIC(encoding=3, mime="image/jpeg", type=3,
                               desc="Cover", data=jpeg_bytes))
                audio.save(audio_path)
            elif fmt_l == "ogg":
                from mutagen.oggvorbis import OggVorbis
                from mutagen.flac import Picture
                import base64
                pic = Picture()
                pic.type, pic.mime, pic.desc = 3, "image/jpeg", "Cover"
                pic.width = pic.height = 600
                pic.depth = 24
                pic.data = jpeg_bytes
                audio = OggVorbis(audio_path)
                audio["metadata_block_picture"] = [
                    base64.b64encode(pic.write()).decode("ascii")]
                audio.save()
            elif fmt_l in ("m4a", "mp4"):
                from mutagen.mp4 import MP4, MP4Cover
                audio = MP4(audio_path)
                audio["covr"] = [MP4Cover(jpeg_bytes,
                                          imageformat=MP4Cover.FORMAT_JPEG)]
                audio.save()
            else:
                log(f"   ⚠  Album art skipped: '.{fmt_l}' not supported.")
                return False
            return True
        except ImportError:
            log("   ⚠  Album art skipped: mutagen is not installed.")
            return False
        except PermissionError:
            log("   ⚠  Album art embedding failed: the file is locked — it may "
                "be open in another program or still syncing (OneDrive). Close "
                "it / let the sync finish, then try again.")
            return False
        except Exception as exc:
            log(f"   ⚠  Album art embedding failed: {exc}")
            return False

    def _stem_confirm_resplit(self, input_path, output_base):
        """Modal re-split warning with a persistent 'don't show again' option.
        Returns True to proceed with the split, False to abort."""
        try:
            song = os.path.splitext(os.path.basename(input_path))[0]
        except Exception:
            song = os.path.basename(input_path)
        folder = output_base
        for cand in (os.path.join(output_base, "DRUMS ONLY"),
                     os.path.join(output_base, "DRUMS")):
            if os.path.isfile(os.path.join(cand, f"{song}_drums.ogg")):
                folder = cand
                break
        else:
            iso_var = getattr(self, "stem_iso_output_var", None)
            iso_base = iso_var.get().strip() if iso_var else ""
            if iso_base and os.path.isfile(
                    os.path.join(iso_base, "DRUMS", f"{song}_drums.ogg")):
                folder = os.path.join(iso_base, "DRUMS")

        dlg = tk.Toplevel(self.root)
        dlg.title("Already split")
        dlg.configure(bg="#222222")
        dlg.resizable(False, False)
        dlg.transient(self.root)
        dlg.grab_set()
        pw, ph = 480, 240
        try:
            px = self.root.winfo_x() + (self.root.winfo_width() - pw) // 2
            py = self.root.winfo_y() + (self.root.winfo_height() - ph) // 2
            dlg.geometry(f"{pw}x{ph}+{px}+{py}")
        except Exception:
            dlg.geometry(f"{pw}x{ph}")

        frame = ttk.Frame(dlg, padding=18)
        frame.pack(fill=tk.BOTH, expand=True)
        ttk.Label(frame, text="⚠  Already split",
                  font=("Segoe UI", 12, "bold"),
                  foreground="#e09a3a").pack(anchor="w", pady=(0, 8))
        ttk.Label(frame, text=f"{song} already has split stems in:",
                  style="TLabel", wraplength=440, justify=tk.LEFT).pack(anchor="w")
        ttk.Label(frame, text=folder, style="Sub.TLabel", foreground="#9a9ab0",
                  wraplength=440, justify=tk.LEFT).pack(anchor="w", pady=(2, 8))
        ttk.Label(frame, text="Splitting again will overwrite them. Continue?",
                  style="TLabel", wraplength=440, justify=tk.LEFT).pack(anchor="w")

        dismiss_var = tk.BooleanVar(value=False)
        ttk.Checkbutton(frame, text="Don't show this warning again",
                        variable=dismiss_var).pack(anchor="w", pady=(10, 0))

        result = {"proceed": False}
        btn_row = ttk.Frame(frame)
        btn_row.pack(anchor="e", pady=(14, 0))

        def _do_cancel():
            result["proceed"] = False
            dlg.destroy()

        def _do_continue():
            result["proceed"] = True
            if dismiss_var.get():
                save_config({"stem_resplit_warn_dismissed": True})
            dlg.destroy()

        ttk.Button(btn_row, text="Cancel", command=_do_cancel).pack(
            side=tk.LEFT, padx=(0, 8))
        ttk.Button(btn_row, text="Continue", style="Convert.TButton",
                   command=_do_continue).pack(side=tk.LEFT)
        dlg.protocol("WM_DELETE_WINDOW", _do_cancel)
        dlg.wait_window()
        return result["proceed"]

    def _yt_fetch_thumbnail(self):
        """Fetch and display a YouTube thumbnail + title for the pasted URL.

        Runs the network call on a daemon thread so the UI never blocks.
        Falls back gracefully if Pillow is not installed or the URL is invalid.
        """
        import re, threading, urllib.request, urllib.parse, json, io

        url = self.yt_url_var.get().strip()

        # ── Empty URL → reset panel ───────────────────────────────────────────
        if not url:
            try:
                self.yt_thumb_lbl.configure(image="", text="")
                self.yt_thumb_status_var.set("Paste a URL above to preview")
                self.yt_thumb_title_var.set("")
                self._yt_thumb_image = None
            except Exception:
                pass
            return

        # ── Extract video ID ──────────────────────────────────────────────────
        m = re.search(r'(?:v=|youtu\.be/|embed/|shorts/)([A-Za-z0-9_-]{11})', url)
        if not m:
            try:
                self.yt_thumb_status_var.set(
                    "⚠  Couldn't recognize a YouTube video ID in this URL")
                self.yt_thumb_title_var.set("")
                self.yt_thumb_lbl.configure(image="", text="")
            except Exception:
                pass
            return

        video_id = m.group(1)
        try:
            self.yt_thumb_status_var.set("🔍  Fetching preview…")
            self.yt_thumb_title_var.set("")
            self.yt_thumb_lbl.configure(image="", text="")
        except Exception:
            pass

        def _fetch():
            title      = None
            thumb_data = None

            # Step 1: oembed gives us title + a proper thumbnail URL in one call.
            try:
                oembed = ("https://www.youtube.com/oembed?"
                          f"url={urllib.parse.quote(url, safe='')}&format=json")
                with urllib.request.urlopen(oembed, timeout=8) as resp:
                    info = json.loads(resp.read().decode("utf-8"))
                title     = info.get("title", "")
                raw_thumb = info.get("thumbnail_url", "")
            except Exception:
                raw_thumb = ""

            # Step 2: Fetch image bytes from the oembed thumbnail URL.
            if raw_thumb:
                try:
                    with urllib.request.urlopen(raw_thumb, timeout=8) as resp:
                        thumb_data = resp.read()
                except Exception:
                    thumb_data = None

            # Step 3: If oembed failed, try direct img.youtube.com URLs.
            if not thumb_data:
                for quality in ("hqdefault", "mqdefault", "default"):
                    direct = (f"https://img.youtube.com/vi/"
                              f"{video_id}/{quality}.jpg")
                    try:
                        with urllib.request.urlopen(direct, timeout=6) as resp:
                            thumb_data = resp.read()
                        break
                    except Exception:
                        continue

            if not thumb_data:
                def _err():
                    try:
                        self.yt_thumb_status_var.set(
                            "⚠  Could not load thumbnail — check the URL or your connection")
                        self.yt_thumb_title_var.set("")
                    except Exception:
                        pass
                self.root.after(0, _err)
                return

            # Step 4: Decode, crop letterbox bars, resize, display.
            try:
                from PIL import Image, ImageTk
                img = Image.open(io.BytesIO(thumb_data))
                iw, ih = img.size
                # hqdefault is 480×360 (4:3) — crop top/bottom to 16:9
                target_h = int(iw * 9 / 16)
                if target_h < ih:
                    pad = (ih - target_h) // 2
                    img = img.crop((0, pad, iw, pad + target_h))
                img   = img.resize((320, 180), Image.LANCZOS)   # v4.4.62-1: match the larger preview box
                photo = ImageTk.PhotoImage(img)

                display_title = title or f"Video ID: {video_id}"

                def _ok():
                    try:
                        self._yt_thumb_image = photo   # prevent GC
                        self.yt_thumb_lbl.configure(image=photo, text="")
                        self.yt_thumb_status_var.set("✓  Connected")
                        self.yt_thumb_title_var.set(display_title)
                    except Exception:
                        pass

                self.root.after(0, _ok)

            except ImportError:
                # Pillow not installed — show title only
                display_title = title or f"Video ID: {video_id}"
                def _nopil():
                    try:
                        self.yt_thumb_lbl.configure(image="", text="🖼")
                        self.yt_thumb_status_var.set(
                            "✓  Connected  —  install Pillow to see thumbnail image")
                        self.yt_thumb_title_var.set(display_title)
                    except Exception:
                        pass
                self.root.after(0, _nopil)

            except Exception as exc:
                msg = str(exc)[:80]
                def _img_err():
                    try:
                        self.yt_thumb_status_var.set(f"⚠  Image error: {msg}")
                    except Exception:
                        pass
                self.root.after(0, _img_err)

        threading.Thread(target=_fetch, daemon=True).start()

    @staticmethod
    def _youtube_sanitize_filename(raw_name):
        """Clean a user-supplied YouTube filename so Windows can save it.

        Returns a sanitized basename (no extension) or ``None`` when the
        input is empty / becomes empty after sanitization, in which case the
        caller should fall back to the YouTube video title (default behavior).

        Rules applied, in order:
          1. Replace Windows-illegal chars  < > : " / \\ | ? *  with '_'
          2. Strip ASCII control chars (0x00-0x1F and 0x7F)
          3. Trim trailing dots and spaces (Windows refuses these)
          4. Prepend '_' to Windows reserved names (CON, PRN, AUX, NUL,
             COM0-COM9, LPT0-LPT9), case-insensitive
          5. Truncate to 200 chars (leaves room for extension + path)
          6. Fall back to None if input is empty/whitespace or wipes out
        """
        if raw_name is None:
            return None
        name = str(raw_name).strip()
        if not name:
            return None

        # Rule 1: replace Windows-illegal characters
        illegal = '<>:"/\\|?*'
        for ch in illegal:
            name = name.replace(ch, "_")

        # Rule 2: strip control characters (0x00-0x1F and 0x7F)
        name = "".join(c for c in name if (ord(c) >= 32 and ord(c) != 0x7F))

        # Rule 3: trim trailing dots and spaces
        name = name.rstrip(". ").strip()
        if not name:
            return None

        # Rule 4: Windows reserved name protection (case-insensitive)
        reserved = {"CON", "PRN", "AUX", "NUL"}
        for n in range(10):
            reserved.add(f"COM{n}")
            reserved.add(f"LPT{n}")
        if name.upper() in reserved:
            name = "_" + name

        # Rule 5: cap length conservatively
        if len(name) > 200:
            name = name[:200].rstrip(". ").strip()
            if not name:
                return None

        return name

    def _yt_check_runtime_status(self):
        """Refresh the JS-runtime status label by re-running detection."""
        if not hasattr(self, "_yt_runtime_status_lbl"):
            return
        custom = getattr(self, "yt_node_path_var", None)
        runtimes = _yt_resolve_js_runtimes(custom.get() if custom else "")
        if runtimes:
            first_name, first_path = runtimes[0]
            if len(runtimes) == 1:
                text = f"✓  {first_name.title()} detected: {first_path}"
            else:
                names = " + ".join(n.title() for n, _ in runtimes)
                text = f"✓  {names} detected (using {first_name.title()})"
            self._yt_runtime_status_lbl.configure(text=text, foreground="#00d4d4")
            # v4.4.16 — gray out the Get Deno button when a runtime is on disk
            # so users don't redundantly re-trigger the download (which is what
            # caused the v4.4.5-pattern bug — owner downloaded Deno 3 times in
            # succession before HTTP-side dedup blocked the 3rd).
            btn = getattr(self, "_yt_deno_btn", None)
            if btn is not None:
                btn.configure(state="disabled")
        else:
            self._yt_runtime_status_lbl.configure(
                text="⚠  No JS runtime detected — YouTube downloads may fail. "
                     "Click Get Deno to auto-install.",
                foreground="#ffb347")
            # v4.4.16 — re-enable the Get Deno button when no runtime detected.
            btn = getattr(self, "_yt_deno_btn", None)
            if btn is not None:
                btn.configure(state="normal")

    def _yt_download_deno(self):
        """Kick off the Deno download in a background thread."""
        threading.Thread(target=self._yt_deno_download_worker,
                         daemon=True).start()

    def _yt_deno_download_worker(self):
        """Download the latest Deno Windows binary into Requirements\\deno.exe.

        Deno is a single-file native binary (~30 MB compressed, ~80 MB
        extracted) distributed as a zip on GitHub releases. yt-dlp auto-enables
        Deno by default, so dropping deno.exe alongside ParaKit's other
        bundled tools makes signature solving work with zero user setup.

        Mirrors the canonical ParaKit download pattern from
        `_a2m_onnx_download_worker` (status updates, size sanity check,
        graceful refresh on success).
        """
        import urllib.request
        import zipfile
        import io

        DENO_URL = ("https://github.com/denoland/deno/releases/latest/download/"
                    "deno-x86_64-pc-windows-msvc.zip")

        dest = _external_path("deno.exe", for_writing=True)
        os.makedirs(os.path.dirname(dest), exist_ok=True)

        def _upd(msg, color="#b388ff"):
            self.root.after(
                0,
                lambda m=msg, c=color: self._yt_runtime_status_lbl.configure(
                    text=m, foreground=c))

        try:
            _upd("Connecting to GitHub...")
            opener = urllib.request.build_opener(
                urllib.request.HTTPRedirectHandler())
            opener.addheaders = [
                ("User-Agent",
                 "Mozilla/5.0 (Windows NT 10.0; Win64; x64) "
                 "AppleWebKit/537.36"),
                ("Accept", "*/*"),
            ]
            buf = io.BytesIO()
            with opener.open(DENO_URL, timeout=120) as resp:
                total      = int(resp.headers.get("Content-Length", 0))
                downloaded = 0
                while True:
                    chunk = resp.read(65536)
                    if not chunk:
                        break
                    buf.write(chunk)
                    downloaded += len(chunk)
                    if total:
                        pct = downloaded / total * 100
                        _upd(f"Downloading Deno... {pct:.0f}%  "
                             f"({downloaded // 1024 // 1024}/"
                             f"{total // 1024 // 1024} MB)")
                    else:
                        _upd(f"Downloading Deno... "
                             f"{downloaded // 1024 // 1024} MB")

            _upd("Extracting deno.exe...")
            buf.seek(0)
            with zipfile.ZipFile(buf) as z:
                deno_member = next(
                    (n for n in z.namelist()
                     if n.lower().endswith("deno.exe")),
                    None)
                if not deno_member:
                    _upd("✗  deno.exe not found in archive — try Node.js instead.",
                         "#ff6b81")
                    return
                with z.open(deno_member) as src, open(dest, "wb") as f:
                    shutil.copyfileobj(src, f)

            if os.path.getsize(dest) < 1024 * 1024:
                os.remove(dest)
                _upd("✗  Extracted file looks invalid — try again or install Node manually.",
                     "#ff6b81")
                return

            self.root.after(0, self._yt_check_runtime_status)

        except Exception as e:
            try:
                if os.path.isfile(dest) and os.path.getsize(dest) < 1024 * 1024:
                    os.remove(dest)
            except Exception:
                pass
            _upd(f"✗  Download failed: {e}", "#ff6b81")

    def _yt_log(self, msg):
        """Append a line to the YouTube tab log.
        While a download is running, prefixes non-blank lines with [mm:ss]
        elapsed since _yt_start_time was set."""
        out = msg
        start = getattr(self, '_yt_start_time', None)
        if start is not None:
            import time as _t
            leading = ""
            body = msg
            while body.startswith("\n"):
                leading += "\n"
                body = body[1:]
            if body.strip():
                elapsed = _t.time() - start
                m = int(elapsed // 60)
                s = int(elapsed % 60)
                out = f"{leading}[{m:02d}:{s:02d}]  {body}"
        self.yt_log.configure(state="normal")
        self._pretty_log_insert(self.yt_log, out + "\n")
        self.yt_log.see(tk.END)
        self.yt_log.configure(state="disabled")

    def _yt_start_download(self):
        """Start YouTube download in a background thread."""
        import threading
        url = self.yt_url_var.get().strip()
        if not url:
            messagebox.showwarning("No URL", "Paste a YouTube URL first.")
            return
        out_dir = self.yt_out_var.get().strip()
        if not os.path.isdir(out_dir):
            messagebox.showwarning("Invalid folder", "Choose a valid output folder.")
            return
        cookie_mode = getattr(self, "yt_cookie_mode_var", tk.StringVar(value="none")).get()
        cookie_browser = getattr(self, "yt_cookie_browser_var", tk.StringVar(value="")).get()
        cookie_profile = getattr(self, "yt_cookie_profile_var", tk.StringVar(value="")).get()
        cookie_file = getattr(self, "yt_cookie_file_var", tk.StringVar(value="")).get().strip()
        cookie_args = _yt_cookie_args(
            cookie_mode, cookie_browser, cookie_profile, cookie_file,
            platform_name=("Windows" if sys.platform == "win32" else sys.platform),
        )
        if cookie_mode == "file" and not cookie_args:
            messagebox.showwarning("No cookies.txt file",
                                   "Choose a cookies.txt file or switch the cookie mode back to No cookies.")
            return
        if cookie_mode == "file" and not os.path.isfile(cookie_file):
            messagebox.showwarning("cookies.txt not found",
                                   "The selected cookies.txt file could not be found.")
            return
        if cookie_mode == "browser" and not cookie_args:
            messagebox.showwarning("No browser selected",
                                   "Choose a browser session or switch the cookie mode back to No cookies.")
            return
        if cookie_mode == "browser":
            if cookie_browser == "OperaGX" and cookie_profile.strip() and not _yt_looks_like_path(cookie_profile):
                messagebox.showwarning(
                    "OperaGX profile hint",
                    "OperaGX works best with a full profile path in the Profile / path box.\n\n"
                    "For Chrome, Edge, Firefox, and Brave, profile names like 'Profile 2' are fine."
                )
                return
        if cookie_mode == "browser":
            if cookie_browser == "OperaGX":
                cookie_desc = "Browser cookies: OperaGX"
            else:
                cookie_desc = f"Browser cookies: {cookie_browser}"
            if cookie_profile.strip():
                cookie_desc += " (profile hint set)"
        elif cookie_mode == "file":
            cookie_desc = "Cookie source: cookies.txt file"
        else:
            cookie_desc = "Cookie source: none"
        self.yt_cancel_var.set(False)
        self.yt_dl_btn.configure(state="disabled")
        self.yt_log.configure(state="normal")
        self.yt_log.delete("1.0", tk.END)
        self.yt_log.configure(state="disabled")

        # Kick off elapsed timer + progress bar — set before the worker runs
        # so the very first log line carries an accurate [mm:ss] prefix.
        import time as _t
        self._yt_start_time = _t.time()
        self.yt_progress_bar.start(12)
        self.yt_timer_lbl.configure(text="⏱  00:00")
        self._timer_start(self.yt_timer_lbl)

        embed_art = bool(getattr(self, "yt_embed_art_var",
                                  tk.BooleanVar(value=False)).get())

        # v4.4.2: optional custom filename (overrides the YouTube video title
        # for the saved file). Only applied when the toggle is on AND the
        # sanitized name is non-empty; otherwise we hand None to the worker
        # and the default %(title)s template is used.
        custom_basename = None
        if getattr(self, "yt_custom_name_enabled_var",
                   tk.BooleanVar(value=False)).get():
            raw_name = getattr(self, "yt_custom_name_var",
                               tk.StringVar(value="")).get()
            custom_basename = self._youtube_sanitize_filename(raw_name)
            if custom_basename is None and raw_name and raw_name.strip():
                # User typed something but it cleaned to empty — log this
                # so the file shows up under the video title and they know
                # why their custom name was ignored.
                self._yt_log(
                    "ℹ  Custom filename was empty after cleanup; saving as "
                    "the YouTube video title instead.")

        t = threading.Thread(target=self._yt_download_worker,
                             args=(url, out_dir, self.yt_fmt_var.get(),
                                   cookie_args, cookie_desc, embed_art,
                                   custom_basename),
                             daemon=True)
        t.start()

    def _yt_download_worker(self, url, out_dir, fmt, cookie_args=None,
                             cookie_desc="Cookie source: none", embed_art=False,
                             custom_basename=None):
        """Background worker: optionally update yt-dlp, then download."""
        import subprocess, sys, shutil

        def log(msg):
            self.root.after(0, lambda m=msg: self._yt_log(m))
        def prog(msg):
            self.root.after(0, lambda m=msg: self.yt_progress_var.set(m))
        def done():
            self.root.after(0, lambda: self.yt_dl_btn.configure(state="normal"))
            self.root.after(0, self.yt_progress_bar.stop)
            self.root.after(0, lambda: self._timer_stop(self.yt_timer_lbl))
            self._yt_start_time = None

        # Resolve yt-dlp path — Requirements\ wins when present, else legacy
        # next-to-EXE; finally falls back to whatever's on PATH.
        ytdlp_name = "yt-dlp.exe" if sys.platform == "win32" else "yt-dlp"
        ytdlp_exe = _external_path(ytdlp_name)
        if not os.path.isfile(ytdlp_exe):
            ytdlp_exe = shutil.which("yt-dlp") or "yt-dlp"

        # Auto-update yt-dlp
        if self.yt_autoupdate_var.get():
            log("Checking for yt-dlp updates...")
            prog("Updating yt-dlp...")
            try:
                result = subprocess.run(
                    [ytdlp_exe, "--update-to", "nightly"],
                    capture_output=True, text=True, timeout=30)
                for line in (result.stdout + result.stderr).splitlines():
                    if line.strip():
                        log(f"  {line}")
                log("yt-dlp up to date.")
            except Exception as e:
                log(f"  yt-dlp update skipped: {e}")

        if self.yt_cancel_var.get():
            log("Cancelled.")
            done()
            return

        log(f"\nDownloading: {url}")
        log(f"Format: {fmt.upper()}  →  {out_dir}\n")
        if cookie_desc:
            log(f"{cookie_desc}")
        prog("Downloading...")

        # Build ffmpeg path — Requirements\ wins when present, else legacy
        # next-to-EXE; finally falls back to whatever's on PATH.
        ffmpeg = shutil.which("ffmpeg") or "ffmpeg"
        if getattr(sys, 'frozen', False):
            ff_local = _external_path("ffmpeg.exe")
            if os.path.isfile(ff_local):
                ffmpeg = ff_local

        # v4.4.2: honor the user-provided custom basename when present; fall
        # back to the YouTube video title (default v4.4.x behavior) otherwise.
        # custom_basename is already sanitized by _youtube_sanitize_filename
        # before reaching the worker, so no further validation is needed here.
        if custom_basename:
            out_template = os.path.join(out_dir, custom_basename + ".%(ext)s")
            log(f"Output filename: {custom_basename}.{fmt}")
        else:
            out_template = os.path.join(out_dir, "%(title)s.%(ext)s")
        cmd = [
            ytdlp_exe,
            "--ffmpeg-location", os.path.dirname(ffmpeg),
            "-x", "--audio-format", fmt,
            "--audio-quality", "0",
            "-o", out_template,
            "--no-playlist",
        ]

        # JS runtime for YouTube signature solving — yt-dlp v2025+ only
        # auto-enables Deno, so we have to name Node explicitly when present.
        _node_custom = getattr(self, "yt_node_path_var", None)
        js_runtimes = _yt_resolve_js_runtimes(_node_custom.get() if _node_custom else "")
        if js_runtimes:
            runtime_arg = ",".join(f"{name}:{path}" for name, path in js_runtimes)
            cmd.extend(["--js-runtimes", runtime_arg])
            summary = ", ".join(f"{name} ({path})" for name, path in js_runtimes)
            log(f"JS runtime(s): {summary}")
        else:
            log("⚠  No JS runtime detected. YouTube signature solving may fail.")
            log("   Install Node.js (https://nodejs.org/) or Deno (https://deno.com/),")
            log("   then close and relaunch ParaKit so the new install is picked up.")

        if cookie_args:
            cmd.extend(cookie_args)
        cmd.append(url)

        try:
            seen_lines = []
            final_audio_path = None  # captured from [ExtractAudio] Destination: line
            proc = subprocess.Popen(cmd, stdout=subprocess.PIPE,
                                    stderr=subprocess.STDOUT, text=True,
                                    bufsize=1)
            for line in proc.stdout:
                if self.yt_cancel_var.get():
                    proc.terminate()
                    log("\nCancelled by user.")
                    prog("Cancelled.")
                    done()
                    return
                line = line.rstrip()
                if line:
                    seen_lines.append(line)
                    log(line)
                    if "[download]" in line or "[ExtractAudio]" in line:
                        prog(line[:80])
                    # Capture final converted audio path for album-art embedding
                    if line.startswith("[ExtractAudio] Destination:"):
                        final_audio_path = line.split("Destination:", 1)[1].strip()
            proc.wait()
            if proc.returncode == 0:
                log(f"\n✓  Done! File saved to: {out_dir}")
                prog("✓  Complete!")
                if embed_art:
                    self._yt_embed_thumbnail(url, final_audio_path, fmt, log)
                # v4.4.61-1 — library completion hook. Fires on EVERY successful
                # download (independent of embed_art) and ONLY in this success
                # branch (an earlier auditor mis-anchored this in the failure
                # branch). Marshalled to the Tk thread; capture out_dir (a worker
                # local, not in scope on the Tk handler) for the fallback glob,
                # plus the parsed video id for the row art/metadata.
                import re as _re
                _m = _re.search(
                    r'(?:v=|youtu\.be/|embed/|shorts/)([A-Za-z0-9_-]{11})',
                    url or "")
                _vid = _m.group(1) if _m else None
                self.root.after(0, lambda p=final_audio_path, f=fmt, d=out_dir,
                                v=_vid: self._yt_on_download_complete(p, f, d, v))
            else:
                for extra_line in _yt_extra_error_guidance("\n".join(seen_lines)):
                    log(extra_line)
                log(f"\n✗  yt-dlp exited with code {proc.returncode}")
                prog("✗  Error — see log below")
        except FileNotFoundError:
            log("✗  yt-dlp not found. Download yt-dlp.exe and place it next to "
                "ParaKit.exe or in Requirements\\.")
            log("   https://github.com/yt-dlp/yt-dlp/releases/latest")
            prog("✗  yt-dlp not found")
        except Exception as e:
            log(f"✗  Error: {e}")
            prog("✗  Error")
        done()

    def _yt_embed_thumbnail(self, url, audio_path, fmt, log):
        """Fetch the YouTube thumbnail, center-crop to a square, and embed it
        as cover art into the freshly-downloaded audio file.

        Runs synchronously inside the download worker thread (after the yt-dlp
        process exits cleanly) — the UI remains responsive because it is still
        on the worker thread, not the Tk main thread."""
        import re, urllib.request, io

        if not audio_path or not os.path.isfile(audio_path):
            log("⚠  Album art skipped: could not locate the converted audio file.")
            return

        fmt_l = (fmt or "").lower()
        if fmt_l == "wav":
            log("ℹ  Album art skipped: WAV does not have a standard cover-art tag.")
            return

        # Extract video ID from the original URL
        m = re.search(r'(?:v=|youtu\.be/|embed/|shorts/)([A-Za-z0-9_-]{11})', url)
        if not m:
            log("⚠  Album art skipped: could not parse video ID from URL.")
            return
        video_id = m.group(1)

        log("\n🖼  Fetching thumbnail for album art...")

        # Try thumbnail qualities in descending order. maxresdefault sometimes
        # returns a tiny placeholder (~1KB) for older videos — guard with size.
        thumb_data = None
        for quality in ("maxresdefault", "hqdefault", "mqdefault", "default"):
            t_url = f"https://img.youtube.com/vi/{video_id}/{quality}.jpg"
            try:
                with urllib.request.urlopen(t_url, timeout=10) as resp:
                    data = resp.read()
                if len(data) > 2000:  # skip 1×1 placeholder
                    thumb_data = data
                    log(f"   ✓  Got {quality} ({len(data) // 1024} KB)")
                    break
            except Exception as exc:
                log(f"   {quality}: {exc}")

        if not thumb_data:
            log("⚠  Album art skipped: could not fetch a usable thumbnail.")
            return

        # Center-crop to square + resize to a reasonable album-art size
        try:
            from PIL import Image
            img = Image.open(io.BytesIO(thumb_data))
            iw, ih = img.size
            side = min(iw, ih)
            left = (iw - side) // 2
            top  = (ih - side) // 2
            img  = img.crop((left, top, left + side, top + side))
            img  = img.resize((600, 600), Image.LANCZOS)
            if img.mode != "RGB":
                img = img.convert("RGB")
            buf = io.BytesIO()
            img.save(buf, format="JPEG", quality=92)
            jpeg_bytes = buf.getvalue()
        except ImportError:
            log("⚠  Album art skipped: Pillow (PIL) is not installed.")
            return
        except Exception as exc:
            log(f"⚠  Album art skipped: image processing failed: {exc}")
            return

        # Embed into the audio file via mutagen
        try:
            if fmt_l == "flac":
                from mutagen.flac import FLAC, Picture
                audio = FLAC(audio_path)
                pic = Picture()
                pic.type   = 3            # 3 = front cover
                pic.mime   = "image/jpeg"
                pic.desc   = "Cover"
                pic.width  = 600
                pic.height = 600
                pic.depth  = 24
                pic.data   = jpeg_bytes
                audio.clear_pictures()
                audio.add_picture(pic)
                audio.save()
                log(f"   ✓  Embedded album art into: {os.path.basename(audio_path)}")
            elif fmt_l == "mp3":
                from mutagen.id3 import ID3, APIC
                from mutagen.id3 import ID3NoHeaderError
                try:
                    audio = ID3(audio_path)
                except ID3NoHeaderError:
                    audio = ID3()
                audio.delall("APIC")
                audio.add(APIC(encoding=3, mime="image/jpeg", type=3,
                                desc="Cover", data=jpeg_bytes))
                audio.save(audio_path)
                log(f"   ✓  Embedded album art into: {os.path.basename(audio_path)}")
            else:
                log(f"ℹ  Album art skipped: format '{fmt_l}' not supported for embedding.")
        except ImportError:
            log("⚠  Album art skipped: mutagen is not installed.")
        except Exception as exc:
            log(f"⚠  Album art embedding failed: {exc}")

    def _build_asset_manager_tab(self, parent):
        """Asset Manager — album art cropper, preview trimmer, metadata fetcher."""
        main = ttk.Frame(parent, padding=16)
        main.pack(fill=tk.BOTH, expand=True)

        ttk.Label(main, text="🎨  Asset Manager",
                  font=("Segoe UI", 13, "bold"), foreground="#b388ff").pack(anchor="w")
        ttk.Label(main,
                  text="Prepare album art, preview clips, and song metadata for Paradiddle charts.",
                  style="Sub.TLabel").pack(anchor="w", pady=(2, 12))

        # ── Metadata Fetcher ──────────────────────────────────────────────────
        meta_frame = ttk.LabelFrame(main, text=" 🔍  Auto-Fetch Metadata ", padding=10)
        meta_frame.pack(fill=tk.X, pady=(0, 10))

        ttk.Label(meta_frame,
                  text="Search MusicBrainz for song metadata and iTunes for album art. "
                       "Results auto-fill into the Song Creator fields.",
                  style="Sub.TLabel", wraplength=800).pack(anchor="w", pady=(0, 2))
        ttk.Label(meta_frame,
                  text="ℹ  Searches can take 10–20 seconds depending on network — "
                       "the spinner below means it's still working, not frozen.",
                  style="Sub.TLabel", foreground="#7a86c8",
                  wraplength=800).pack(anchor="w", pady=(0, 6))

        search_row = ttk.Frame(meta_frame)
        search_row.pack(fill=tk.X, pady=(0, 4))
        ttk.Label(search_row, text="Search:", width=8).pack(side=tk.LEFT)
        self.am_search_var = tk.StringVar()
        ttk.Entry(search_row, textvariable=self.am_search_var, width=50).pack(side=tk.LEFT, padx=(0, 8))
        ttk.Button(search_row, text="🔍  Fetch Metadata",
                   command=self._am_fetch_metadata).pack(side=tk.LEFT)

        ttk.Label(meta_frame, text='e.g. "Duality Slipknot" or "Enter Sandman Metallica"',
                  style="Sub.TLabel", foreground="#555").pack(anchor="w", pady=(0, 4))

        # Spinner — shown only while a search is running
        self.am_search_progress = _G85AltSnareProgressBar(meta_frame, mode="indeterminate", width=300, height=28)

        # Results preview
        self.am_meta_result_var = tk.StringVar(value="")
        result_row = ttk.Frame(meta_frame)
        result_row.pack(fill=tk.X)
        ttk.Label(result_row, textvariable=self.am_meta_result_var,
                  style="Sub.TLabel", foreground="#00d4d4",
                  wraplength=800, justify=tk.LEFT).pack(anchor="w")

        # Art preview canvas
        # v4.4.62 — enlarged the preview to a 240px square (was 120) per owner,
        # for an easier-to-see thumbnail. This is DISPLAY-ONLY and keeps the 1:1
        # aspect; the applied/saved cover art is unchanged (still downscaled to
        # 120x120 in _am_show_art_preview). All placeholder + art coords derive
        # from self._am_art_px so the size lives in one place.
        self._am_art_px = 240
        _ap = self._am_art_px
        _inset = 12
        self.am_art_canvas = tk.Canvas(meta_frame, width=_ap, height=_ap,
                                        bg="#0d0d1a", highlightthickness=1,
                                        highlightbackground="#3a3a5c")
        self.am_art_canvas.pack(anchor="w", pady=(4, 0))
        # Placeholder — cleared and replaced when art loads
        # v4.4.57.93-10 Patch 15: cyan placeholder for visibility (was muted
        # purple #2e2e5e / #3a3a5a — too dim to read on dark background)
        self.am_art_canvas.create_rectangle(_inset, _inset, _ap - _inset, _ap - _inset,
                                             outline="#00d4d4", width=1,
                                             dash=(4, 4), tags="placeholder")
        self.am_art_canvas.create_text(_ap // 2, int(_ap * 0.42), text="♪", fill="#00e0e0",
                                        font=("Segoe UI", 56), tags="placeholder")
        self.am_art_canvas.create_text(_ap // 2, int(_ap * 0.71), text="No art loaded", fill="#00e0e0",
                                        font=("Segoe UI", 14), tags="placeholder")
        self._am_art_image = None  # keep reference

        apply_row = ttk.Frame(meta_frame)
        apply_row.pack(fill=tk.X, pady=(6, 0))
        ttk.Button(apply_row, text="✓  Apply Metadata to Song Creator",
                   style="Convert.TButton",
                   command=self._am_apply_metadata).pack(side=tk.LEFT, padx=(0, 8))
        ttk.Button(apply_row, text="🖼  Apply art from thumbnail to Song Creator",
                   style="Convert.TButton",
                   command=self._am_apply_art).pack(side=tk.LEFT, padx=(0, 8))
        ttk.Button(apply_row, text="💾  Save Image...",
                   style="Convert.TButton",
                   command=self._am_save_image).pack(side=tk.LEFT, padx=(0, 8))
        ttk.Label(meta_frame,
                  text="Metadata fills Title and Artist. Art sets the Cover Image path. "
                       "Use one or both — each can be applied independently.\n"
                       "Save Image saves the fetched art (.jpg or .png) — pick a folder "
                       "or skip the dialog to use the default ALBUM ART ASSETS folder "
                       "next to the app.",
                  style="Sub.TLabel", foreground="#555",
                  wraplength=700, justify=tk.LEFT).pack(anchor="w", pady=(2, 0))

        # ── Album Art Cropper ─────────────────────────────────────────────────
