        self.am_trim_in_var = tk.StringVar()
        ttk.Entry(trim_in_row, textvariable=self.am_trim_in_var, width=50).pack(side=tk.LEFT, padx=(0, 8))
        ttk.Button(trim_in_row, text="Browse...",
                   command=lambda: self.am_trim_in_var.set(
                       filedialog.askopenfilename(
                           filetypes=[("Audio", "*.ogg *.wav *.flac *.mp3"), ("All", "*.*")])
                       or self.am_trim_in_var.get())).pack(side=tk.LEFT)

        trim_out_row = ttk.Frame(trim_frame)
