        # ══════════════════════════════════════════════════════════════════════
        # LEFT COLUMN — Workflow & Setup
        # ══════════════════════════════════════════════════════════════════════

        # ── Recommended Workflow ──────────────────────────────────────────────
        s = section("🎵  Recommended Workflow", left, expanded=True,
                    summary="The shortest path from audio to playable chart.")
        entry(s,
              "STEP 1 →  Stem Splitter\n"
              "  Split your song into a drums-only track and a backing track.\n"
              "  Why: the detector works best on isolated drum audio.\n"
              "  Use .flac or .wav for best quality (see Audio Format below).\n\n"
              "STEP 2 →  Audio → MIDI  (skip if you have a MIDI already)\n"
              "  Convert the drums-only stem into a MIDI file.\n"
              "  Why: this is the rough draft — it won't be perfect, and that's okay.\n"
              "  Pick the Genre closest to your song.\n\n"
              "STEP 3 →  MIDI Editor  (always do this)\n"
              "  Review and clean up the generated MIDI.\n"
              "  Why: the auto-detector will always have some mistakes. This is where\n"
              "  you fix them — remove false hits, add missing ones, reclassify wrong\n"
              "  instruments.\n\n"
              "STEP 3.5 →  Preview/Practice Track  (optional but recommended)\n"
              "  Watch your chart fall exactly as it will in Paradiddle.\n"
              "  Why: lets you catch timing and feel issues before converting.\n\n"
              "  Want to play along? Use the Practice subtab's 'Launch New Practice "
              "  (BETA)' button to open the new mini-game window with real-time "
              "  scoring, keyboard controls, and optional MIDI drum-kit input.\n\n"
              "STEP 4 →  Song Tester  (recommended)\n"
              "  Verify BPM and offset alignment before converting.\n"
              "  Why: catches sync problems early. Some warnings after manual edits\n"
              "  are false positives — always confirm in-game.\n\n"
              "STEP 5 →  Single Song Creator\n"
              "  Combine MIDI + audio into a .rlrr file.\n\n"
              "STEP 6 →  Copy output folder to Paradiddle:\n"
              "  PC:     Documents\\Paradiddle\\Songs\\\n"
              "  Quest:  Internal Shared Storage\\Paradiddle\\Songs\\")
        note(s, "The Audio → MIDI generator gives you a strong starting point, not a "
                "finished chart. Think of it as a rough draft. The MIDI Editor is where "
                "you turn that draft into your own chart — add your own freestyle sections, "
                "fix what the detector missed, remove what doesn't belong. Do not expect "
                "the auto-detection to be perfect. It isn't meant to be.")

        # ── Audio Format ──────────────────────────────────────────────────────
        s = section("🎧  Audio Format — FLAC / WAV vs MP3", left,
                    summary="Better source audio means better stems and MIDI.")
        warn(s, "Always use .flac or .wav if possible. MP3 is lossy — audio data is "
                "permanently discarded during compression. Even 320kbps MP3 has less "
                "information than the original, reducing stem quality and MIDI accuracy.")
        entry(s,
              ".flac  —  Lossless + compressed. Best choice for most users.\n"
              ".wav   —  Lossless + uncompressed. Larger files, same quality as FLAC.\n"
              ".mp3   —  Accepted but not recommended. Less accurate results.")
        tip(s, "Converting MP3 to FLAC does NOT recover quality — that data is gone "
               "permanently. Use the YouTube → FLAC tab (Tab 8) to download lossless audio directly — "
               "this is the recommended source. Bandcamp is a good alternative if you own the release, "
               "as it often offers FLAC downloads from artists.")
        tip(s, "Audio → MIDI accuracy — FLAC vs WAV: FLAC and WAV are both lossless, "
               "and detection results are usually identical between them. In some cases, WAV "
               "may pick up subtle transients a little more accurately. If you're not happy "
               "with detection results on a FLAC file, try converting it to .wav and running "
               "the conversion again — it's not guaranteed to help, but it's worth a try when "
               "results feel off.")
        note(s, "YouTube Music links (music.youtube.com) are not directly supported by yt-dlp, "
                "but you can still paste them into the YouTube → FLAC tab. They usually reroute "
                "to the matching supported YouTube video automatically. If yt-dlp keeps failing "
                "even after Deno is installed, install Node.js too — that fixes YouTube download "
                "failures for most users.")

        # ── Stem Splitter ─────────────────────────────────────────────────────
        s = section("🥁  Stem Splitter", left,
                    summary="Create drums-only audio before using Auto MIDI.")
        entry(s,
              "Standard Split:\n"
              "  Separates your audio into three folders:\n"
              "    📁 DRUMS ONLY              — isolated drum track (.ogg, for game packaging)\n"
              "    📁 BACKINGS                — everything except drums (.ogg, for game packaging)\n"
              "    📁 LOSSLESS SPLITS (DRUMS) — lossless drums (.flac, fed to Audio → MIDI)\n"
              "  The lossless FLAC drums stem gives the detector cleaner cymbal/transient\n"
              "  data than the .ogg version, which is lossy. The 'Send Lossless Drums to\n"
              "  MIDI Converter' button on the success popup routes the FLAC automatically.\n\n"
              "  Use htdemucs for fastest results. htdemucs_ft is slower but slightly\n"
              "  more accurate. Both are excellent for charting purposes.\n\n"
              "Custom Isolation Split  [🧪 BETA]:\n"
              "  Splits audio into up to 6 individual stems using htdemucs_6s.\n"
              "  These are the actual stems the model separates — NOT individual\n"
              "  drum components. You cannot isolate kick from snare with demucs.\n\n"
              "  Available stems (select any combination):\n"
              "    Drums   — all drums and percussion combined\n"
              "    Bass    — bass guitar\n"
              "    Guitar  — electric/acoustic guitar\n"
              "    Piano   — piano and keyboards\n"
              "    Vocals  — lead and backing vocals\n"
              "    Other   — everything else (synths, strings, etc.)\n\n"
              "  How to use:\n"
              "    1.  Check 'Enable Custom Isolation Split'\n"
              "    2.  Select which stems you want\n"
              "    3.  Optionally enable 'Also include Backings split'\n"
              "    4.  Optionally set an 'Isolation Output' folder\n"
              "    5.  Click Split Stems\n\n"
              "  Output file naming:\n"
              "    Each stem is saved with a _stemname suffix:\n"
              "      songname_drums.ogg   →  in a  DRUMS\\  subfolder\n"
              "      songname_bass.ogg    →  in a  BASS\\  subfolder\n"
              "      songname_guitar.ogg  →  in a  GUITAR\\  subfolder  (etc.)\n\n"
              "  Isolation Output folder:\n"
              "    Optional second output folder for isolation stems only.\n"
              "    Leave blank to save everything to the main Output Folder.\n\n"
              "  Selecting ALL 6 stems automatically reverts to standard split.\n\n"
              "  Important limitations:\n"
              "    ⚠  Results are NOT perfect — this is a BETA feature.\n"
              "    ⚠  Bleed between instruments is expected on complex mixes.\n"
              "    ⚠  Significantly slower than standard split.\n\n"
              "  Best use: load the drums stem into the MIDI Editor for note\n"
              "  verification, or use bass/guitar stems to study arrangement.")
        warn(s, "Custom Isolation Split uses htdemucs_6s which separates drums, bass,\n"
                "guitar, piano, vocals, and other — not individual drum components.\n"
                "Bleed between stems is expected. Use the standard split for Auto MIDI.")
        divider(s)
        entry(s,
              "🥁  DrumSep — Drum Component Separation  [BETA]:\n\n"
              "  Separates a drums-only stem into 4 individual components:\n"
              "    Kick, Snare, Cymbals, Toms\n\n"
              "  Uses a specialized drum separation model (49469ca8) trained specifically\n"
              "  for this task — not a generic demucs model.\n\n"
              "  ⚠  IMPORTANT: Run Standard Split first to get a drums-only stem.\n"
              "  Then run DrumSep on that result. Do NOT run DrumSep on a full mix.\n\n"
              "  First-time setup:\n"
              "    1.  Enable DrumSep in the Stem Splitter\n"
              "    2.  Click '↓ Download Model' (~200MB, one-time download)\n"
              "    3.  Wait for '✓ Model ready' status\n"
              "    Model is stored in drumsep_model\\ next to ParaKit.exe,\n"
              "    or in Requirements\\drumsep_model\\ when Requirements\\ exists.\n"
              "    GitHub is tried first, Google Drive as fallback.\n\n"
              "  How to use:\n"
              "    1.  Run Standard Split on your song to get a drums-only stem\n"
              "    2.  Enable DrumSep\n"
              "    3.  In the main Input field, browse to the drums-only stem\n"
              "    4.  Optionally set a different Output Folder for the drum stems\n"
              "    5.  Click Split Stems\n\n"
              "  Output:\n"
              "    songname_kick.ogg    →  KICK\\\n"
              "    songname_snare.ogg   →  SNARE\\\n"
              "    songname_cymbals.ogg →  CYMBALS\\\n"
              "    songname_toms.ogg    →  TOMS\\\n\n"
              "  Best use: load each stem into a MIDI Editor stem slot for\n"
              "  per-lane verification — e.g. the kick stem shows only kick\n"
              "  transients in the waveform, making kick note placement precise.\n\n"
              "  Limitations:\n"
              "    ⚠  Results are NOT perfect — this is a BETA feature.\n"
              "    ⚠  Bleed between components is expected on complex patterns.\n"
              "    ⚠  Slower than standard split — CPU only.\n"
              "    ⚠  Not recommended as input for Auto MIDI generation.\n"
              "    ⚠  Model must be downloaded before first use (~200MB).")
        warn(s, "DrumSep requires a drums-only stem as input, not a full mix.\n"
                "Always run Standard Split first, then run DrumSep on the DRUMS ONLY result.")
        divider(s)
        entry(s,
              "Project Save / Load:\n"
              "  💾 Save Project — saves all Song Creator fields (MIDI, audio,\n"
              "  cover, title, artist, BPM, offset, difficulty, output folder)\n"
              "  to a .parakit file you can reload at any time.\n"
              "  📂 Load Project — restores all those fields from a saved file.\n"
              "  Use this to switch between songs without re-browsing everything.\n\n"
              "BPM correction:\n"
              "  ÷2 / ×2 buttons next to Manual BPM — halve or double the BPM\n"
              "  if detection gives you half or double the correct value.\n"
              "  Only available when Manual BPM mode is active.\n\n"
              "Send to Batch:\n"
              "  📋 Copy to Batch — copies current files to the Create Multiple\n"
              "  Songs tab to convert up to 3 songs at once.")
        divider(s)
        entry(s,
              "Extra Stems\n"
              "  Click '➕ Add more stem options' in the Files section to add up to\n"
              "  4 additional audio tracks beyond Song Audio and Drum Audio.\n\n"
              "  Each extra stem has two checkboxes (mutually exclusive):\n"
              "    ☑ Drum audio (default) — added to drumTracks in the .rlrr\n"
              "    ☐ Song audio           — added to songTracks in the .rlrr\n"
              "  Clicking one automatically unchecks the other.\n\n"
              "  Drum stems are added to drumTracks in the .rlrr.\n"
              "  Song stems are added to songTracks.\n"
              "  All extra stem files are copied to the output folder alongside\n"
              "  the main audio files.\n\n"
              "Preview Clip\n"
              "  Use Asset Manager to trim a short preview clip from your full mix,\n"
              "  then click 'Send clip to Song Creator' there. Song Audio is often\n"
              "  the backing track with no drums, so trimming that file can make the\n"
              "  in-game preview sound empty or strange.\n\n"
              "  The Preview Clip field stays editable if you already have a .ogg\n"
              "  preview clip made somewhere else.")
        tip(s, "Both features are available in Single Song Creator and Create Multiple Songs.")
        warn(s,
             "Auto-detect BPM only works reliably with a drums-only stem.\n\n"
             "If you run it against a full mix or a backing track (no drums), "
             "the detector picks up guitar, bass, and vocal transients instead of "
             "drum hits. This almost always produces a BPM that is exactly half "
             "the real value (e.g. 80 BPM instead of 160 BPM) because the "
             "strongest transients fall on beats 1 and 3 of a half-time grid.\n\n"
             "How to fix it:\n"
             "  1. Load a drums-only stem in the Drum Audio field before converting.\n"
             "     The Stem Splitter tab can generate one from any song.\n"
             "  2. If you only have a full mix, switch to Manual BPM and look up\n"
             "     the song's BPM online, or use a tap-tempo tool.\n"
             "  3. If auto-detect ran and gave a wrong value, use ÷2 or ×2 to\n"
             "     correct it before converting.\n\n"
             "The log will warn you when BPM detection is running on a full mix.")

        # ── Folder Batch ──────────────────────────────────────────────────────
        s = section("\U0001f3b6  Folder Batch", left,
                    summary="Convert a whole folder of MIDI + audio pairs at once.")
        entry(s,
              "What it does\n"
              "  Converts a folder of .mid + audio file pairs into Paradiddle charts\n"
              "  in one click. Each .mid file is matched to an audio file with the\n"
              "  same name (.ogg preferred, then .flac, .mp3, .wav).\n\n"
              "How to use\n"
              "  1.  Open the Create Multiple Songs tab.\n"
              "  2.  Scroll down to the Folder Batch section.\n"
              "  3.  Set Input Folder — the folder containing your .mid + audio pairs.\n"
              "  4.  Set Output Folder — where chart folders will be created.\n"
              "  5.  Optionally select a Template to control difficulty, complexity,\n"
              "      creator name, and overwrite behavior.\n"
              "  6.  Click \U0001f50d Check for Issues to check for problems before converting.\n"
              "  7.  Click \U0001f3b5 Convert Folder to start.\n\n"
              "Templates\n"
              "  A template is a small JSON file that sets chart options for the\n"
              "  whole batch. Three starter templates ship with ParaKit:\n"
              "    default.json    \u2014  Expert difficulty, complexity 3\n"
              "    fast_rock.json  \u2014  Hard difficulty, complexity 4, reduction on\n"
              "    metal.json      \u2014  Expert difficulty, complexity 5\n"
              "  Templates live in the templates\\ folder next to ParaKit.exe.\n"
              "  Click New... to create a copy you can edit.\n\n"
              "File matching rules\n"
              "  Flat scan only \u2014 subfolders are not searched.\n"
              "  Audio priority: .ogg > .flac > .mp3 > .wav\n"
              "  Files with no matching audio are listed as 'no audio' and skipped.\n\n"
              "Overwrite policy (set in template)\n"
              "  skip      \u2014  leave existing output folders untouched (default)\n"
              "  overwrite \u2014  write into the existing folder\n"
              "  rename    \u2014  append _2, _3, etc. to avoid collision\n\n"
              "Stop button\n"
              "  Stops after the current file finishes. No half-written .rlrr files\n"
              "  are left behind.")
        tip(s, "Metadata (title, artist) is read from audio file tags automatically.\n"
               "If tags are missing, the MIDI filename is used as the title.\n"
               "You can override defaults in the template's metadata_defaults section.")

        # ── Audio → MIDI Settings ─────────────────────────────────────────────
        s = section("🎹  Audio → MIDI — Settings Guide", left)
        note(s, "The purpose of the generator is to do the heavy lifting — it gives you "
                "a close, reasonably accurate chart to start from. It will always have "
                "some mistakes. That is normal and expected. Always clean up the output "
                "in the MIDI Editor before converting.")
        tip(s, "A misclassified note is always better than a missing one — the timing "
               "is already correct, you just need to change the instrument. Reclassify "
               "mode in the MIDI Editor is almost always the fastest and easiest fix "
               "regardless of what went wrong. When in doubt, generate first and "
               "reclassify after rather than spending time trying to get the settings perfect.")
        entry(s,
              "What to expect from each engine:\n\n"
              "  Spectral (default)\n"
              "    Works well on most songs with clean mixes. Kick, snare, and hi-hat\n"
              "    detection is solid. Toms and ride are less reliable. On fast or\n"
              "    dense patterns you may see occasional duplicate hits (same hit\n"
              "    detected twice) or a missed note here and there.\n\n"
              "  Hybrid  (recommended when model is installed)\n"
              "    Significantly more accurate than Spectral alone on most songs,\n"
              "    especially on kick, snare, and hi-hat. The ML model catches hits\n"
              "    that spectral misses, and spectral catches edge cases the model\n"
              "    may not have seen in training.\n\n"
              "    What Hybrid still gets wrong:\n"
              "    • Fast consecutive hits (16th/32nd note hi-hat runs, rapid snare\n"
              "      rolls) — may occasionally produce a duplicate hit or drop one\n"
              "      in a tight cluster. Easy to fix with the Dedup or Delete tools.\n"
              "    • Note misclassification still happens — the model treats crash and\n"
              "      ride as one cymbal class, so ride hits appear as crash. Toms still\n"
              "      occasionally appear as hi-hats or vice versa on dense fills.\n"
              "    • Song sections with heavy reverb, layered effects, or very quiet\n"
              "      ghost notes may still be missed or misread.\n\n"
              "    The improvement is real and noticeable on most songs, but Hybrid is\n"
              "    not a finished chart. It is a better rough draft. The MIDI Editor\n"
              "    is still the final step — expect 5-10 minutes of cleanup instead of\n"
              "    15-20 for most songs.")
        divider(s)
        entry(s,
              "⚡  Quick-fix guide — common problems and how to solve them fast\n\n"
              "These cover the most common issues with auto-generated MIDI and show\n"
              "how to fix them in 30 seconds or less using the MIDI Editor tools.\n\n"
              "━━  Problem 1: A whole section of notes is the wrong instrument\n"
              "    (e.g. a verse where all hi-hats show up as crashes, or a fill where\n"
              "    all toms show up as snares)\n\n"
              "    Fix — Rubber-band + Reclassify:\n"
              "    1. Hold Shift and drag across the section to select all notes in it\n"
              "    2. Click Reclassify in the toolbar\n"
              "    3. Click the correct instrument (e.g. Hi-Hat)\n"
              "    All selected notes change at once. Done in under 10 seconds.\n\n"
              "━━  Problem 2: Duplicate hits — every snare (or kick) shows up twice,\n"
              "    two notes right on top of each other\n\n"
              "    Fix — Dedup tool:\n"
              "    1. Select all affected notes (Ctrl+A for all, or rubber-band a section)\n"
              "    2. Click Tools → Dedup\n"
              "    3. Set the gap to something larger than the duplicate spacing (e.g. 40ms)\n"
              "    Dedup removes the second of any two notes within that gap window.\n"
              "    Alternatively: lower the Snare/Kick dedup gap in Advanced settings\n"
              "    and regenerate the MIDI.\n\n"
              "━━  Problem 3: A ride cymbal section — all notes are showing as crash\n"
              "    (this is normal behavior with the ML model — crash and ride are\n"
              "    the same class)\n\n"
              "    Fix — Rubber-band + Reclassify:\n"
              "    1. Hold Shift and drag across the crash notes in that section\n"
              "    2. Click Reclassify → Ride\n"
              "    The timestamps are already correct. You're only changing the label.\n"
              "    Tip: use the Preview/Practice Track while selecting so you can hear where\n"
              "    the ride section actually is.\n\n"
              "━━  Problem 4: A tom fill is missing 2-3 hits in the middle, or the\n"
              "    fill has the right number of notes but they're mostly hi-hats\n\n"
              "    Option A — Reclassify (if notes are there but wrong instrument):\n"
              "    1. Rubber-band select the fill\n"
              "    2. Reclassify → correct tom type\n\n"
              "    Option B — Add missing notes manually (if they're not there at all):\n"
              "    1. Turn OFF Snap to Grid (fast fills don't align to the beat grid)\n"
              "    2. Play the song in Preview/Practice Track and listen for where each hit lands\n"
              "    3. Click directly in the tom lane at the right position to place notes\n"
              "    4. Use the Song Tester to verify timing after placement\n\n"
              "━━  Problem 5: The whole chart is slightly early or late — every note\n"
              "    lands a consistent number of milliseconds off in Song Tester\n\n"
              "    Fix — Song Tester offset:\n"
              "    1. Open the Song Tester tab and play the chart\n"
              "    2. Adjust the Audio Offset slider until notes land on beat\n"
              "    3. This shifts the audio relative to the chart — no regeneration\n"
              "       needed\n"
              "    If it's only specific instruments that are early/late (not all of\n"
              "    them), use Peak Detection Interval in the Advanced settings instead\n"
              "    and regenerate.")
        divider(s)
        entry(s, "Onset Sensitivity  (default: 0.50)\n"
                 "How aggressively the detector picks up drum hits overall.\n"
                 "  Lower → more notes, higher risk of false hits.\n"
                 "  Higher → only strong hits detected, may miss quieter ones.\n"
                 "  Raise if you're getting too many ghost notes. Lower if hits are missing.")
        divider(s)
        entry(s, "Note Threshold  (default: 0.30)\n"
                 "Secondary sensitivity filter applied after onset detection. "
                 "Works alongside Onset Sensitivity — adjust them together if needed.")
        entry(s, "Genre\n"
                 "Adjusts internal detection thresholds based on how drums typically sound "
                 "in that style. These are broad approximations — not a perfect match for "
                 "every song. If a preset gives bad results, try another or tune manually.\n\n"
                 "Understanding the key parameters so you can tune manually:\n\n"
                 "  kick_sub_dom_thresh — how dominant the sub-bass must be for a hit to\n"
                 "    count as kick. Higher = stricter (fewer false kicks). Lower = more\n"
                 "    kicks detected including false ones.\n"
                 "    Default: 1.0  |  Pop-Punk: 1.6  |  Metal: uses default\n\n"
                 "  snare_delta_mult — onset sensitivity multiplier for snare detection.\n"
                 "    Lower = more sensitive, catches quieter/faster snares.\n"
                 "    Higher = only strong snare hits detected.\n"
                 "    Default: 0.9  |  Pop-Punk: 0.7  |  Metal: 0.5\n\n"
                 "  tom_rsub_max — max allowed sub-bass ratio for a tom hit. Keeps\n"
                 "    kick bleed from being misclassified as toms. Raise if toms are\n"
                 "    missing; lower if kicks are appearing as toms.\n"
                 "    Default: 0.40  |  Pop-Punk: 0.55\n\n"
                 "  tom_rwire_max — max allowed high-frequency ratio for a tom hit.\n"
                 "    Keeps hi-hat bleed from being misclassified as toms. Raise if\n"
                 "    toms are missing; lower if hi-hats appear as toms.\n"
                 "    Default: 0.35  |  Pop-Punk: 0.45\n\n"
                 "  cymbal_delta_mult — onset sensitivity for cymbal (hi-hat/crash) layer.\n"
                 "    Default: 1.6 for all presets currently.\n\n"
                 "  crash_strength_pct — percentile of cymbal hit strengths above which\n"
                 "    a hit is classified as crash rather than hi-hat. Higher = fewer\n"
                 "    crashes, more hi-hats. Default: 90 (top 10% are crashes).\n\n"
                 "Preset status:\n"
                 "  Auto / No Adjustment   — identical defaults, no overrides\n"
                 "  Pop / Pop-Punk & Rock  — kick threshold raised, snare more sensitive,\n"
                 "                           tom filters loosened.\n"
                 "  Metal / Hard Rock      — snare much more sensitive (guitar bleed).\n"
                 "  Punk & Hardcore        — removed. Lo-fi production, fast irregular\n"
                 "    tempos, and dense wall-of-cymbal playing make auto-detection\n"
                 "    unreliable for this genre regardless of threshold settings.\n"
                 "    For punk songs: use Auto or No Adjustment, generate a rough\n"
                 "    skeleton, then do heavy manual cleanup in the MIDI Editor.\n"
                 "    Sourcing a MIDI file if one exists will always give better results.\n\n"
                 "💡  If you understand what a parameter does, you can use 'No Adjustment'\n"
                 "and tune the Onset Sensitivity and dedup gaps manually to get the same\n"
                 "effect for your specific song without being locked into a preset.")
        divider(s)
        entry(s, "Detection Mode  (Spectral / Hybrid engine only)\n"
                 "  Sets the spectral analysis method used inside the Spectral and Hybrid engines.\n"
                 "  Has no effect when Detection Engine is set to ML / ONNX (pure).\n\n"
                 "  Auto (recommended) — tries both methods, picks better snare/kick ratio.\n"
                 "  Spectral — better for rock and acoustic drums.\n"
                 "  Frequency Band — better for programmed or synthetic drums.")
        divider(s)
        entry(s, "Ride Cymbal Detection  —  OFF: ride goes to Crash/Hi-Hat  /  ON: attempt separation\n"
                 "This toggle controls where ride cymbal hits end up in the MIDI Editor.\n\n"
                 "OFF (default):\n"
                 "  Ride hits are not separated from crash/hi-hat. They will appear in the\n"
                 "  Crash or Hi-Hat lane depending on their spectral energy. The Ride lane\n"
                 "  will be empty. This is the recommended default — reclassify manually\n"
                 "  after conversion (see Ride section in the cymbal behavior guide above).\n\n"
                 "ON — attempt ride separation:\n"
                 "  The spectral path tries to identify ride hits and route them to the Ride\n"
                 "  lane. Results are unreliable on most songs but can be useful on cleaner\n"
                 "  recordings or if you want to invest time tuning for a specific song.\n\n"
                 "  In Spectral mode: best-effort spectral estimate only.\n"
                 "  In ML mode: ML handles kick/snare/hi-hat/crash; ride detection comes\n"
                 "    from spectral only (the ML model combines crash and ride into one class).\n"
                 "  In Hybrid mode: same as ML for ride specifically. Because kick/snare/hi-hat\n"
                 "    are handled by ML, there is less spectral bleed into ride detection —\n"
                 "    this gives the best conditions for auto-detection.\n\n"
                 "Tips for experimenting:\n"
                 "  1. Use Hybrid mode + a drums-only stem from the Stem Splitter\n"
                 "  2. Enable ride detection\n"
                 "  3. Try different Ride dedup gap values in Advanced settings\n"
                 "  4. Compare a few runs\n"
                 "  Expect to manually correct most of the output regardless.\n\n"
                 "If a ride section has no notes at all after conversion, add them manually\n"
                 "in the Ride lane. Turn off Snap to Grid for precise placement on rapid hits.")
        divider(s)
        entry(s, "Kick Drum Detection  (default: on, ~90% accurate)\n"
                 "On by default and accurate for most songs. If you're getting many false "
                 "kick hits, disable it and add kicks manually in the MIDI Editor, or use "
                 "Reclassify mode to fix individual notes.")
        divider(s)
        warn(s, "Tom detection in Spectral mode is unreliable regardless of preset or settings. "
                "ML and Hybrid mode significantly improve basic tom hit detection, though the "
                "split between tom1/tom2/floor tom remains imprecise in all modes. "
                "The fastest fix: use Reclassify mode in the MIDI Editor to change misread "
                "notes to the correct tom type, or add missed tom hits manually in the tom "
                "lane. Turn off Snap to Grid for precise placement on fast tom fills.")
        divider(s)
        entry(s, "Note Dedup Gap  (Advanced/Debug)\n"
                 "How close two hits of the same instrument can be before the second is "
                 "discarded as a duplicate. Lower = more notes kept. Higher = more filtering.\n"
                 "  Hi-hats too sparse → lower Hi-Hat gap\n"
                 "  Double snare hits → raise Snare gap\n"
                 "  Rapid roll only shows first hit → lower Snare or Tom gap\n\n"
                 "The 'Settings for engine' toggle in the dedup section lets you set\n"
                 "separate values for Spectral/ML mode and Hybrid mode. They are stored\n"
                 "independently and the correct set is used automatically at conversion time.\n\n"
                 "Defaults:\n"
                 "  Spectral / ML — Global: 30ms, Hi-Hat: 20ms, others: 30ms\n"
                 "  Hybrid — Global: 20ms, Hi-Hat: 12ms, Crash: 25ms, others: 20ms\n"
                 "Hybrid defaults are tighter because ML timing is more precise and the\n"
                 "18ms merge window already collapsed near-duplicate cross-method detections.")
        divider(s)
        entry(s, "⚡  RAPID ROLL FIX\n"
                 "If a fast snare/tom roll shows the first hit correctly but the rest appear "
                 "as hi-hats or crashes at the same positions — the timing is already correct. "
                 "The energy was picked up but misclassified as cymbals.\n\n"
                 "Fix: Use Reclassify mode in the MIDI Editor. Click each misclassified note "
                 "and select the right instrument. No position adjustment needed. "
                 "No regeneration required.\n\n"
                 "If you hear a rapid roll in the MIDI Editor or Preview/Practice Track but see a "
                 "total note gap — no notes at all in that section — the roll was not "
                 "detected at all. Two options:\n"
                 "  • Lower the Snare or Tom dedup gap in Advanced/Debug and regenerate.\n"
                 "  • Add the missing notes manually in the MIDI Editor. Turn off "
                 "Snap to Grid first — rapid hits need precise placement and the grid "
                 "may not align with the actual timing of each hit.", "#00e5ff")
        divider(s)
        entry(s, "Peak Detection Interval  (Advanced/Debug)\n"
                 "Default: 0ms (off). When set above 0, scans forward from each detected "
                 "onset to find the true amplitude peak and snaps the note timestamp there.\n\n"
                 "The detector fires on the leading edge of a transient — the first moment "
                 "energy rises. The actual peak (loudest point) may be a few ms later. "
                 "This setting corrects for that without changing which notes are detected.\n\n"
                 "  Try 5–15ms if notes feel consistently slightly early after Song Tester correction.\n"
                 "  Avoid values above 20ms on fast patterns — snapping can overshoot.\n"
                 "  Regenerate after changing. Leave at 0 for most songs.")
        divider(s)
        entry(s, "Trigger Align  (Advanced/Debug — hidden by default)\n"
                 "Shifts every detected note timestamp by a fixed millisecond amount, "
                 "applied uniformly across all instruments after detection.\n\n"
                 "This is hidden because it is rarely needed. Use it only if:\n"
                 "  • Every note across all instruments lands the same fixed amount\n"
                 "    early or late, AND\n"
                 "  • Song Tester offset and Peak Detection Interval haven't resolved it.\n\n"
                 "If you're unsure whether you need this, you don't. Leave it at 0.\n"
                 "Click the '▾ Advanced: Trigger Align' button in Advanced/Debug to reveal it.")
        divider(s)
        entry(s,
              "🤖  Detection Engine  (v4.0)  ✨ NEW!\n\n"
              "Selects how drum hits are found in the audio. Three modes:\n\n"
              "  Spectral  (default)\n"
              "    The original audio analysis pipeline used in all versions before v4.0.\n"
              "    Uses band-pass filters and spectral shape to classify hits. No extra\n"
              "    files needed. Works on all systems without any setup.\n\n"
              "  ML / ONNX  (AI drum detection)\n"
              "    Uses the ADTOF neural network — the current state of the art in\n"
              "    automatic drum transcription research as of 2024/2025. The model was\n"
              "    trained on over 350 hours of real music annotated from rhythm game\n"
              "    charts — the same annotation style used by Paradiddle. It significantly\n"
              "    outperforms spectral methods on kick, snare, and hi-hat detection,\n"
              "    especially on complex or fast songs where spectral analysis struggles.\n"
              "    Requires: parakit_drum_model.onnx (click ↓ Download Model to download).\n\n"
              "  Hybrid  (recommended for best accuracy)\n"
              "    Runs both ML and Spectral in parallel, then merges results. Notes\n"
              "    found by either method are included. This gives the best overall\n"
              "    coverage — ML catches what spectral misses and vice versa.\n"
              "    Requires: parakit_drum_model.onnx.\n\n"
              "What the ML model improves:\n"
              "  Kick, snare, and hi-hat: significantly more accurate than spectral on\n"
              "    most songs, particularly fast or busy tracks.\n"
              "  Crash cymbals: detected from a combined cymbal class (crash + ride\n"
              "    together) — better coverage than spectral for crash hits.\n"
              "  Toms: detected as a single tom class — better than spectral for\n"
              "    basic tom hits, though tom1/tom2/floor_tom split still relies on\n"
              "    Hybrid mode or manual correction in the MIDI Editor.\n\n"
              "What the ML model does not improve:\n"
              "  Ride cymbal (separate from crash): the model treats crash and ride as\n"
              "    one class. Use Hybrid mode to let the spectral path attempt ride\n"
              "    detection, or reclassify manually in the MIDI Editor.\n"
              "  Electronic or heavily processed drum sounds: the model was trained on\n"
              "    acoustic drums. Electronic kits may give worse results than spectral.\n"
              "  Full mix vs drum stems: accuracy is significantly better if you run\n"
              "    the Stem Splitter first to isolate the drum track before converting.\n\n"
              "Important note about accuracy:\n"
              "  Published benchmark results for ADTOF are measured on clean stem audio\n"
              "    with expert-verified labels. Real-world results on full mixes will\n"
              "    vary. The model also uses an approximation of the original spectrogram\n"
              "    format, which may slightly reduce accuracy vs the published benchmarks.\n"
              "  Always review the result in the MIDI Editor regardless of which mode\n"
              "    you use — no automatic method is perfect.\n\n"
              "Recommended workflow for best results:\n"
              "  1.  Run Stem Splitter on your song to isolate the drum track\n"
              "  2.  Use the drum stem (not the full mix) as input for Audio → MIDI\n"
              "  3.  Select Hybrid as the Detection Engine\n"
              "  4.  Set genre if applicable\n"
              "  5.  Convert, then review and clean up in the MIDI Editor\n\n"
              "How to set up ML / Hybrid mode:\n"
              "  1.  In the Detection Engine section, select ML or Hybrid\n"
              "  2.  Click '↓ Download Model' — parakit_drum_model.onnx (~1.7 MB) downloads\n"
              "      automatically to Requirements\\ if present, otherwise next to ParaKit.exe\n"
              "  3.  Status should change to ✅ Model ready\n"
              "  4.  Convert as normal\n"
              "  Or: place parakit_drum_model.onnx manually next to ParaKit.exe\n"
              "      or in Requirements\\, then click 🔍 Check\n\n"
              "ML Confidence Threshold  (default: 0.50)\n"
              "  Controls how certain the model must be before counting a hit.\n"
              "  0.50 is a safe starting point for most songs.\n"
              "  Raise to 0.65–0.75 if getting too many false positives (ghost hits).\n"
              "  Lower to 0.35–0.40 if real hits are being missed.\n\n"
              "Troubleshooting:\n"
              "  'No model found' — model file is missing or in the wrong location.\n"
              "    Fix: click ↓ Download Model, or place parakit_drum_model.onnx next to\n"
              "    ParaKit.exe or in Requirements\\, then click 🔍 Check.\n\n"
              "  'Model error' — the file is corrupt or incompatible.\n"
              "    Fix: delete parakit_drum_model.onnx and click ↓ Download Model to\n"
              "    re-download a fresh copy.\n\n"
              "  ML/Hybrid gave worse results than Spectral on my song —\n"
              "    This can happen with electronic drum sounds, heavily compressed\n"
              "    mixes, or songs outside the model's training genre (mostly rock/metal).\n"
              "    Fix: switch back to Spectral, or try Hybrid with a higher confidence\n"
              "    threshold to suppress the bad ML hits while keeping spectral results.\n\n"
              "  Too many false hits —\n"
              "    Raise the ML Confidence Threshold (try 0.65–0.75).\n\n"
              "  Missing hits —\n"
              "    Lower the ML Confidence Threshold (try 0.35–0.40), or use Hybrid\n"
              "    so the spectral path fills in what ML misses.\n\n"
              "  Fallback behavior: if the model fails to load for any reason,\n"
              "    ParaKit automatically falls back to Spectral and logs the reason.\n"
              "    Check the conversion log for a fallback notice.")
        divider(s)
        entry(s,
              "🔬  Enhanced Detection  (experimental)  ✨ NEW!\n\n"
              "An optional helper that runs alongside the built-in detector. You\n"
              "choose exactly what it is allowed to improve.\n\n"
              "Options:\n"
              "  • Off: default detection only.\n"
              "  • Crash only: improves crash cymbal detection on tricky material.\n"
              "    Tom detection stays on the built-in detector.\n"
              "  • Toms only: improves tom detection on rock and metal tracks with\n"
              "    prominent fills. Crash detection stays on the built-in detector.\n"
              "    On songs with very few toms, this can add unwanted tom notes;\n"
              "    drag-select across the tom row in the MIDI Editor and press Delete.\n"
              "  • Crash + Toms: both enhancements active. This matches the old\n"
              "    Enhanced Detection ON behavior from v4.4.0.\n\n"
              "What always stays the same:\n"
              "  • Kick, snare, hi-hat, ride, and final tom-lane choices stay on\n"
              "    the built-in detector.\n"
              "  • If the helper has any problem, ParaKit falls back to the built-in\n"
              "    detector so your conversion still finishes.\n"
              "  • Enhanced options take extra processing time and write a comparison\n"
              "    file (.alt_detector.mid) for Ghost Overlay review.\n\n"
              "When to use it:\n"
              "  • Leave it OFF for normal use.\n"
              "  • Try Crash only for pop, ballads, or songs with few toms.\n"
              "  • Try Crash + Toms for rock or metal tracks with big fills.\n\n"
              "This is still experimental, so always review the chart before export.")
        divider(s)
        entry(s,
              "🧠  Neural Stem Isolation  (experimental)  ✨ NEW!\n\n"
              "An optional pre-cleaning step. Before detection runs, ParaKit can "
              "feed your audio into an AI splitter that separates the drums into "
              "kick, snare, hi-hat, toms, and cymbals stems, then mixes those "
              "cleaner stems back into a single track. Detection runs on the "
              "cleaned track instead of the original.\n\n"
              "When to use it:\n"
              "  • Leave it OFF for normal use — it adds about 30-60 seconds per\n"
              "    song on CPU and is not always better.\n"
              "  • Try it on tricky tracks where kick / snare / cymbal hits bleed\n"
              "    into each other and the default detector confuses them.\n"
              "  • Internal testing on metal tracks showed strong improvements\n"
              "    showed noticeably better snare, kick, and crash detection on metal tracks.\n"
              "    Other genres are still being measured.\n\n"
              "First time you turn it on, ParaKit prompts to download a ~417 MB\n"
              "model file. The model is saved to your user app data folder; "
              "ParaKit doesn't bundle the weights because the upstream model "
              "doesn't declare a license. The download is one-time — after "
              "that the option is just a checkbox.\n\n"
              "Heads up:\n"
              "  • CPU-only in this version. GPU support comes later.\n"
              "  • The ride lane still uses default detection in this version.\n"
              "  • If the splitter has any problem at runtime, ParaKit falls back\n"
              "    to default detection so your conversion still finishes.")
        divider(s)
        entry(s,
              "👻  Comparing detectors with Ghost Overlay\n\n"
              "When you turn on Enhanced Detection, ParaKit writes two chart files: "
              "the regular chart file used in the game, and a second comparison file "
              "that shows what the enhanced detector found on its own. You can use "
              "both to compare the two detectors side-by-side without converting "
              "your song twice.\n\n"
              "How to compare them:\n"
              "  1. Open the regular chart file in the MIDI Editor.\n"
              "  2. In the right sidebar, find the Ghost Overlay panel.\n"
              "  3. Click Browse in Ghost Overlay and select the comparison file "
              "     from the same folder.\n"
              "  4. The second file's notes appear as faded ghost notes underneath "
              "     your regular chart.\n\n"
              "Where the two charts agree, the notes line up. Where they disagree, "
              "you can see exactly which notes one detector caught that the other "
              "missed. This makes it easy to decide if any cleanup is needed before "
              "saving your final chart.")
        divider(s)
        entry(s,
              "🥁  How each engine handles cymbals — what to expect in the MIDI Editor\n\n"
              "Understanding this will save you confusion when you open the editor and\n"
              "see things in lanes you didn't expect.\n\n"
              "━━  Spectral mode\n"
              "  Hi-Hat lane:   populated with hits below the crash energy threshold.\n"
              "                 Open and closed hi-hat are NOT distinguished — they all\n"
              "                 appear as the same hi-hat note.\n"
              "  Crash lane:    populated with the top " + str(90) + "% strongest cymbal hits\n"
              "                 (the crash_strength_pct threshold). On a song with moderate\n"
              "                 cymbal activity this is usually correct. On busy crash-heavy\n"
              "                 sections it can over-fill the crash lane.\n"
              "  Ride lane:     always EMPTY unless you enable Ride Cymbal Detection\n"
              "                 in the settings. That toggle is off by default because\n"
              "                 spectral ride detection is unreliable — see the Ride\n"
              "                 section above.\n\n"
              "━━  ML / ONNX mode (pure)\n"
              "  Hi-Hat lane:   populated from the model's dedicated hi-hat class.\n"
              "                 This is the strongest class in the ADTOF model and tends\n"
              "                 to be the most accurate of all the cymbal outputs. Open\n"
              "                 and closed hi-hat are still NOT distinguished — they all\n"
              "                 appear as the same hi-hat note.\n"
              "  Crash lane:    populated from the model's combined 'CY+RD' cymbal class.\n"
              "                 This is the key thing to understand: the ADTOF model was\n"
              "                 trained on rhythm game chart data which does not separate\n"
              "                 crash and ride into different classes. Every cymbal hit\n"
              "                 that is not a hi-hat — crash, ride, china, open hi-hat\n"
              "                 hit hard — will appear in the CRASH lane. Not because\n"
              "                 they are all crashes, but because the model puts them there.\n"
              "  Ride lane:     always EMPTY in pure ML mode. The model has no ride class.\n\n"
              "━━  Hybrid mode\n"
              "  Hi-Hat lane:   best coverage — both ML and spectral hi-hat results\n"
              "                 are merged. ML timing is preferred when both methods\n"
              "                 detect the same hit. Fast hi-hat patterns (16th notes)\n"
              "                 are significantly better than Spectral alone.\n"
              "  Crash lane:    merged from ML's combined cymbal class and spectral's\n"
              "                 crash detections. This means the crash lane will typically\n"
              "                 contain more hits than Spectral alone — including ride hits\n"
              "                 that the ML model classified as cymbal. This is expected.\n"
              "  Ride lane:     populated ONLY from the spectral path if Ride Cymbal\n"
              "                 Detection is turned ON. ML contributes nothing to the\n"
              "                 ride lane. Even with spectral ride enabled, results\n"
              "                 are unreliable — see the Ride section above.\n\n"
              "━━  Summary table\n"
              "                  Spectral    ML          Hybrid\n"
              "  Hi-Hat          ✓ good      ✓ best      ✓ best\n"
              "  Open hi-hat     ✗ same as closed (all modes — no open/closed class)\n"
              "  Crash           ✓ ok        ⚠ mixed*    ✓ good\n"
              "  Ride            ✗ empty†    ✗ empty     ✗ empty†\n"
              "\n"
              "  * Crash lane contains crash + ride + other cymbals in ML mode\n"
              "  † Unless Ride Cymbal Detection toggle is ON (unreliable, see above)\n\n"
              "━━  What to do about ride in the MIDI Editor\n"
              "  After generating with ML or Hybrid:\n"
              "  1. Open the MIDI Editor and look at the Crash lane\n"
              "  2. Sections that should be ride will be in the Crash lane as orange notes\n"
              "  3. Hold Shift and drag across those notes to select them\n"
              "  4. Click Reclassify → Ride\n"
              "  The timing is already correct. You are only changing the instrument label.\n"
              "  This takes 30-60 seconds on most songs.\n\n"
              "━━  What to do about open hi-hat\n"
              "  Open hi-hat is not detected by any engine — they appear as regular hi-hat.\n"
              "  There is no separate open hi-hat instrument in Paradiddle's MIDI mapping,\n"
              "  so there is no lane to reclassify them to.\n\n"
              "  The correct approach is to represent open hi-hats as ghost notes:\n"
              "  1. In the MIDI Editor, use the MIDI Editor's playback (or send to Preview/Practice Track) to listen for the open hits\n"
              "     (sustained, not choked — usually louder and longer sounding)\n"
              "  2. Select those hi-hat notes (click or rubber-band)\n"
              "  3. In the Velocity Lane below the piano roll, click the Ghost (30) preset\n"
              "     button, or drag the note's velocity bar down below 40\n"
              "  The note renders as a hollow outline — Paradiddle sometimes interprets\n"
              "  low-velocity hi-hat hits as the open articulation in-game.")
        warn(s, "The most common post-generation confusion: opening the MIDI Editor after\n"
                "using ML or Hybrid and seeing the ride lane empty while the crash lane is\n"
                "full of notes that should be rides. This is not a bug. The model combined\n"
                "them intentionally. Use rubber-band select + Reclassify to fix it in under\n"
                "a minute.")

        # ── MIDI Extractor ────────────────────────────────────────────────────
        s = section("📂  MIDI Extractor", left)
        entry(s,
              "Convert a Paradiddle chart file (.rlrr) to MIDI without re-recording.\n\n"
              "Open it from the Advanced / Debug section of the Audio → MIDI tab — "
              "click '▾  MIDI Extractor (hidden)' to reveal the panel.\n\n"
              "Single File mode:\n"
              "  Select a .rlrr file. The panel immediately shows a preview: note count, "
              "duration, BPM, and per-instrument breakdown. Edit the Title, Artist, and "
              "Creator fields if needed — these are written into the MIDI file's track "
              "name and used as the output filename.\n\n"
              "  Extract MIDI — writes the file next to the source (or to a chosen output folder).\n"
              "  Extract MIDI & Send to Editor — extracts the file then immediately loads "
              "it into the MIDI Editor tab so you can start editing without any extra steps.\n\n"
              "Batch Folder mode:\n"
              "  Select a folder. All .rlrr files in it (and subfolders) are listed with "
              "a live count. Use the Difficulty filter to extract only specific difficulties "
              "(Easy / Medium / Hard / Expert / Expert+). Click Extract MIDI to convert "
              "all matching files. A Stop button cancels cleanly between files — no "
              "half-written MIDIs are left behind.\n\n"
              "Output Folder:\n"
              "  Browse to set a custom output directory (persists between sessions).\n"
              "  Clear resets it to 'Same as source'. 📂 Open opens the current folder.\n"
              "  Defaults to the same folder as the source .rlrr file.")
        tip(s, "Use 'Extract MIDI & Send to Editor' to go straight from a chart file to "
               "editing — one click extracts and opens. Great for creating alternate "
               "difficulties or cleaning up auto-detected charts.")
        note(s, "Requires the 'Extractor Mini App' folder alongside ParaKit.exe. "
                "If the panel shows an error message instead of the extractor UI, "
                "that folder is missing or has been renamed.")

        # ── MIDI Editor ───────────────────────────────────────────────────────
        s = section("🎼  MIDI Editor", left)
        entry(s,
              "Standard controls:\n"
              "  Left-click empty space  →  add a note\n"
              "  Right-click a note      →  delete it\n"
              "  Left-click + drag note  →  move a note horizontally\n"
              "  Scroll wheel            →  scroll the timeline left/right\n"
              "  Click the beat ruler    →  seek playback position\n"
              "  Drag the beat ruler     →  scrub through the timeline\n"
              "  Right-click beat ruler  →  set loop In/Out points\n"
              "  Click the waveform      →  seek to that position\n\n"
              "Multi-select:\n"
              "  Shift + drag on empty space →  rubber-band select multiple notes\n"
              "  Ctrl + left-click           →  toggle individual notes in/out of selection\n"
              "  Delete / Backspace          →  delete all selected notes at once\n"
              "  Drag a selected note        →  move all selected notes together\n"
              "  Right-click in Reclassify mode → reclassify all selected notes at once\n\n"
              "Keyboard shortcuts:\n"
              "  P                       →  play / pause\n"
              "  S                       →  stop\n"
              "  T                       →  tap to mark offset (see below)\n"
              "  B                       →  tap BPM for the last tempo map entry\n"
              "  D                       →  place a marker at playhead or last click\n"
              "  Middle-click (canvas)   →  place a marker at clicked position\n"
              "  1                       →  place Kick note\n"
              "  2                       →  place Snare note\n"
              "  3                       →  place Hi-Hat note\n"
              "  4                       →  place Crash note\n"
              "  5                       →  place Ride note\n"
              "  6                       →  place Tom 1 note\n"
              "  7                       →  place Tom 2 note\n"
              "  8                       →  place Floor Tom note\n"
              "  Delete / Backspace      →  delete selected note(s) and/or marker(s)\n"
              "  Ctrl + Z                →  undo  (including note moves and markers)\n"
              "  Ctrl + Y                →  redo\n"
              "  Ctrl + C                →  copy selected notes\n"
              "  Ctrl + V                →  paste at playhead or last click position\n"
              "  Ctrl + Q                →  quantize selected notes (or all) to 16th grid\n"
              "  Ctrl + scroll wheel     →  zoom in / out\n\n"
              "  All note-placement keys (1–8, D) place at the playhead if audio is\n"
              "  playing, or at the last position you clicked on the canvas if not.\n"
              "  Snap to Grid applies to all hotkey placements.\n\n"
              "Reclassify mode  (green checkbox in toolbar):\n"
              "  Enable to change any note's instrument without deleting it.\n"
              "  Two ways to reclassify:\n"
              "    Click a note         →  instrument picker menu appears\n"
              "    Drag a note vertically  →  moves it directly to whichever lane\n"
              "                              the mouse crosses — faster for bulk lane\n"
              "                              fixes when the target is visually obvious\n"
              "  With multiple notes selected, both methods affect all selected notes.\n"
              "  Ctrl+Z undoes any reclassification.")
        divider(s)
        entry(s,
              "📋 Send to Song Creator  (handoff button):\n\n"
              "  The Song Creator button at the top of the MIDI Editor tab\n"
              "  hands the current chart off to Single Song Creator (Tab 1)\n"
              "  with most of the wiring done for you:\n\n"
              "    - MIDI File field is set to the current MIDI's path.\n"
              "    - 'Use BPM from MIDI file' is enabled automatically.\n"
              "    - If a Drums audio stem is loaded in MIDI Editor stem\n"
              "      slot 1 (Drums), its path is copied into Song Creator's\n"
              "      Drum Audio field.\n\n"
              "  Unsaved MIDI edits are written to disk before the handoff,\n"
              "  so Song Creator always sees your latest notes. In 'Save as\n"
              "  copy' mode you'll be asked to pick a copy path first; in\n"
              "  'Modify original' mode the changes go to the loaded file.\n\n"
              "  You still need to:\n"
              "    - Add the backing audio (Song Audio / Full Mix) manually —\n"
              "      ParaKit doesn't assume which stem ships as the in-game\n"
              "      backing track.\n"
              "    - Fill in metadata (title, artist, difficulty, complexity)\n"
              "      and cover art — Asset Manager (Tab 9) can auto-fetch\n"
              "      metadata + album art with one click.")
        divider(s)
        entry(s,
              "1–8 Note Hotkeys:\n\n"
              "  Press keys 1–8 while on the MIDI Editor tab to instantly place a note\n"
              "  in the corresponding lane at the current playhead position (if playing)\n"
              "  or at the last position you clicked on the canvas (if paused).\n\n"
              "  Mapping:\n"
              "    1 = Kick          5 = Ride\n"
              "    2 = Snare         6 = Tom 1\n"
              "    3 = Hi-Hat        7 = Tom 2\n"
              "    4 = Crash         8 = Floor Tom\n\n"
              "  The mapping follows the most common charting workflow — kick and snare\n"
              "  on 1 and 2 (the most frequent hits), hi-hat on 3, cymbals on 4-5,\n"
              "  toms ascending on 6-8.\n\n"
              "  All placements respect Snap to Grid. Velocity defaults to 100.\n"
              "  Use the Velocity Lane to adjust dynamics after placing.\n\n"
              "  Keys only fire when focus is not in a text entry field.\n"
              "  Click any of the editor canvas, waveform strip, or velocity lane\n"
              "  to return focus to the editor after typing in a text field.\n"
              "  Keys do not fire on other tabs.")
        divider(s)
        entry(s,
              "🎚 Audio output latency:\n\n"
              "  ParaKit shows a playhead while audio plays so you can match notes to\n"
              "  what you hear. The audio engine takes a few milliseconds to flush its\n"
              "  output buffer through the OS and your hardware (Bluetooth, HDMI, USB\n"
              "  DAC, etc.) — without compensation the playhead would draw ahead of the\n"
              "  audio and the editor would feel out of sync.\n\n"
              "  The 'Audio output latency' slider above the playback controls fixes\n"
              "  this. The starting value is auto-estimated for your operating system\n"
              "  (Windows ~42 ms, macOS ~22 ms, Linux ~37 ms). Slide the value up if\n"
              "  the playhead still leads the audio you hear, or down if the playhead\n"
              "  lags behind.\n\n"
              "  Tip:\n"
              "    Calibrate by playing a section with an obvious downbeat, then\n"
              "    adjusting the slider until the playhead crosses each note exactly\n"
              "    when you hear the hit. Note offsets and the T tap-to-mark feature\n"
              "    will then capture audio-true times automatically.")
        divider(s)
        entry(s,
              "🥁 Flam Tool  (toolbar row 2):\n\n"
              "  A flam is a drumming technique where a very quiet grace note lands\n"
              "  just milliseconds before the main hit, giving it a 'fat' or accented\n"
              "  sound. In charting, flams appear as two near-simultaneous notes in the\n"
              "  same lane — the grace note is much quieter than the main hit.\n\n"
              "  How to use:\n"
              "    1.  Select one or more notes you want to add a flam to\n"
              "    2.  Click 🥁 Flam\n"
              "    3.  A ghost note (velocity 30) is placed 30ms before each selected note\n"
              "    4.  Ctrl+Z to undo\n\n"
              "  Tips:\n"
              "    Best used on snare hits and accented tom hits.\n"
              "    30ms / velocity 30 are standard flam values — if you need tighter\n"
              "    flams, place grace notes manually with Snap to Grid off.\n"
              "    Do not apply flams to rapid 16th-note patterns — they will overlap.")
        divider(s)
        entry(s,
              "Multi-Stem Audio Workspace  (Playback Audio section):\n\n"
              "  The MIDI Editor supports up to 4 simultaneous audio stems loaded at once.\n"
              "  Each stem has its own browse slot and a radio button to select it.\n\n"
              "  Active stem indicator:\n"
              "    Each stem row has a thin colored bar on its left edge:\n"
              "      🟢 Green  — this stem is the active one in Single track mode\n"
              "      🔵 Blue   — stem is loaded and playing in Layered mode\n"
              "      ⬛ Dark   — stem is inactive or no file is loaded\n"
              "    The indicator updates instantly when you click a radio button,\n"
              "    switch modes, or press play.\n\n"
              "  ⇄ Switch Stem button cycles to the next loaded stem in Single mode.\n\n"
              "  Recommended stem layout:\n"
              "    Slot 1 (Drums)    — drums-only stem from the Stem Splitter\n"
              "    Slot 2 (Full Mix) — the complete song audio\n"
              "    Slot 3 (Stem 3)   — any additional stem (e.g. kick-only or bass)\n"
              "    Slot 4 (Stem 4)   — any additional stem\n\n"
              "  Why use multiple stems:\n"
              "    The drums-only stem is clearest for timing — use it when placing notes.\n"
              "    Switch to the full mix to check how the chart feels against the song.\n\n"
              "  Single track mode: only the active (green) stem plays.\n"
              "  Layered mode: all loaded stems play simultaneously (blue indicators).\n"
              "  All stems accept .ogg, .wav, .flac, .mp3.\n"
              "  Drag and drop files directly onto the entry fields.")
        divider(s)
        entry(s,
              "Edit Tools  (toolbar row 2):\n\n"
              "  ⊞ Quantize  (also Ctrl+Q):\n"
              "    Snaps selected notes to the nearest 16th-note grid position.\n"
              "    If nothing is selected, quantizes all notes.\n"
              "    Use when notes from auto-detection land slightly off the beat.\n"
              "    Tip: select only the notes you want quantized — avoid quantizing\n"
              "    ghost notes or shuffle grooves that are intentionally off the grid.\n\n"
              "  ⧉ Copy  /  ⧈ Paste  (also Ctrl+C / Ctrl+V):\n"
              "    Copy: saves the selected notes to a clipboard (relative positions).\n"
              "    Paste: places them starting at the current playhead position,\n"
              "    or at the last position you clicked on the canvas if not playing.\n"
              "    Pasted notes are automatically selected so you can move them.\n"
              "    Paste can be repeated — each Ctrl+V places another copy.\n\n"
              "  × Dedup:\n"
              "    Removes exact duplicate notes — same time and same lane.\n"
              "    The auto-detector occasionally creates stacked duplicates that\n"
              "    are invisible but cause double-hit artifacts. Run Dedup after\n"
              "    generating to clean these up. Reports how many were removed.\n\n"
              "  ↻ Repeat:\n"
              "    Tiles the selected pattern once immediately after itself.\n"
              "    Useful for building out a chart from a detected verse or fill.\n"
              "    Select one bar, click Repeat, select two bars, click Repeat, etc.\n"
              "    Pattern length snaps to the nearest beat for clean tiling.\n"
              "    Ctrl+Z undoes. The repeated notes are selected after pasting.\n\n"
              "  ✂ Vel Filter:\n"
              "    Removes all notes below a velocity threshold you choose (1–127).\n"
              "    Default threshold is 30 — this catches most ghost-note artifacts\n"
              "    and low-confidence bleed hits from auto-detection without touching\n"
              "    real notes, which are typically velocity 60+.\n"
              "    A live preview tells you exactly how many notes will be removed\n"
              "    before you commit.\n"
              "    If notes are selected, only those notes are filtered.\n"
              "    If nothing is selected, the filter applies to all notes.\n"
              "    Ctrl+Z undoes. Run this right after generating MIDI for a fast\n"
              "    first pass at removing false positives.")
        tip(s, "Reclassify mode is the fastest fix for misclassified notes — especially "
               "for rapid roll hits that showed up as hi-hats or crashes.")
        divider(s)
        entry(s,
              "Velocity Lane  (inside the Tempo Map + Velocity Lane section):\n\n"
              "  Each note has a velocity (1–127) that controls how hard it is hit.\n"
              "  In Paradiddle this maps to accent and ghost note dynamics.\n\n"
              "  Visual distinction in the piano roll:\n"
              "    Ghost notes (vel < 40)   — hollow outline, no fill (always hollow,\n"
              "                               even when selected — white outline when selected)\n"
              "    Normal notes (vel 40–114) — solid filled shape\n"
              "    Accent notes (vel ≥ 115)  — solid fill + hot pink outline\n"
              "  This matches how Paradiddle renders them in-game.\n\n"
              "  How to place a ghost note:\n"
              "    1.  Place the note normally (click canvas or use 1–8 hotkeys)\n"
              "    2.  Select it (click to select, or rubber-band)\n"
              "    3.  In the Velocity Lane, click the Ghost (30) preset button,\n"
              "        OR drag the note's bar to a low height (< 40)\n"
              "    The note will immediately render as hollow in the piano roll.\n\n"
              "  How to place an accent note:\n"
              "    1.  Select the note(s) you want accented\n"
              "    2.  Click the Accent (120) preset button in the Velocity Lane,\n"
              "        OR drag the note's bar to the top (≥ 115)\n"
              "    The note will render with a hot pink outline.\n\n"
              "  Quick presets (apply to selected notes, or all if none selected):\n"
              "    Ghost (30)   — makes notes hollow — very quiet in Paradiddle\n"
              "    Normal (100) — standard hit volume\n"
              "    Accent (120) — loud, prominent hit with hot pink outline\n\n"
              "  Set Selected slider:\n"
              "    Drag to a specific value, click Apply to Selected.\n"
              "    Use this for precise control outside the three presets.\n\n"
              "  The velocity lane scrolls in sync with the piano roll.\n"
              "  Open it by checking the Tempo Map + Velocity Lane toggle.")
        tip(s, "Reclassify mode is the fastest fix for misclassified notes — especially "
               "for rapid roll hits that showed up as hi-hats or crashes.")
        divider(s)
        entry(s, "Playback Audio (Multi-Stem Workspace):\n"
                 "  Load up to 4 audio stems in the Playback Audio section.\n"
                 "  Each slot has its own Browse button and recent files list.\n"
                 "  Recommended: Slot 1=Drums Only, Slot 2=Full Mix,\n"
                 "  Slots 3-4 for additional stems (kick-only, bass, etc.)\n\n"
                 "Playback modes:\n"
                 "  Single track — only the stem selected by the radio button plays.\n"
                 "  Layered — all loaded stems play simultaneously.\n"
                 "  Use the 🎚 Mixer popup button to control per-stem volume.\n"
                 "  ⚠  Layered mode at non-1.0x speed is CPU-intensive — use 1.0x.\n\n"
                 "  Requires pygame (install prompt shown if missing).\n\n"
                 "Playback speed controls:\n"
                 "  -0.1x / +0.1x — slow down or speed up playback in 0.1x steps.\n"
                 "  Maximum speed is 1.0x (normal). Minimum is 0.1x.\n"
                 "  Speed: label shows current rate. ↺ Reset returns to 1.0x.\n"
                 "  Speed changes do NOT change pitch — only tempo is affected.\n"
                 "  Slowing to 0.3x or lower is useful for finding exact hit timestamps.\n"
                 "  No delay when changing speed or pressing play/pause.\n\n"
                 "  ⚠  At slow speeds, drum hits may appear to land slightly after\n"
                 "  the note marker even when sync is correct. This is a perceptual\n"
                 "  limitation of time-stretching — the transient attack of each hit\n"
                 "  gets smeared slightly by the algorithm, making it sound like it\n"
                 "  arrives a few ms late. The playhead and note positions are\n"
                 "  mathematically accurate. The same content at 1.0x will feel\n"
                 "  perfectly locked. Trust the 1.0x feel for final sync checks,\n"
                 "  and use slow speed only for finding timestamps.\n\n"
                 "Waveform display:\n"
                 "  A waveform strip appears below the piano roll showing the audio\n"
                 "  amplitude aligned to the current scroll position. The waveform\n"
                 "  scrolls in sync with the note lanes. The green playhead line\n"
                 "  appears on the waveform too. Click the waveform to seek.\n"
                 "  Loads automatically when you browse an audio file.\n"
                 "  The waveform always shows the active stem (radio button).\n\n"
                 "  Using the waveform to find offset:\n"
                 "  Load a drums-only stem for the clearest view. Scroll to the\n"
                 "  start of the waveform and look for the first visible spike —\n"
                 "  that is your first drum hit. Slow to 0.3x, play near the spike,\n"
                 "  and press T at the moment you hear it. The offset is set.\n\n"
                 "  Using the waveform to add missed notes:\n"
                 "  With a drums-only stem loaded, slow to 0.3x and scrub through\n"
                 "  the waveform. Each spike is a drum hit. If a spike has no note\n"
                 "  above it, click that position in the correct lane to add it.\n"
                 "  This is the most reliable method for catching missed hits —\n"
                 "  you can see exactly where the energy is without guessing.\n\n"
                 "Loop section:\n"
                 "  Right-click the beat ruler to set In/Out points, or use the\n"
                 "  Set Start / Set End buttons at the current playback position.\n"
                 "  Enable the Loop checkbox to repeat that section continuously.\n"
                 "  Gold Start/End markers and a shaded region show the loop range.\n"
                 "  Clear Loop resets both points and disables looping.")
        divider(s)
        entry(s, "Tap to mark offset  (T key):\n\n"
                 "  Use this to find the exact audio offset for a song's drum intro\n"
                 "  without guessing. Best used alongside the waveform display.\n\n"
                 "  Workflow:\n"
                 "  1.  Load your drums-only stem in Playback Audio — Drums Only\n"
                 "  2.  Look at the waveform strip below the piano roll — the first\n"
                 "      spike is your first drum hit\n"
                 "  3.  Click near that spike to seek to it\n"
                 "  4.  Slow to 0.3x–0.5x using -0.1x, or pause near the hit\n"
                 "  5.  Press T at the exact moment you hear it — or while paused\n"
                 "      at the correct position\n"
                 "  6.  The timestamp writes to the Drum start offset field on the\n"
                 "      Sheet Music tab (Tab 7) automatically\n"
                 "  7.  Switch to Sheet Music tab and convert — offset is set\n\n"
                 "  Use the ±10ms / ±100ms nudge buttons on the Sheet Music tab\n"
                 "  to fine-tune after tapping if needed.\n\n"
                 "  Note: T only works while on the MIDI Editor tab and when focus\n"
                 "  is not in a text entry field.")
        note(s, "Kick notes appear PINK in the editor. In-game they are dark blue. "
                "This is intentional — pink makes kicks visually distinct from all other notes. "
                "Toggle 'Show kick as full-width line' in the toolbar to switch to bar style.")
        note(s, "Undo/redo now correctly covers note moves by drag. The state is captured "
                "at the moment you click a note to drag it, so Ctrl+Z restores the exact "
                "position before the move.")
        divider(s)
        entry(s,
              "Snap to Nearby Notes  (Display & Snap panel, right column of MIDI Editor):\n\n"
              "  When enabled, dragging a note will snap it to the exact timestamp of the\n"
              "  nearest note in any other lane — useful for aligning a snare to a kick,\n"
              "  or a tom hit to a cymbal that is already perfectly timed.\n\n"
              "  Controls:\n"
              "    Snap to nearby notes — enable/disable the feature\n"
              "    Threshold — how close (in pixels) the dragged note must be before it\n"
              "      snaps. Default: 10px. Raise for looser snap, lower for tighter.\n"
              "    Guides — choose 'On snap' to show the yellow guide line only when\n"
              "      locked to a note, or 'Always' to show it continuously as a\n"
              "      visual reference while moving.\n"
              "    Show even when snap off — force the guide line to appear during a\n"
              "      drag even with 'Snap to notes' unchecked.  Useful when you want a\n"
              "      vertical reference without engaging snap behavior.\n\n"
              "  Priority: note snap takes precedence over grid snap when a nearby note\n"
              "  is within the threshold. Falls back to grid snap if nothing is close.\n"
              "  The dragged note and other selected notes are excluded from snap targets.")
        divider(s)
        entry(s,
              "Change a note's lane  (Reclassify mode):\n\n"
              "  To move a note between lanes (kick / snare / hi-hat / etc.) without\n"
              "  changing its time, turn on the Reclassify toggle in the editor.\n"
              "  Then drag the note up or down — the lane changes as you drag.\n\n"
              "  Multi-select: select several notes first, then drag any of them in\n"
              "  Reclassify mode and they all shift to the new lane together.\n\n"
              "  Right-click a note in Reclassify mode for a lane picker menu.\n\n"
              "  You can also add a new note in the correct lane (with snap on) and\n"
              "  delete the old one — same outcome.")
        divider(s)
        entry(s,
              "Chart Start / Chart End markers:\n\n"
              "  When a MIDI is loaded, a green dashed line marks the first note\n"
              "  (Chart Start) and an orange dashed line marks the last note\n"
              "  (Chart End). Both are labeled in the timeline header.\n\n"
              "  On the waveform strip, audio before Chart Start and after Chart End\n"
              "  is darkened — this audio is not covered by the chart.\n\n"
              "  Why this matters:\n"
              "  Many community charts skip pre-roll or outro drums and start at the\n"
              "  main verse downbeat. If the audio contains drum hits before the Chart\n"
              "  Start marker (or after Chart End), that is usually intentional — the\n"
              "  chart-maker chose not to include those sections.\n\n"
              "  Do NOT shift the chart to align with the audio's first drum hit.\n"
              "  Doing so will move all notes relative to the song's tempo grid and\n"
              "  break in-game sync in Paradiddle. The chart is correctly placed —\n"
              "  the pre-roll audio simply is not charted.")
        divider(s)
        entry(s,
              "Note Display  (Display & Snap panel, right of Playback Audio):\n\n"
              "  Grid: (1/4 | 1/8 | 1/16 | 1/32)\n"
              "    Controls how many subdivision lines are drawn between beats.\n"
              "    1/4  — quarter notes only: beat and bar lines, no subdivisions.\n"
              "    1/8  — eighth notes: one subdivision line between each beat.\n"
              "    1/16 — sixteenth notes: three subdivision lines per beat (default).\n"
              "    1/32 — thirty-second notes: seven subdivisions per beat, shown at\n"
              "           three brightness levels — 8th-note lines (brightest sub),\n"
              "           16th-note lines (mid), and 32nd-note lines (faintest).\n"
              "    Changing the resolution is purely visual. Note positions are stored\n"
              "    as absolute time values and are never affected by the grid setting.\n\n"
              "  Show grid lines over notes:\n"
              "    Redraws the beat grid on top of all notes rather than behind them.\n"
              "    Useful for seeing exactly which beat a note falls on.\n\n"
              "  All notes as squares:\n"
              "    Forces every note to render as a rectangle. Cymbal lanes (hi-hat,\n"
              "    crash, ride) normally draw as circles — this overrides that.\n"
              "    Easier for cross-lane alignment. Kick line still works.\n\n"
              "  Show notes as in-game icons:\n"
              "    Each note stretches to fill the full height of its lane row,\n"
              "    matching how notes appear as you play in-game. ON by default.\n"
              "    Width is still controlled by the Note Size buttons only.\n"
              "    Kick line toggle still works independently.\n\n"
              "  All three toggles can be combined for maximum clarity.\n\n"
              "  🎯  Stripe low-confidence ML notes  (hot pink):\n"
              "    Only relevant after using ML or Hybrid detection. Notes where the\n"
              "    model's confidence was below 70% are drawn with hot-pink diagonal\n"
              "    stripes while keeping their lane color. Full-width kick lines are\n"
              "    excluded so the view stays readable. These are the hits most likely to be false positives.\n"
              "    Use the 🔍 Review Issues button to jump directly to low-confidence\n"
              "    notes for fast review. Toggle off to see the chart normally.\n\n"
              "  ⚡  Reactive notes  (flash white on playhead):\n"
              "    Notes turn solid white as the playhead passes over their center.\n"
              "    Works during playback, while scrubbing (dragging the playhead), and\n"
              "    while paused — click anywhere on the timeline to see which notes\n"
              "    are at that position. The flash window is ±40 ms around the note's\n"
              "    exact time, so the visual feedback is tied to the note center, not\n"
              "    the note's drawn width.\n\n"
              "    Use this when filling in a difficult section and you want to confirm\n"
              "    at a glance that your notes land on the beat as the track plays through.")
        divider(s)
        entry(s,
              "👻  Ghost Overlay  (Display & Snap panel, right column):\n\n"
              "  Load a second MIDI file as a faded reference layer behind your\n"
              "  main notes. Ghost notes are non-interactive — you cannot click,\n"
              "  drag, or select them. They are visual guides only.\n\n"
              "  Use case 1 — Difficulty scaling:\n"
              "  Chart your Expert version first, then load it as a Ghost Overlay\n"
              "  while charting Hard or Medium. You can see exactly where the major\n"
              "  crashes, kicks, and fills land without switching files, ensuring\n"
              "  all difficulties stay structurally aligned to the same song.\n\n"
              "  Use case 2 — Reworking or personalizing an outsourced MIDI:\n"
              "  If a chart already exists for a song but it's too easy, too hard,\n"
              "  or you just don't like how the charter handled certain sections,\n"
              "  you don't have to start from scratch or constantly flip between\n"
              "  two files to reference it.\n\n"
              "  Load the existing chart as a Ghost Overlay, then build your own\n"
              "  version on top of it. The ghost notes show you exactly where\n"
              "  every hit lands — you can recreate what you want to keep, skip\n"
              "  what you don't, and place your edits with precise timing without\n"
              "  any guesswork. A fast fill you want to simplify, a section you\n"
              "  want to make harder, a pattern you'd play differently — you can\n"
              "  see the original positions and work against them directly.\n\n"
              "  How to use:\n"
              "    1.  Click ... next to the Ghost Overlay entry field\n"
              "    2.  Select a .mid or .midi file\n"
              "    3.  Ghost notes appear immediately as faded shapes\n"
              "    4.  Use the Opacity slider (10–60%) to adjust visibility\n"
              "    5.  Click ✕ to clear the overlay\n\n"
              "  The ghost notes use the same lane color as your main notes but\n"
              "  blended toward the background, so they are readable but clearly\n"
              "  secondary. They scroll and zoom with the piano roll.")
        divider(s)
        entry(s,
              "Markers  (📍 Markers button, right column of the MIDI Editor):\n\n"
              "  Markers are full-height vertical lines that span all lanes. They are\n"
              "  session-only — they clear when you load a new MIDI and are never saved.\n"
              "  Use them to flag positions you want to come back to, mark sections where\n"
              "  notes need to be added, or annotate problem areas while working.\n\n"
              "  Placing markers:\n"
              "    D key — places a marker at the playhead if audio is playing, or at\n"
              "      the last position you clicked on the canvas if not.\n"
              "    Middle-click — click the scroll wheel anywhere on the canvas to place\n"
              "      a marker at that exact position. Snap to grid applies.\n\n"
              "  Each marker shows a small triangle handle in the header strip for\n"
              "  easy clicking and dragging. Labels appear above the line in the header.\n\n"
              "  Selecting and editing:\n"
              "    Click a marker handle to select it.\n"
              "    Ctrl+click to toggle individual markers in/out of selection.\n"
              "    Shift+drag (rubber band) selects markers and notes together —\n"
              "      toggle 'Select with rubber band' off to exclude markers.\n"
              "    Drag a selected marker to move it. Snap to grid applies.\n"
              "    Delete key removes all selected markers (and notes).\n\n"
              "  Marker options:\n"
              "    All / Selected radio — controls whether Color and Label changes\n"
              "      apply to every marker or only the ones currently selected.\n"
              "    Color — 6 swatches: G=Green, R=Red, Y=Yellow,\n"
              "      B=Sky Blue, O=Orange, P=Purple.\n"
              "      New markers inherit the active color.\n"
              "    Label — type a short label and click Set to assign it. The label\n"
              "      appears above the marker line in the header strip. Labels are\n"
              "      most useful when combined with a color — for example:\n"
              "        Red (R) + label 'Snare'  → marks where a snare hit should go\n"
              "        Yellow (Y) + label 'timestamp' → marks an exact position to note\n"
              "        Green (G) + label 'Roll'  → marks where a drum roll should be\n"
              "      This lets you color-code markers by meaning and read them\n"
              "      at a glance without clicking each one.\n"
              "    Select with rubber band — when off, rubber-band select ignores\n"
              "      markers so you can select notes without picking up markers.\n"
              "    Clear All — removes all markers instantly (undoable).")
        warn(s, "Song Tester may report false sync warnings after manual MIDI edits. "
                "This is expected — always confirm timing in-game.")
        divider(s)
        entry(s,
              "Tempo Map — fixing drift from mid-song tempo changes:\n\n"
              "  If a song has a tempo change partway through (common in live recordings\n"
              "  or songs that were not played to a click track), notes will be in sync\n"
              "  at the start but drift increasingly out of sync after the change point.\n"
              "  This is a source limitation — the MIDI was built at a flat BPM that\n"
              "  doesn't match the recording past that point.\n\n"
              "  Finding the new BPM — two methods:\n"
              "    🎵 BPM from Selection — rubber-band select notes in the drifted\n"
              "       section (Shift+drag, 4+ notes), then click the button. The app\n"
              "       analyzes note timing and fills the BPM field automatically.\n"
              "       Most accurate when you have enough notes to analyze.\n\n"
              "    Tap / B key — click the Tap button or press B in time with the beat\n"
              "       while audio plays. Speed compensation is automatic. Useful when\n"
              "       the drifted section has very few notes.\n\n"
              "  If the drift is gradual (a few ms over the whole song), try a slight\n"
              "  BPM tweak in the Song Tester (e.g. 143.0 → 142.8) instead.\n"
              "  The Tempo Map is for hard tempo changes, not gradual drift.")
        s2_lbl = tk.Label(s, justify=tk.LEFT, wraplength=440, fg="#00e5ff",
                          bg="#222222",
                          font=("Segoe UI", 9),
                          text="Step-by-step: Using the Tempo Map\n\n"
                               "1.  Load your MIDI and audio in the MIDI Editor\n\n"
                               "2.  Play through and find where drift starts — notes\n"
                               "    begin landing early or late against the audio.\n"
                               "    Use T key to stamp that timestamp.\n\n"
                               "3.  Click '+ Add Entry' in the Tempo Map section\n\n"
                               "4.  Enter the timestamp from step 2 in the Time field.\n"
                               "    Accepted formats:\n"
                               "      74.0      (seconds)\n"
                               "      1:14      (minutes:seconds)\n"
                               "      1:14.500  (minutes:seconds.milliseconds)\n\n"
                               "5.  Find the new BPM — two methods:\n\n"
                               "    Method A — BPM from Selection (most accurate):\n"
                               "    a.  Rubber-band select (Shift+drag) a group of\n"
                               "        notes in the drifted section (4+ notes)\n"
                               "    b.  Click '🎵 BPM from Selection'\n"
                               "    c.  The app analyzes note timing and fills the\n"
                               "        BPM field of the last entry automatically\n\n"
                               "    Method B — Tap BPM (useful when notes are sparse):\n"
                               "    a.  Seek to just before the drift point\n"
                               "    b.  Press Play — slow down to 0.3x if needed\n"
                               "    c.  Click the 'Tap' button or press B in time\n"
                               "        with the beat for 6–8 beats\n"
                               "        (B always targets the last added entry)\n"
                               "    d.  The BPM field updates live as you tap\n"
                               "    e.  Speed compensation is automatic — tap at\n"
                               "        whatever speed you hear\n"
                               "    f.  Stop tapping — value freezes after 3s\n\n"
                               "6.  Click '⟳ Apply Tempo Map'\n\n"
                               "7.  Play through to verify. If still off, Ctrl+Z,\n"
                               "    adjust the BPM slightly, and re-apply.\n\n"
                               "8.  Repeat steps 3–7 for additional tempo changes.\n\n"
                               "Notes before the first entry are never moved.\n"
                               "Every apply is fully undoable with Ctrl+Z.")
        s2_lbl.pack(anchor="w", padx=4, pady=(4, 0))

        # ══════════════════════════════════════════════════════════════════════
        # RIGHT COLUMN — Problems, Tools & Reference
        # ══════════════════════════════════════════════════════════════════════

        # ── Preview/Practice Track ───────────────────────────────────────────
        s = section("📺  Preview/Practice Track (Tab 11)", right)
        entry(s,
              "Preview subtab — visual reference only:\n"
              "  Load a MIDI file to watch your chart fall exactly as it will in\n"
              "  Paradiddle. No scoring, no input — just a clean visual check.\n\n"
              "Audio fields:\n"
              "  Full Mix Audio — complete song\n"
              "  Drum Audio — drums-only stem for toggling\n"
              "  Toggle button — switches tracks during playback\n\n"
              "Controls:\n"
              "  ▶ / ⏸ / ⏹         — play, pause, stop\n"
              "  Scrubber           — click or drag to seek\n"
              "  Offset (s)          — shift notes earlier/later\n"
              "  ✓ Apply Offset      — redraw after changing offset\n"
              "  ↺ Reload Notes     — re-parse the MIDI\n"
              "  Zoom buttons       — higher = more notes visible\n"
              "  🗑 Clear All       — reset all fields\n\n"
              "Note density bar:\n"
              "  The thin bar above the canvas shows note density as a heatmap.\n"
              "  Click it to seek to that position.")
        note(s,
             "Songs with a drum-free intro: the canvas will be empty for the first few "
             "seconds while the audio plays — this is completely normal. Notes only start "
             "appearing when the first drum hit is due.")
        entry(s,
              "Practice subtab — the NEW Practice mini-game (BETA):\n\n"
              "  This is a separate window that opens when you click 'Launch New "
              "  Practice (BETA)'. It is NOT the same as the in-app Preview canvas.\n\n"
              "What it does:\n"
              "  • Real-time falling notes from your actual chart — timed to the audio\n"
              "  • Keyboard input: A=Hi-Hat, W=Crash, S=Snare, D/F/C=Toms, R=Ride,\n"
              "    Space=Kick (or remap in Controls & Learn Mode)\n"
              "  • MIDI drum-kit input if you have a kit connected (see MIDI Drum Kit\n"
              "    Input section below)\n"
              "  • Hit grading: PERFECT (±35 ms), EARLY / LATE (±75 ms), MISS (>120 ms)\n"
              "  • Live stats: streak, best streak, hits, misses, accuracy, combo counter\n"
              "  • End-of-song results screen with grade letter (S/A/B/C/D), score,\n"
              "    timing histogram, and per-grade breakdown\n"
              "  • Play Again button to restart the chart; Esc or Back to ParaKit to exit\n\n"
              "Window controls:\n"
              "  • Drag the corner to resize (minimum 800×600)\n"
              "  • Alt+Enter or F11 to toggle fullscreen\n"
              "  • Portrait monitors (e.g. 1440×2560) work as a first-class layout\n"
              "  • High-DPI displays render crisply at 125% / 150% / 200% scaling\n\n"
              "Troubleshooting:\n"
              "  If the new Practice window doesn't open:\n"
              "    → Try unchecking 'Use legacy Practice mini-game' in Visual Settings\n"
              "    → Make sure pygame is installed (pip install pygame-ce)\n"
              "    → Check the MIDI Controls dialog if you want to play with a real drum kit")
        warn(s, "The Preview subtab is visual reference only — no scoring. The new Practice "
                "mini-game window adds scoring, keyboard input, MIDI drum-kit input, and a "
                "results screen. Always test on the Quest for the definitive feel.")

        s = section("🎹  MIDI Drum Kit Input (BETA)", right)
        entry(s,
              "Play the Practice Mini-Game with a real e-drum kit. This is a BETA "
              "feature — it works well on recognized kits and most class-compliant "
              "USB MIDI drums, but the layout of your kit's pads may not match "
              "ParaKit's defaults (see Learn Mode below if a pad fires the wrong "
              "lane).\n\n"
              "To use it:\n"
              "  1. Plug your MIDI drum kit into your PC via USB.\n"
              "  2. Go to the Preview/Practice Track tab.\n"
              "  3. Open the Practice subtab — the MIDI panel on the right shows\n"
              "     your connection status and a launcher button for setup.\n"
              "  4. Click 'Open MIDI Controls' (or the MIDI Input button at top).\n"
              "  5. Pick your device from the dropdown.\n"
              "  6. Hit pads on your kit — each strike should pulse the matching\n"
              "     lane's hit indicator in the dialog (cyan = hi-hat, orange =\n"
              "     crash, red = snare, blue/green/purple = toms, gold = ride,\n"
              "     pink = kick).\n"
              "  7. Close the dialog and start Practice — your hits register as\n"
              "     Practice inputs.\n\n"
              "Learn Mode — fixing a wrong-lane pad:\n"
              "  Sometimes a kit sends a different MIDI note than ParaKit expects "
              "for a pad — your hi-hat might fire 'Crash', or your floor tom might "
              "fire 'Snare'. To fix it:\n"
              "  1. Open MIDI Controls.\n"
              "  2. Watch which lane's indicator flashes when you hit the wrong-\n"
              "     mapped pad — that's the lane currently receiving your hit.\n"
              "  3. Click the 🎯 Learn button on the lane you WANT to receive\n"
              "     that pad's hit.\n"
              "  4. Hit the pad on your kit — ParaKit captures that MIDI note as\n"
              "     the new mapping for that lane.\n"
              "  5. The change is saved automatically and survives across\n"
              "     ParaKit restarts.\n"
              "Use the ↺ button on a lane to reset that lane to its default. Use "
              "Reset All Mappings (bottom of dialog) to clear everything.\n\n"
              "Recognized devices (auto-configured):\n"
              "  - Alesis Nitro Pro / Alesis Nitro Mesh\n"
              "  - Akai MPD218\n"
              "  - Akai MPC One / MPC Live II / MPC Studio (firmware 2.11+)\n"
              "  - Akai MPK Mini MK3 (8 pads; toggle between Bank A and\n"
              "    Bank B for full lane coverage)\n"
              "  - Novation Launchpad Mini MK3 / Launchpad X / Launchpad Pro MK3\n"
              "    (press the DRUM button for Drum Mode so the left-half 4x4\n"
              "    grid sends drum-MIDI notes; Mini and X have non-velocity-\n"
              "    sensitive pads — only the Pro MK3 has full velocity sensing)\n"
              "  - Roland TD-17 and most Roland V-Drums\n"
              "  - Most class-compliant USB MIDI drum kits through GM defaults\n\n"
              "Optional: turn on Show Open Hi-Hat as separate lane if you want open "
              "hi-hat hits to appear in their own Practice lane while testing.\n\n"
              "Live recording in the MIDI Editor (BETA):\n"
              "  Connect your MIDI drum kit, open the MIDI Editor with a song's "
              "audio loaded, then press the new ● Record button. ParaKit plays "
              "a 1-bar count-in (4 metronome clicks) so you can get ready, then "
              "starts the song while recording your drum hits onto the chart.\n\n"
              "  While recording, each drum hit becomes a new note in the matching "
              "lane. Stop recording with the ■ Stop button, or let the song finish. "
              "The full take can be undone with Ctrl+Z.\n\n"
              "  Count-in toggle: ON by default. Turn it off if you want recording "
              "to start as soon as you press Record.\n\n"
              "  Metronome sound: choose Wood block, Cowbell, Rim shot, High blip, "
              "or Procedural sine. Click ▶ Test to hear the selected sound once.\n\n"
              "  Recording timing off? Open MIDI Input (BETA) and adjust MIDI "
              "input offset. Negative values move recorded notes earlier; positive "
              "values move them later.\n\n"
              "Snap to Grid and recordings:\n"
              "  If Snap to Grid is on in the MIDI Editor toolbar, your recorded hits "
              "will snap to the nearest grid line (or to a nearby existing note if "
              "note-snap mode is also on). Turn snap off in the editor toolbar before "
              "recording if you want exact human timing.\n\n"
              "Why BETA: the core MIDI routing is solid, but Learn Mode is new, "
              "device-profile coverage is still expanding, and some advanced "
              "features like per-velocity calibration are still planned for later.")

        # ── Sheet Music → MIDI ────────────────────────────────────────────────
        s = section("🎼  Sheet Music → MIDI (Tab 7)", right)
        entry(s,
              "Converts a MusicXML drum chart into a Paradiddle-ready MIDI file.\n"
              "Unlike Audio → MIDI detection, the result is 1:1 accurate — every note\n"
              "comes directly from the sheet music with no guesswork.\n\n"
              "Does my file need to be drums-only?\n"
              "  No. Full band scores work fine — ParaKit finds the drum part\n"
              "  automatically and ignores everything else.\n\n"
              "When to use this instead of Audio → MIDI:\n"
              "  • You have sheet music for the song — result will be note-perfect\n"
              "  • You wrote your own drum part and want to chart it\n"
              "  • Audio → MIDI gave poor results and sheet music is available\n\n"
              "File types — there is no quality difference between them:\n"
              "  .mxl      — compressed MusicXML. This is what MuseScore.com gives you.\n"
              "              Load it directly into ParaKit — no conversion needed.\n"
              "  .xml      — uncompressed MusicXML. What you get when exporting from\n"
              "              notation software (MuseScore desktop, Guitar Pro, Sibelius).\n"
              "  .musicxml — same as .xml, different extension. All three formats work.\n\n"
              "How to get a MusicXML file:\n"
              "  • From MuseScore.com — use the search in this tab, download the .mxl,\n"
              "    load it here directly. Many files require a Pro subscription (~$39.99/yr).\n"
              "    Free scores are available and marked on the site.\n"
              "  • From MuseScore desktop — File → Export → MusicXML\n"
              "  • From Guitar Pro, Sibelius, Finale, Noteflight — File → Export → MusicXML")
        entry(s,
              "Conversion Quality — which mode to use:\n\n"
              "  High accuracy (recommended, uses music21 library)\n"
              "    Correctly handles: songs with multiple tempo changes, complex drum\n"
              "    patterns, and full band scores with many instruments. This is almost\n"
              "    always what you want. music21 must be installed for this to work —\n"
              "    a status indicator in the tab tells you if it is available.\n\n"
              "  Basic (fallback, built-in XML parser)\n"
              "    Use if High accuracy gives unexpected results. Works reliably for\n"
              "    simple drum-only files with a single fixed tempo. Does not require\n"
              "    any additional libraries.")
        entry(s,
              "Instrument name correction — automatic:\n\n"
              "  MuseScore writes instrument names in the user's language (English, French,\n"
              "  German, Spanish, Italian, Portuguese, Dutch, Polish, and others). Some\n"
              "  transcribers also accidentally assign the wrong MIDI note number to a\n"
              "  correctly-named instrument (e.g. a kick drum labeled 'Bass Drum 1' but\n"
              "  stored as MIDI note 37 instead of 36).\n\n"
              "  ParaKit automatically reads the instrument name from the file and\n"
              "  corrects any wrong note numbers before converting. The log shows every\n"
              "  correction made and what was changed. You do not need to do anything —\n"
              "  this happens automatically on every conversion.")
        divider(s)
        entry(s,
              "Audio Offset — syncing sheet music to your audio:\n\n"
              "  Sheet music always starts at beat 1, measure 1 — but your audio may\n"
              "  have an intro before the drums come in. Without an offset, the MIDI\n"
              "  will be musically correct but out of sync with the audio in-game.\n\n"
              "  How to find and set your offset:\n"
              "    1.  Open the MIDI Editor (Tab 6) and load your drums-only stem\n"
              "        in the Playback Audio — Drums Only field\n"
              "    2.  Look at the waveform strip below the piano roll — the first\n"
              "        spike is your first drum hit. Click near it to seek there.\n"
              "    3.  Slow to 0.3x, or pause near the spike\n"
              "    4.  Press T at the moment you hear the hit — or while paused\n"
              "        at that position. The Drum start offset field updates automatically.\n"
              "    5.  Switch to the Sheet Music tab and re-convert, or hit Apply Offset to All Notes in the MIDI Editor — done\n\n"
              "  Auto-align (on by default):\n"
              "    Ensures the offset value you enter is accurate by accounting for\n"
              "    the sheet music's own internal start time. Without it, entering\n"
              "    37.740 might result in the note landing at 38.412 instead. Leave\n"
              "    this on unless you specifically need raw tick-level control.\n\n"
              "  Use ±10ms / ±100ms nudge buttons to fine-tune after converting.\n\n"
              "  Negative values — if the sheet music has a count-in:\n"
              "    Some sheet music includes a count-in bar or pickup notes before\n"
              "    the song actually starts. If your audio doesn't have that count-in,\n"
              "    those extra notes will land before the audio begins — sounding wrong.\n"
              "    Enter a negative offset to pull all notes back by that amount.\n\n"
              "    To find the right negative value: figure out how long the count-in\n"
              "    is in seconds. For example, if the sheet music has 1 bar of count-in\n"
              "    at 120 BPM in 4/4 time, that bar lasts 2 seconds — so enter -2.000.\n"
              "    At 145 BPM, 1 bar of 4/4 = 60 ÷ 145 × 4 ≈ 1.655 → enter -1.655.\n"
              "    The BPM is shown in the log after converting.")
        divider(s)
        entry(s,
              "Drum Part selector — for files with multiple parts:\n\n"
              "  ParaKit automatically detects the drum part in full band scores.\n"
              "  If it picks the wrong one, click '⚙ Advanced' to expand the options,\n"
              "  then click '🔍 Scan File' to read all parts from the file and choose\n"
              "  the correct one from the dropdown. This is rarely needed — auto-detect\n"
              "  works correctly for the vast majority of files.\n\n"
              "Advanced overrides — BPM and time signature:\n\n"
              "  These only need to be used if the file has no tempo marking, or if the\n"
              "  tempo stored in the file is wrong (e.g. the file says 60 BPM but the\n"
              "  song is actually 120 BPM). Leave both blank to use values from the file.\n"
              "  Overriding these values does NOT stretch or shift notes — it only changes\n"
              "  how the MIDI header is written.")
        divider(s)
        entry(s,
              "What to check in the log after every conversion:\n\n"
              "  ✓  Note counts per instrument — does the number of kicks, snares,\n"
              "      hi-hats, and crashes look believable for this song? A rock or\n"
              "      metal song with zero kicks or 2 crashes is almost certainly wrong.\n\n"
              "  ℹ  'X corrected by name' — ParaKit fixed wrong note numbers using\n"
              "      instrument names. The corrected entries are listed with what changed.\n\n"
              "  ℹ  Remapped notes — drum sounds auto-converted to a nearby equivalent\n"
              "      (e.g. tambourine → hi-hat). Check these make sense for your song.\n\n"
              "  ⚠  Dropped notes — no Paradiddle equivalent exists. Add manually in\n"
              "      the MIDI Editor if the sound was important.\n\n"
              "  ⚠  Transcription quality warnings — ParaKit flags suspicious patterns\n"
              "      like zero kicks in a 100-note chart, or an unusually high rim click\n"
              "      count. These mean the original sheet music transcriber made errors.\n"
              "      Use the MIDI Editor to reclassify the affected lanes.")
        divider(s)
        note(s, "If the log shows 0 notes parsed: the drum staff in your file may not "
                "be set to a Percussion instrument in the notation software. Open the "
                "file in MuseScore desktop, check that the drum staff instrument type "
                "is set to Drumset or Percussion (not a pitched instrument like piano), "
                "re-export as MusicXML, and try again.")
        divider(s)
        note(s, "Transcription errors on MuseScore.com are common. If the note counts "
                "in the log look wrong (e.g. zero kicks, 2 crashes in a crash-heavy song), "
                "the original transcriber made mistakes in the sheet music. ParaKit corrects "
                "as many as it can automatically using instrument names. Remaining issues "
                "must be fixed in the MIDI Editor using Reclassify mode — select all notes "
                "in the wrong lane, right-click, choose the correct instrument.")
        divider(s)
        warn(s, "Audio sync is your responsibility. This converter reads what is written "
                "in the sheet music — it has no knowledge of your audio file. If the sheet "
                "music tempo does not exactly match your recording, or the audio has an intro "
                "the sheet music does not account for, notes will be out of sync in-game. "
                "Always use the Audio Offset field for intros, then run the Song Tester "
                "(Tab 10) to verify BPM and fine-tune offset before creating your .rlrr file.")

        # ── Common Problems ───────────────────────────────────────────────────
        s = section("▶  YouTube → FLAC (Tab 8)", right)
        entry(s,
              "Downloads audio from YouTube and converts it to FLAC.\n"
              "FLAC is the recommended format for the Stem Splitter — lossless quality\n"
              "and significantly better results than MP3 or .ogg as input.\n\n"
              "Requirements:\n"
              "  yt-dlp.exe must be placed next to ParaKit.exe or in Requirements\\.\n"
              "  Download it free from: https://github.com/yt-dlp/yt-dlp/releases/latest\n"
              "  ffmpeg.exe must also be present next to ParaKit.exe or in Requirements\\\n"
              "  (it ships with ParaKit).\n\n"
              "How to use:\n"
              "  1.  Paste a YouTube URL into the URL field\n"
              "  2.  Choose an output folder\n"
              "  3.  Select format (FLAC recommended)\n"
              "  4.  Optional: tick 'Name file other than video title' if you\n"
              "      want to type your own filename instead of the YouTube\n"
              "      title. The .flac or .wav extension is added for you,\n"
              "      so just type the name. Invalid characters (< > : \" / \\\n"
              "      | ? *) are replaced with underscores automatically so\n"
              "      Windows can save the file.\n"
              "  5.  Leave 'Auto-update yt-dlp' checked — YouTube occasionally\n"
              "      changes its API and yt-dlp needs to update to stay compatible\n"
              "  6.  Click Download & Convert\n"
              "  7.  The log shows progress and the final file location\n\n"
              "Formats:\n"
              "  FLAC — lossless, best quality for Stem Splitter input (~30MB/song)\n"
              "  WAV  — uncompressed, same quality as FLAC but much larger files")
        entry(s,
              "New in v4.4.61-1 — Send to Stem Splitter + Downloaded Songs library:\n"
              "  - After a download finishes, click 'Send to Stem Splitter' to\n"
              "    load that file into the Stem Splitter and jump straight there.\n"
              "  - The Downloaded Songs library (left of the log) lists every\n"
              "    song you've downloaded, with cover art, format, duration, and\n"
              "    badges for STEMS (split yet?) and MIDI (converted yet?). Click\n"
              "    a song to Send it to the Stem Splitter, or Open its stems\n"
              "    folder once it has been split. Search and sort are at the top;\n"
              "    the list persists between sessions.\n"
              "  - The Stem Splitter now warns before re-splitting a song you've\n"
              "    already split, so you don't overwrite stems by accident (with\n"
              "    a 'don't show this again' option).\n"
              "  - (v4.4.62-1) Each song has a Play/Pause button that previews the\n"
              "    whole track (no time limit); it stops when you leave this tab.")
        warn(s,
             "Only download content you have the legal right to use.\n"
             "Downloading copyrighted audio without permission may violate YouTube's\n"
             "Terms of Service and applicable copyright law. Age-restricted and\n"
             "private videos cannot be downloaded.  (I won't tell if you won't)")
        tip(s,
            "If the download fails with an error about 'Sign in to confirm your age'\n"
            "or 'Video unavailable', the video is restricted. Try a different source.\n"
            "If it fails with 'ERROR: ...' after updating yt-dlp, YouTube may have\n"
            "changed their API again — check yt-dlp's GitHub for a newer release.")
        divider(s)

        s = section("🎨  Asset Manager (Tab 9)", right)
        entry(s,
              "Auto-Fetch Metadata:\n"
              "  Searches MusicBrainz for song title, artist, and album,\n"
              "  and iTunes for album artwork.\n\n"
              "  How to use:\n"
              "    1.  Type artist and song name (e.g. 'Duality Slipknot')\n"
              "    2.  Click 🔍 Fetch Metadata\n"
              "    3.  Review the result and art thumbnail\n"
              "    4.  Click ✓ Apply Metadata to Song Creator to fill Title and\n"
              "        Artist, and/or 🖼 Apply art from thumbnail to Song Creator\n"
              "        to set just the Cover Image path. Each button is\n"
              "        independent so you can apply one without the other.\n"
              "    5.  (Optional) Click 💾 Save Image... to save the fetched\n"
              "        cover art to disk as .jpg or .png. Pick the format from\n"
              "        the Save As dialog's file-type dropdown. The default\n"
              "        folder is 'ALBUM ART ASSETS' next to ParaKit (created\n"
              "        automatically the first time you save into it), and the\n"
              "        default filename is built from the fetched artist and\n"
              "        title — both editable before saving.\n\n"
              "  MusicBrainz provides title/artist/album.\n"
              "  iTunes provides the cover art image (600×600 JPG).\n"
              "  Internet connection required. Works for most major releases.\n"
              "  Obscure or unlicensed music may return no results.\n\n"
              "Album Art Cropper:\n"
              "  Paradiddle requires album art in a perfect 1:1 square ratio.\n"
              "  This tool crops any image to a centered square and resizes it.\n\n"
              "  How to use:\n"
              "    1.  Browse to your image (PNG, JPG, WEBP, BMP supported)\n"
              "    2.  Choose a save location\n"
              "    3.  Select output size (512×512 recommended for Paradiddle)\n"
              "    4.  Click ✂ Crop to Square\n\n"
              "  The crop is always centered — equal amounts removed from each side.\n"
              "  If your art already has a square subject off-center, crop manually\n"
              "  in an image editor first, then use this to resize.\n\n"
              "Preview Audio Trimmer:\n"
              "  Paradiddle uses a short .ogg clip (~15 seconds) for the song\n"
              "  selection menu preview. This tool trims any point of your audio.\n\n"
              "  How to use:\n"
              "    1.  Browse to your audio file (any format)\n"
              "    2.  Choose a save location (.ogg)\n"
              "    3.  Set Start (seconds from beginning) and Duration\n"
              "    4.  Click ✂ Trim & Export as .ogg\n\n"
              "  Tip: Pick a memorable hook — chorus or a distinctive fill.\n"
              "  Avoid starting at 0.0 if the song has a quiet intro.\n"
              "  15 seconds is the standard Paradiddle preview length.")
        divider(s)

        s = section("📲  Push to Quest (ADB)", right)
        entry(s,
              "The 📲 Push to Quest button in the Song Creator sends your\n"
              "converted .rlrr folder directly to a connected Meta Quest\n"
              "over USB — no SideQuest or file manager needed.\n\n"
              "Files included in the ParaKit zip:\n"
              "  adb.exe, AdbWinApi.dll, AdbWinUsbApi.dll\n"
              "  All three must be together in one of these locations:\n"
              "    - inside Requirements\\platform-tools\\ (recommended), or\n"
              "    - directly inside Requirements\\ (flat), or\n"
              "    - directly next to ParaKit.exe (legacy layout).\n"
              "  Manual download: https://developer.android.com/tools/releases/platform-tools\n\n"
              "Quest setup (one-time):\n"
              "  1.  Enable Developer Mode on your Quest:\n"
              "      Meta app → Menu → Devices → [headset] → Developer Mode → On\n"
              "  2.  Plug Quest into PC via USB cable\n"
              "  3.  Put on the headset — a dialog will appear asking to allow\n"
              "      USB debugging from your PC. Click Allow.\n\n"
              "How to use:\n"
              "  1.  Convert your song in Song Creator\n"
              "  2.  Keep the Quest plugged in and awake\n"
              "  3.  Click 📲 Push to Quest\n"
              "  4.  The song appears in Paradiddle → Custom Songs immediately\n\n"
              "  If no Quest is detected, check the USB cable and that you\n"
              "  accepted the USB debugging prompt inside the headset.\n"
              "  If push fails with a permissions error, the Quest Songs folder\n"
              "  path may have changed — check ParadiddleDB for the current path.")
        divider(s)

        s = section("🔧  Common Problems & Fixes", right)
        entry(s, "Notes out of sync in-game\n"
                 "  → Run the Song Tester for recommended BPM and offset.\n"
                 "  → Use 'Use BPM from MIDI file' in Song Creator if MIDI was\n"
                 "    generated by this app.\n"
                 "  → Use backing track (no drums) as Song Audio when you also\n"
                 "    have a separate drum audio file.\n"
                 "  → Convert audio to .ogg — MP3 can cause sync drift.\n"
                 "  → If BPM seems half or double, try ×2 or ÷2.\n"
                 "  → If notes feel slightly early consistently even after offset\n"
                 "    correction, try Peak Detection Interval (5–15ms) in Advanced/Debug\n"
                 "    and regenerate.")
        divider(s)
        entry(s, "Too many crashes / not enough hi-hats\n"
                 "  → Enable Ride Cymbal Detection if the song uses ride and regenerate.\n"
                 "  → Delete excess crashes manually in the MIDI Editor.")
        divider(s)
        entry(s, "Three notes on the same beat\n"
                 "  → Physically impossible on a real kit — remove the least likely one.\n"
                 "  → Listen at that timestamp. Keep crash if there's a clear accent;\n"
                 "    otherwise keep hi-hat and remove the crash.")
        divider(s)
        entry(s, "Kicks missing or too many false kicks\n"
                 "  → Kick detection is on by default, ~90% accurate for most songs.\n"
                 "  → Too many false kicks: disable kick detection and regenerate,\n"
                 "    then add kicks manually, or use Reclassify mode to fix them.\n"
                 "  → Kicks missing: check that kick detection is enabled in Audio → MIDI.")
        divider(s)
        entry(s, "Rapid snare/tom roll — only first hit shows, rest are hi-hats/crashes\n"
                 "  → The timing of those cymbal notes is already correct.\n"
                 "  → Use Reclassify mode to change them to the right instrument.\n"
                 "  → Or lower the Snare/Tom dedup gap and regenerate.")
        divider(s)
        entry(s, "Not enough snares\n"
                 "  → Try Metal / Hard Rock / Post-Hardcore genre if it's a heavy song.\n"
                 "  → Lower Onset Sensitivity slightly.\n"
                 "  → Add missing snares manually on beats 2 and 4.")
        divider(s)
        entry(s, "Song doesn't appear in Paradiddle\n"
                 "  → Almost always a missing cover image. Open the .rlrr in Notepad,\n"
                 "    find 'coverImagePath' and set it to \"\". Re-copy the folder.\n"
                 "  → Verify the folder is in the correct Songs directory.")
        divider(s)
        entry(s, "Stem Splitter is slow\n"
                 "  → GPU acceleration requires an NVIDIA CUDA GPU. GTX 10-series through\n"
                 "    RTX 40-series work on a standard CUDA PyTorch build; RTX 50-series\n"
                 "    (Blackwell) needs a CUDA 12.8+ (cu128) PyTorch build.\n"
                 "    AMD and Intel GPUs always run on CPU — a Demucs limitation, not a\n"
                 "    ParaKit bug.\n"
                 "  → Use htdemucs (not htdemucs_ft) for faster splits.")
        divider(s)
        entry(s, "Drag and drop not working\n"
                 "  → Browse buttons always work as a fallback.\n"
                 "  → If drag and drop is consistently unavailable, try reinstalling ParaKit.")
        entry(s, "Push to Quest failed — 'No Quest Found'\n"
                 "  → Check that adb.exe (with its .dll files) is in one of the\n"
                 "    supported locations: next to ParaKit.exe, inside\n"
                 "    Requirements\\platform-tools\\, or directly inside Requirements\\.\n"
                 "  → Plug Quest in via USB and put on the headset — accept the\n"
                 "    USB debugging prompt that appears inside the headset.\n"
                 "  → Enable Developer Mode in the Meta app on your phone first.")
        entry(s, "App crashed and disappeared\n"
                 "  → A crash report file (parakit_crash.txt) and debug log\n"
                 "    (parakit_debug.log) are saved next to ParaKit.exe automatically.\n"
                 "  → Send parakit_crash.txt when reporting the issue.")
        entry(s, "Zip output is empty or missing files\n"
                 "  → Make sure the song converted successfully before the zip runs.\n"
                 "  → Check the Zip To folder exists and you have write permissions.\n"
                 "  → Leave Zip To blank to save the zip next to the output folder.")

        # ── Song Tester ───────────────────────────────────────────────────────
        s = section("🔬  Song Tester", right)
        entry(s,
              "The Song Tester checks BPM and offset alignment before you convert.\n\n"
              "Load MIDI and audio (and optionally .rlrr for the most accurate test), "
              "then run the analysis. It will recommend BPM and offset values and "
              "flag specific issues with explanations.\n\n"
              "Ratings:\n"
              "  ✓ EXCELLENT — ready to convert\n"
              "  ⚠ GOOD      — minor issue flagged, likely fine in-game\n"
              "  ✗ NEEDS WORK — specific problems listed with fix instructions\n\n"
              "Use 'Send to Preview/Practice Track' from the tester adjuster panel to carry "
              "your corrected BPM and offset directly to the visualizer.")
        divider(s)
        warn(s, "The tester may flag false warnings after manual MIDI edits — it cannot "
                "account for changes you made by hand. If it flags something after you "
                "fixed it manually, trust your ears and test on the Quest.")
        divider(s)
        tip(s, "Load the .rlrr file in the tester (not just the MIDI) for the most "
               "accurate alignment check — the .rlrr is what Paradiddle actually reads.")

        # ── General Tips ──────────────────────────────────────────────────────
        s = section("💡  General Tips", right)
        tip(s, "Always convert audio to .ogg before use. MP3 can cause sync drift in "
               "Paradiddle due to encoding header variations. Use YouTube → FLAC (Tab 8) "
               "or download from Bandcamp for the best lossless source.")
        divider(s)
        tip(s, "For Audio → MIDI, always run Stem Splitter first to get a drums-only stem, "
               "then use Hybrid detection mode on that stem. Hybrid gives the best results "
               "of any mode — it runs ML and Spectral in parallel and picks the best hits.")
        divider(s)
        tip(s, "After Audio → MIDI finishes, click Review Issues (🔍) before editing. "
               "It flags likely duplicates, low-confidence hits, and cymbal problems in one "
               "scan — faster than finding them manually.")
        divider(s)
        tip(s, "Ride hits detected by the ML model appear in the Crash lane — this is expected. "
               "The timing is already correct. Use Reclassify mode in the MIDI Editor to move "
               "them: drag the note up/down to the Ride lane, or click to pick from a list.")
        divider(s)
        tip(s, "External MIDI files from a repository will almost always give better results "
               "than Audio → MIDI. MuseScore.com often has community drum sheets — download "
               "as .mxl and use Sheet Music → MIDI (Tab 7) for near-perfect accuracy.")
        divider(s)
        tip(s, "If auto-detected BPM seems wrong, it is often exactly half or double "
               "the correct value. Try ×2 or ÷2 first before adjusting manually. "
               "Use the B key while playing to tap-correct the BPM, and T to tap the "
               "audio offset for sync alignment.")
        divider(s)
        tip(s, "A missing cover image silently prevents Paradiddle from loading the song. "
               "Make sure the image file is in the output folder. Use Asset Manager (Tab 9) "
               "to auto-fetch art and crop it to the required 1:1 square ratio. "
               "Or, in Song Creator, enable 'Use album art from audio file metadata' to "
               "auto-extract embedded cover art from FLAC, MP3, OGG, or M4A files.")
        divider(s)
        tip(s, "Use DrumSep in the Stem Splitter to separate a drums-only stem into "
               "individual kick, snare, cymbal, and tom tracks. Load each into a MIDI Editor "
               "stem slot — the kick stem shows only kick transients, making per-lane note "
               "placement much more precise.")
        divider(s)
        tip(s, "Use BPM from MIDI file in the Song Creator when your MIDI was generated "
               "by this app. Avoids a second BPM detection pass and preserves tempo map accuracy.")
        divider(s)
        tip(s, "Snap to Grid keeps notes on 16th-note positions. Turn it off for triplets "
               "or fast fills. Snap to Notes (Display & Snap panel) aligns across lanes — "
               "useful for placing a snare exactly on a kick, or a tom on a crash.")

        # ── Layout Mode (1080p / 1440p) ──────────────────────────────────────
        s = section("🖥  Layout Mode (1080p / 1440p)", right)
        entry(s,
              "What it does\n"
              "  - Switches ParaKit's chrome — header, tabs, buttons, and helper\n"
              "    text — between a roomy layout for larger monitors and a compact\n"
              "    layout for smaller ones (especially 1920×1080 panels).\n"
              "  - Compact layout uses a smaller logo, smaller wordmark, tighter\n"
              "    padding, and a shorter help line so the MIDI Editor piano roll,\n"
              "    Velocity Lane, and other canvas-heavy tabs have more room.\n\n"
              "Where to change it\n"
              "  - Tools menu > Layout Mode (1080p / 1440p). Three options:\n"
              "      Auto (detect monitor size)   - default; ParaKit picks based\n"
              "                                     on the monitor's work area.\n"
              "      Compact (1080p / smaller)    - force the compact layout.\n"
              "      Roomy (1440p / larger)       - force the roomy layout.\n"
              "  - Selection is saved and takes effect on next launch.\n\n"
              "When to use which\n"
              "  - On a 1080p (or smaller) monitor where the MIDI Editor canvas\n"
              "    feels squeezed or the Velocity Lane is cut off the bottom of\n"
              "    the window, pick Compact.\n"
              "  - On a 1440p (or larger) monitor where the layout already has\n"
              "    plenty of breathing room, pick Roomy (or leave on Auto).\n"
              "  - On multi-monitor setups, auto-detect may pick the wrong\n"
              "    monitor when ParaKit starts on one screen and is later moved\n"
              "    to another — use the manual Compact / Roomy override in that\n"
              "    case instead of relying on Auto.")

        # ── Paradiddle Note Mapping ───────────────────────────────────────────
        s = section("🥁  Paradiddle MIDI Note Mapping", right)
        entry(s,
              "MIDI 35/36   Kick Drum\n"
              "MIDI 37      Rim Click / Side Stick\n"
              "MIDI 38/40   Snare Drum\n"
              "MIDI 41/43   Floor Tom\n"
              "MIDI 42/44   Closed / Pedal Hi-Hat\n"
              "MIDI 45/47   Low Tom\n"
              "MIDI 46      Open Hi-Hat\n"
              "MIDI 48/50   Mid Tom\n"
              "MIDI 49/55   Crash / Splash Cymbal\n"
              "MIDI 51/53   Ride Cymbal / Bell\n"
              "MIDI 57      Crash Cymbal (17\")\n"
              "MIDI 59      Ride Cymbal (20\")\n\n"
              "Notes not in this list are silently ignored during conversion.")

        # ── Detection Troubleshooter ──────────────────────────────────────────
        s = section("🔬  Detection Troubleshooter", right, expanded=True,
                    summary="Paste your Audio→MIDI log + check symptoms for targeted setting suggestions.",
                    badge="New!")

        note(s, "How to use: Before converting, enable 'Show diagnostic log' in the Audio→MIDI tab — "
                "this gives the troubleshooter the detailed detection numbers it needs for accurate suggestions. "
                "Run Audio→MIDI on your song, then go to the log panel at the bottom of that tab. "
                "Select all and copy directly (Ctrl+A then Ctrl+C inside the log box), or click 'Export Log' to save it first. "
                "Paste the log below, check every box that describes your result, then click Analyze. "
                "The troubleshooter reads your actual detection numbers and gives you specific "
                "settings to try — not generic advice.\n\n"
                "Workflow tip: use the Troubleshooter when detection quality is wrong (too many or too few hits) — "
                "adjust settings here, then Re-run ML in the MIDI Editor. "
                "Once detection looks right, use Review Issues (MIDI Editor toolbar) to clean up "
                "the resulting file: remove duplicates, reclassify wrong lanes, filter quiet phantom hits.")

        entry(s, "Paste your Audio→MIDI log here:")

        dt_log_box = scrolledtext.ScrolledText(
            s, height=7, bg="#0d1117", fg="#58a6ff",
            insertbackground="#ffffff", relief="flat",
            font=("Consolas", 8), wrap=tk.WORD)
        dt_log_box.pack(fill=tk.X, pady=(2, 8))
        _bind_textbox_mousewheel(dt_log_box)

        entry(s, "What went wrong?  (check all that apply)")

        sym_frame = tk.Frame(s, bg="#222222")
        sym_frame.pack(fill=tk.X, pady=(4, 0))
        sym_frame.columnconfigure(0, weight=1)
        sym_frame.columnconfigure(1, weight=1)

        _sym_defs = [
            ("too_many_kicks",     "Too many kick hits"),
            ("too_few_kicks",      "Not enough kick hits"),
            ("too_many_snares",    "Too many snare hits"),
            ("too_few_snares",     "Not enough snare hits"),
            ("too_many_hihats",    "Too many hi-hat hits"),
            ("too_few_hihats",     "Not enough hi-hat hits"),
            ("too_many_crashes",   "Too many crash hits"),
            ("too_few_crashes",    "Not enough crash hits"),
            ("lots_of_duplicates", "Lots of duplicate / stacked hits"),
            ("cymbal_misclass",    "Cymbals misclassified (crash/hi-hat/ride)"),
            ("snare_tom_misclass", "Snares/toms/kicks misclassified"),
            ("timing_messy",       "Timing feels off or messy"),
            ("dense_overdetect",   "Dense sections are over-detected"),
            ("fast_underdetect",   "Fast fills are under-detected"),
        ]
        sym_vars = {}
        for i, (key, label) in enumerate(_sym_defs):
            var = tk.BooleanVar(value=False)
            sym_vars[key] = var
            row, col = divmod(i, 2)
            tk.Checkbutton(
                sym_frame, text=label, variable=var,
                bg="#222222", fg="#c0c0d0", selectcolor="#0d1117",
                activeforeground="#ffffff", activebackground="#222222",
                font=("Segoe UI", 9), anchor="w"
            ).grid(row=row, column=col, sticky="w", pady=1, padx=(0, 8))

        dt_btn_row = ttk.Frame(s)
        dt_btn_row.pack(fill=tk.X, pady=(10, 4))

        dt_out = scrolledtext.ScrolledText(
            s, height=12, bg="#0d1117", fg="#c0c0d0",
            relief="flat", font=("Consolas", 8),
            wrap=tk.WORD, state="disabled")
        dt_out.pack(fill=tk.X, pady=(4, 0))
        _bind_textbox_mousewheel(dt_out)

        # Pending actionable setting changes populated by _dt_analyze, consumed by popup
        _dt_actions      = []   # list of {"label", "detail", "fn"}  — Audio→MIDI setting tweaks
        _dt_flag_actions = []   # list of {"label", "detail", "fn"}  — MIDI Editor flag actions

        def _dt_clear():
            dt_log_box.delete("1.0", tk.END)
            for var in sym_vars.values():
                var.set(False)
            dt_out.configure(state="normal")
            dt_out.delete("1.0", tk.END)
            dt_out.configure(state="disabled")
            _dt_actions.clear()
            _dt_flag_actions.clear()
            _dt_apply_btn.configure(state="disabled")

        def _dt_apply_global_dedup(new_val_ms):
            """Apply a global dedup change and persist it as the active default."""
            new_val = float(new_val_ms)
            self.a2m_dedup_global_var.set(new_val)
            if hasattr(self, '_a2m_global_dedup_lbl'):
                self._a2m_global_dedup_lbl.configure(text=f"{new_val:.0f} ms")
            mode = "hybrid" if getattr(self, "a2m_engine_var", tk.StringVar(value="spectral")).get() == "hybrid" else "spectral"
            if hasattr(self, '_a2m_dedup_stored'):
                self._a2m_dedup_stored[mode]["global"] = new_val
            self._a2m_persist_current_settings()

        def _dt_apply_setting_dedup(inst_key, new_val_ms):
            """Apply a dedup gap change to the correct variable and update its label."""
            new_val = float(new_val_ms)
            if hasattr(self, '_a2m_dedup_per_vars') and inst_key in self._a2m_dedup_per_vars:
                if hasattr(self, 'a2m_dedup_per_inst_var'):
                    self.a2m_dedup_per_inst_var.set(True)
                try:
                    self._a2m_toggle_per_inst_dedup()
                except Exception:
                    pass
                self._a2m_dedup_per_vars[inst_key].set(new_val)
                if hasattr(self, '_a2m_dedup_per_lbls') and inst_key in self._a2m_dedup_per_lbls:
                    self._a2m_dedup_per_lbls[inst_key].configure(text=f"{new_val:.0f} ms")
                # Also persist to stored dict so it survives mode switches
                mode = "hybrid" if getattr(self, "a2m_engine_var", tk.StringVar(value="spectral")).get() == "hybrid" else "spectral"
                if hasattr(self, '_a2m_dedup_stored'):
                    self._a2m_dedup_stored[mode][inst_key] = new_val
            else:
                _dt_apply_global_dedup(new_val)
                return
            self._a2m_persist_current_settings()

        def _dt_analyze():
            import re as _re
            log = dt_log_box.get("1.0", tk.END)

            # ── Parse engine ──────────────────────────────────────────────
            engine = "spectral"
            if "Hybrid (ML + Spectral)" in log:
                engine = "hybrid"
            elif "ML / ONNX (pure)" in log or "Detection Engine: ML" in log:
                engine = "ml"

            # ── Parse scalars ─────────────────────────────────────────────
            def _num(pattern, cast=float, flags=0):
                m = _re.search(pattern, log, flags)
                return cast(m.group(1)) if m else None

            ml_thresh   = _num(r"ML confidence threshold:\s*([\d.]+)")
            bpm         = _num(r"Detected BPM:\s*([\d.]+)")
            dedup_gap   = _num(r"Dedup gap:\s*(\d+)ms", cast=int)
            genre_match = _re.search(r"Genre:\s*(.+)", log)
            genre       = genre_match.group(1).strip() if genre_match else None

            # ── Parse pre-dedup totals ────────────────────────────────────
            totals = {}
            for key, pat in [
                ("kick",      r"Kick:\s+(\d+)"),
                ("snare",     r"Snare:\s+(\d+)"),
                ("hihat",     r"Hi-hat:\s+(\d+)"),
                ("crash",     r"Crash:\s+(\d+)"),
                ("floor_tom", r"Floor tom:\s+(\d+)"),
                ("tom",       r"Toms?:\s+(\d+)"),
                ("ride",      r"Ride:\s+(\d+)"),
            ]:
                v = _num(pat, cast=int)
                if v is not None:
                    totals[key] = v

            # ── Parse Hybrid spectral→merged jumps ────────────────────────
            hybrid_jumps = {}
            for inst in ("Kick", "Snare", "HiHat", "Crash"):
                m = _re.search(
                    rf"{inst}\s*:\s*spectral=\s*(\d+).*?merged=\s*(\d+).*?\(\+(\d+)\s*net ML"
                    rf".*?conf<[\d.]+:\s*(\d+),\s*spacing:\s*(\d+)",
                    log, _re.IGNORECASE | _re.DOTALL)
                if m:
                    hybrid_jumps[inst.lower()] = {
                        "spectral":  int(m.group(1)),
                        "merged":    int(m.group(2)),
                        "ml_added":  int(m.group(3)),
                        "low_conf":  int(m.group(4)),
                        "spacing":   int(m.group(5)),
                    }

            # ── Build suggestions + actionable changes ────────────────────
            suggestions  = []   # (priority, text)
            actions      = []   # {"label", "detail", "fn"}
            flag_actions = []   # {"label", "detail", "fn"}  — MIDI Editor flag actions
            checked      = {k for k, v in sym_vars.items() if v.get()}

            def _add(priority, text):
                suggestions.append((priority, text))

            def _act(label, detail, fn):
                actions.append({"label": label, "detail": detail, "fn": fn})

            def _flg(label, detail, fn):
                flag_actions.append({"label": label, "detail": detail, "fn": fn})

            # ── MIDI Editor flag helpers ──────────────────────────────────
            def _flag_notes_in_lanes(lane_indices):
                """Flag all notes in given lane(s) as dt_review → orange outline."""
                if not getattr(self, "me_notes", None):
                    messagebox.showinfo("No MIDI File",
                        "Open a MIDI file in the MIDI Editor first, then rerun the troubleshooter.",
                        parent=self.root)
                    return
                flagged_dict = getattr(self, "me_flagged", {})
                count = 0
                for note in self.me_notes:
                    if note["lane_idx"] in lane_indices:
                        flagged_dict[note["time"]] = "dt_review"
                        count += 1
                self.me_flagged = flagged_dict
                self._me_redraw()
                for i in range(self.notebook.index("end")):
                    if "MIDI Editor" in self.notebook.tab(i, "text"):
                        self.notebook.select(i)
                        break
                self._set_global_status(
                    f"Flagged {count} note(s) in MIDI Editor for review (orange outline).", 5000)

            def _flag_duplicate_notes():
                """Flag notes that appear within 20ms of a same-lane note as dt_review."""
                if not getattr(self, "me_notes", None):
                    messagebox.showinfo("No MIDI File",
                        "Open a MIDI file in the MIDI Editor first.", parent=self.root)
                    return
                WINDOW = 20  # ms — same-lane duplicates
                sorted_notes = sorted(self.me_notes, key=lambda n: n["time"])
                flagged_times = set()
                for i, n in enumerate(sorted_notes):
                    for j in range(i + 1, len(sorted_notes)):
                        m = sorted_notes[j]
                        if m["time"] - n["time"] > WINDOW:
                            break
                        if n["lane_idx"] == m["lane_idx"]:
                            flagged_times.add(n["time"])
                            flagged_times.add(m["time"])
                flagged_dict = getattr(self, "me_flagged", {})
                for t in flagged_times:
                    flagged_dict[t] = "dt_review"
                self.me_flagged = flagged_dict
                self._me_redraw()
                for i in range(self.notebook.index("end")):
                    if "MIDI Editor" in self.notebook.tab(i, "text"):
                        self.notebook.select(i)
                        break
                self._set_global_status(
                    f"Flagged {len(flagged_times)} duplicate note(s) in MIDI Editor (orange outline).", 5000)

            def _flag_dense_notes():
                """Flag notes in dense time windows (≥8 notes in 500ms) as dt_review."""
                if not getattr(self, "me_notes", None):
                    messagebox.showinfo("No MIDI File",
                        "Open a MIDI file in the MIDI Editor first.", parent=self.root)
                    return
                WINDOW  = 500  # ms
                DENSITY = 8
                sorted_notes = sorted(self.me_notes, key=lambda n: n["time"])
                flagged_times = set()
                for i in range(len(sorted_notes)):
                    start_t = sorted_notes[i]["time"]
                    count   = 0
                    for j in range(i, len(sorted_notes)):
                        if sorted_notes[j]["time"] - start_t > WINDOW:
                            break
                        count += 1
                    if count >= DENSITY:
                        for j in range(i, len(sorted_notes)):
                            if sorted_notes[j]["time"] - start_t > WINDOW:
                                break
                            flagged_times.add(sorted_notes[j]["time"])
                flagged_dict = getattr(self, "me_flagged", {})
                for t in flagged_times:
                    flagged_dict[t] = "dt_review"
                self.me_flagged = flagged_dict
                self._me_redraw()
                for i in range(self.notebook.index("end")):
                    if "MIDI Editor" in self.notebook.tab(i, "text"):
                        self.notebook.select(i)
                        break
                self._set_global_status(
                    f"Flagged {len(flagged_times)} dense-region note(s) in MIDI Editor (orange outline).", 5000)

            def _flag_misclass_notes():
                """Run misclassification scan and flag suspicious notes (yellow/lime outlines)."""
                if not getattr(self, "me_notes", None):
                    messagebox.showinfo("No MIDI File",
                        "Open a MIDI file in the MIDI Editor first.", parent=self.root)
                    return
                try:
                    count = self._me_flag_misclassifications()
                except Exception:
                    count = 0
                self._me_redraw()
                for i in range(self.notebook.index("end")):
                    if "MIDI Editor" in self.notebook.tab(i, "text"):
                        self.notebook.select(i)
                        break
                self._set_global_status(
                    f"Flagged {count} possible misclassification(s) in MIDI Editor "
                    f"(yellow outline, lime on Ride).", 5000)

            cur_thresh = ml_thresh or 0.50
            cur_dedup  = dedup_gap or 19

            # ── Hybrid over/under per instrument ──────────────────────────
            if engine == "hybrid":
                for inst_key, display in [("kick","Kick"),("snare","Snare"),
                                          ("hihat","Hi-Hat"),("crash","Crash")]:
                    if inst_key not in hybrid_jumps:
                        continue
                    j = hybrid_jumps[inst_key]
                    ratio = j["ml_added"] / max(j["spectral"], 1)
                    over_sym  = ("too_many_kicks"  if inst_key == "kick"  else
                                 "too_many_snares" if inst_key == "snare" else
                                 "too_many_hihats" if inst_key == "hihat" else
                                 "too_many_crashes")
                    under_sym = ("too_few_kicks"   if inst_key == "kick"  else
                                 "too_few_snares"  if inst_key == "snare" else
                                 "too_few_hihats"  if inst_key == "hihat" else
                                 "too_few_crashes")

                    if ratio > 0.5 and (over_sym in checked or "lots_of_duplicates" in checked):
                        sug = min(cur_thresh + 0.12, 0.82)
                        sug_dedup = cur_dedup + 11
                        _add(1,
                            f"⚡ {display} over-detection in Hybrid:\n"
                            f"   ML added +{j['ml_added']} hits on top of {j['spectral']} spectral hits "
                            f"({int(ratio*100)}% increase)\n"
                            f"   → Raise ML confidence threshold:  {cur_thresh:.2f}  →  {sug:.2f}\n"
                            f"   → Or raise {display.lower()} dedup gap:  {cur_dedup}ms  →  {sug_dedup}ms\n"
                            f"   Why: ML is adding transients spectral did not confirm")
                        _act(f"Raise ML confidence threshold",
                             f"{cur_thresh:.2f} → {sug:.2f}",
                             lambda v=sug: self.a2m_ml_thresh_var.set(v))
                        _act(f"Raise {display} dedup gap",
                             f"{cur_dedup}ms → {sug_dedup}ms",
                             lambda k=inst_key, v=sug_dedup: _dt_apply_setting_dedup(k, v))
                        _lane = (7 if inst_key == "kick" else 2 if inst_key == "snare"
                                 else 0 if inst_key == "hihat" else 1)
                        _flg(f"Flag over-detected {display} notes",
                             f"orange outline on {display.lower()} notes",
                             lambda li=[_lane]: _flag_notes_in_lanes(li))

                    if j["ml_added"] == 0 and j["spectral"] > 0 and under_sym in checked:
                        sug = max(cur_thresh - 0.10, 0.25)
                        _add(1,
                            f"📉 {display} under-detection in Hybrid:\n"
                            f"   ML added 0 hits — threshold filtering too aggressively\n"
                            f"   → Lower ML confidence threshold:  {cur_thresh:.2f}  →  {sug:.2f}\n"
                            f"   Why: ML is rejecting all its own {display.lower()} candidates")
                        _act(f"Lower ML confidence threshold",
                             f"{cur_thresh:.2f} → {sug:.2f}",
                             lambda v=sug: self.a2m_ml_thresh_var.set(v))

            # ── ML-only over/under ────────────────────────────────────────
            elif engine == "ml":
                if any(k in checked for k in ("too_many_kicks","too_many_snares",
                                               "too_many_hihats","lots_of_duplicates")):
                    sug = min(cur_thresh + 0.10, 0.82)
                    _add(1,
                        f"⚡ Over-detection in ML mode:\n"
                        f"   → Raise ML confidence threshold:  {cur_thresh:.2f}  →  {sug:.2f}\n"
                        f"   → Or switch to Hybrid (adds spectral confirmation)\n"
                        f"   Why: Pure ML has no spectral cross-check")
                    _act("Raise ML confidence threshold",
                         f"{cur_thresh:.2f} → {sug:.2f}",
                         lambda v=sug: self.a2m_ml_thresh_var.set(v))
                    _act("Switch engine to Hybrid",
                         "ml → hybrid",
                         lambda: self.a2m_engine_var.set("hybrid"))

                if any(k in checked for k in ("too_few_kicks","too_few_snares",
                                               "too_few_hihats","too_few_crashes")):
                    sug = max(cur_thresh - 0.10, 0.25)
                    _add(1,
                        f"📉 Under-detection in ML mode:\n"
                        f"   → Lower ML confidence threshold:  {cur_thresh:.2f}  →  {sug:.2f}\n"
                        f"   → Or switch to Hybrid for better recall\n"
                        f"   Why: Threshold rejecting real hits the model detected at lower confidence")
                    _act("Lower ML confidence threshold",
                         f"{cur_thresh:.2f} → {sug:.2f}",
                         lambda v=sug: self.a2m_ml_thresh_var.set(v))
                    _act("Switch engine to Hybrid",
                         "ml → hybrid",
                         lambda: self.a2m_engine_var.set("hybrid"))

            # ── Spectral over/under ───────────────────────────────────────
            elif engine == "spectral":
                if any(k in checked for k in ("too_many_kicks","too_many_snares",
                                               "too_many_hihats","lots_of_duplicates")):
                    sug_frame = min(self.a2m_frame_var.get() + 0.15, 0.85)
                    _add(1,
                        "⚡ Over-detection in Spectral mode:\n"
                        "   → Switch to Hybrid engine — Spectral has no confidence gating\n"
                        f"   → Or raise Note threshold:  {self.a2m_frame_var.get():.2f}  →  {sug_frame:.2f}\n"
                        "   Why: Spectral flags any energy spike above threshold")
                    _act("Switch engine to Hybrid",
                         "spectral → hybrid",
                         lambda: self.a2m_engine_var.set("hybrid"))
                    _act("Raise Note threshold",
                         f"{self.a2m_frame_var.get():.2f} → {sug_frame:.2f}",
                         lambda v=sug_frame: self.a2m_frame_var.set(v))

                if any(k in checked for k in ("too_few_kicks","too_few_snares",
                                               "too_few_hihats","too_few_crashes")):
                    sug_frame = max(self.a2m_frame_var.get() - 0.10, 0.20)
                    _add(1,
                        "📉 Under-detection in Spectral mode:\n"
                        f"   → Lower Note threshold:  {self.a2m_frame_var.get():.2f}  →  {sug_frame:.2f}\n"
                        "   → Or switch to Hybrid or ML for better recall\n"
                        "   Why: Threshold too high — quiet hits fall below cutoff")
                    _act("Lower Note threshold",
                         f"{self.a2m_frame_var.get():.2f} → {sug_frame:.2f}",
                         lambda v=sug_frame: self.a2m_frame_var.set(v))
                    _act("Switch engine to Hybrid",
                         "spectral → hybrid",
                         lambda: self.a2m_engine_var.set("hybrid"))

            # ── Symptom-specific (engine-agnostic) ────────────────────────
            if "lots_of_duplicates" in checked:
                sug_dedup = cur_dedup + 12
                _add(2,
                    f"🔁 Duplicate / stacked hits:\n"
                    f"   → MIDI Editor → Dedup  (fastest fix)\n"
                    f"   → Increase global dedup gap:  {cur_dedup}ms  →  {sug_dedup}ms\n"
                    f"   Why: Two detections within dedup window kept as separate hits")
                _act("Increase global dedup gap",
                     f"{cur_dedup}ms → {sug_dedup}ms",
                     lambda v=float(sug_dedup): _dt_apply_global_dedup(v))
                _flg("Flag duplicate notes in MIDI Editor",
                     "orange outline on near-duplicate same-lane hits",
                     _flag_duplicate_notes)

            if "cymbal_misclass" in checked:
                _add(2,
                    "🥁 Cymbal misclassification (crash / hi-hat / ride):\n"
                    "   → MIDI Editor → Reclassify mode: click or drag notes to correct lane\n"
                    "   → Keep Ride Detection OFF — reclassify rides from Crash lane manually\n"
                    "   Why: ADTOF model combines crash+ride into one class — no setting fixes this")
                _flg("Flag misclassified cymbals in MIDI Editor",
                     "yellow/lime outline on suspicious onset-overlap notes",
                     _flag_misclass_notes)

            if "snare_tom_misclass" in checked:
                _add(2,
                    "🔄 Snare / tom / kick misclassification:\n"
                    "   → MIDI Editor → Reclassify mode: click a note to pick the correct lane\n"
                    "   → Or drag the note up/down to move it to the correct row\n"
                    "   Why: Tom separation relies on frequency ratios that vary per kit and recording")
                _flg("Flag misclassified snare/tom/kick notes in MIDI Editor",
                     "yellow/lime outline on suspicious onset-overlap notes",
                     _flag_misclass_notes)

            if "timing_messy" in checked:
                bpm_str = f"{bpm:.1f}" if bpm else "unknown"
                _add(2,
                    f"⏱ Timing feels off or messy  (detected BPM: {bpm_str}):\n"
                    "   → MIDI Editor → Quantize (Ctrl+Q) to snap to nearest 16th-note grid\n"
                    "   → Or use Soft Quantize for lighter nudge that preserves groove\n"
                    "   → Verify tempo map is correct first — bad BPM makes quantize worse")

            if "dense_overdetect" in checked:
                sug_dedup = cur_dedup + 12
                _add(2,
                    f"📈 Dense sections over-detected:\n"
                    f"   → Increase global dedup gap:  {cur_dedup}ms  →  {sug_dedup}ms\n"
                    "   → In Hybrid: raise ML confidence threshold\n"
                    "   → Try Metal genre preset — tuned for dense playing\n"
                    "   → MIDI Editor → Vel Filter: remove hits below velocity 35–45")
                _act("Increase global dedup gap (dense over-detection)",
                     f"{cur_dedup}ms → {sug_dedup}ms",
                     lambda v=float(sug_dedup): _dt_apply_global_dedup(v))
                if engine in ("ml","hybrid"):
                    sug = min(cur_thresh + 0.10, 0.82)
                    _act("Raise ML confidence threshold (dense over-detection)",
                         f"{cur_thresh:.2f} → {sug:.2f}",
                         lambda v=sug: self.a2m_ml_thresh_var.set(v))
                _flg("Flag dense-region notes in MIDI Editor",
                     "orange outline on notes in over-crowded time windows",
                     _flag_dense_notes)

            if "fast_underdetect" in checked:
                sug_dedup = max(cur_dedup - 8, 10)
                _add(3,
                    f"📉 Fast fills under-detected:\n"
                    f"   → Lower global dedup gap:  {cur_dedup}ms  →  {sug_dedup}ms\n"
                    "   → In ML/Hybrid: lower confidence threshold slightly\n"
                    "   → Add missing hits manually using 1–8 hotkeys at 0.5x speed")
                _act("Lower global dedup gap (fast under-detection)",
                     f"{cur_dedup}ms → {sug_dedup}ms",
                     lambda v=float(sug_dedup): _dt_apply_global_dedup(v))

            if "too_many_crashes" in checked or "too_few_crashes" in checked:
                _add(3,
                    "🔔 Crash hit counts off:\n"
                    "   → In ML/Hybrid: crash and ride share one model class\n"
                    "   → 'Too many' often means ride hits need reclassifying\n"
                    "   → Use Reclassify mode for ride hits appearing in the Crash lane")
                if "too_many_crashes" in checked:
                    _flg("Flag Crash-lane notes in MIDI Editor",
                         "orange outline on all crash notes (check for misplaced rides)",
                         lambda: _flag_notes_in_lanes([1]))

            # ── Threshold health warnings ─────────────────────────────────
            if engine in ("ml","hybrid") and ml_thresh is not None:
                if ml_thresh < 0.35:
                    sug = 0.45
                    _add(8,
                        f"⚠ ML threshold ({ml_thresh:.2f}) is very low — expect frequent false hits.\n"
                        f"   Consider raising to {sug:.2f} as a baseline.")
                    _act("Raise ML threshold to safe baseline",
                         f"{ml_thresh:.2f} → {sug:.2f}",
                         lambda v=sug: self.a2m_ml_thresh_var.set(v))
                elif ml_thresh > 0.72:
                    sug = 0.60
                    _add(8,
                        f"⚠ ML threshold ({ml_thresh:.2f}) is very high — expect missed hits.\n"
                        f"   Consider lowering to {sug:.2f} as a baseline.")
                    _act("Lower ML threshold to safe baseline",
                         f"{ml_thresh:.2f} → {sug:.2f}",
                         lambda v=sug: self.a2m_ml_thresh_var.set(v))

            # ── Fallback ──────────────────────────────────────────────────
            if not suggestions:
                if not checked:
                    _add(9,
                        "ℹ No symptoms selected and no log anomalies detected.\n"
                        "   Check the boxes that match what you see in the MIDI Editor,\n"
                        "   then click Analyze again for targeted suggestions.")
                else:
                    _add(9,
                        "ℹ Log values look within normal range for the checked symptoms.\n"
                        "   Try: MIDI Editor → Dedup, Vel Filter, or Reclassify mode.\n"
                        "   If issues persist, switch detection engine and rerun.")

            # ── Render output ─────────────────────────────────────────────
            suggestions.sort(key=lambda x: x[0])
            _dt_actions.clear()
            _dt_actions.extend(actions)
            _dt_flag_actions.clear()
            _dt_flag_actions.extend(flag_actions)

            lines = []
            lines.append("=" * 54)
            lines.append("  DETECTION TROUBLESHOOTER RESULTS")
            lines.append("=" * 54)
            lines.append(f"  Engine : {engine.upper()}")
            if bpm:             lines.append(f"  BPM    : {bpm:.1f}")
            if genre:           lines.append(f"  Genre  : {genre}")
            if ml_thresh is not None:
                                lines.append(f"  ML conf: {ml_thresh:.2f}")
            if dedup_gap:       lines.append(f"  Dedup  : {dedup_gap}ms")
            if totals:
                lines.append("")
                lines.append("  Pre-dedup hit counts (from log):")
                for k, v in totals.items():
                    lines.append(f"    {k:<10}: {v}")
            lines.append("")
            lines.append("-" * 54)
            lines.append(f"  {len(suggestions)} suggestion(s)  —  most critical first")
            lines.append("-" * 54)
            for i, (_, text) in enumerate(suggestions, 1):
                lines.append(f"\n[{i}]  {text}")
            lines.append("")
            lines.append("-" * 54)
            if _dt_actions or _dt_flag_actions:
                if _dt_actions:
                    lines.append(f"  {len(_dt_actions)} setting(s) can be auto-applied.")
                if _dt_flag_actions:
                    lines.append(f"  {len(_dt_flag_actions)} problem(s) can be flagged in the MIDI Editor.")
                lines.append("  Click 'Apply / Flag' to choose what to apply.")
            else:
                lines.append("  No auto-applicable settings for these suggestions.")
                lines.append("  Use the MIDI Editor tools listed above instead.")
            lines.append("=" * 54)

            dt_out.configure(state="normal")
            self._pretty_log_replace(dt_out, "\n".join(lines))
            dt_out.configure(state="disabled")
            _dt_apply_btn.configure(
                state="normal" if (_dt_actions or _dt_flag_actions) else "disabled")
            main.after(50, lambda: canvas.configure(scrollregion=canvas.bbox("all")))

        def _dt_copy_results():
            text = dt_out.get("1.0", tk.END).strip()
            if not text:
                messagebox.showinfo("Copy Results", "Analyze a log first, then copy the results.")
                return
            self.root.clipboard_clear()
            self.root.clipboard_append(text)
            self._set_global_status("Detection Troubleshooter results copied to clipboard.", 3500)

        def _dt_open_apply_popup():
            """Popup with two sections: ⚙ Settings and 🔍 Flag in MIDI Editor."""
            if not _dt_actions and not _dt_flag_actions:
                return
            pop = tk.Toplevel(self.root)
            pop.title("Apply / Flag Suggestions")
            pop.configure(bg="#222222")
            pop.resizable(False, False)
            pop.grab_set()

            tk.Label(pop, text="Apply / Flag Suggestions",
                     bg="#222222", fg="#ffffff",
                     font=("Segoe UI", 11, "bold")).pack(anchor="w", padx=16, pady=(14, 2))
            tk.Label(pop,
                     text="Settings take effect on the next Audio→MIDI run.\n"
                          "Flags open the MIDI Editor with problem notes highlighted in orange.",
                     bg="#222222", fg="#8b949e",
                     font=("Segoe UI", 8), justify=tk.LEFT).pack(anchor="w", padx=16, pady=(0, 8))

            ttk.Separator(pop, orient="horizontal").pack(fill=tk.X, padx=12, pady=(0, 6))

            cb_vars_settings = []
            cb_vars_flags    = []

            # ── Section 1: Audio→MIDI Settings ────────────────────────────
            if _dt_actions:
                tk.Label(pop, text="⚙  Adjust Audio→MIDI Settings",
                         bg="#222222", fg="#00d4d4",
                         font=("Segoe UI", 9, "bold")).pack(anchor="w", padx=12, pady=(0, 3))
                for act in _dt_actions:
                    var = tk.BooleanVar(value=True)
                    cb_vars_settings.append(var)
                    row = tk.Frame(pop, bg="#111827", highlightthickness=1,
                                   highlightbackground="#2b2b55")
                    row.pack(fill=tk.X, padx=12, pady=(0, 3))
                    tk.Checkbutton(row, variable=var,
                                   bg="#111827", selectcolor="#0d1117",
                                   activebackground="#111827").pack(side=tk.LEFT, padx=(8, 0), pady=6)
                    tk.Label(row, text=act["label"],
                             bg="#111827", fg="#c0c0d0",
                             font=("Segoe UI", 9, "bold"), anchor="w").pack(
                        side=tk.LEFT, padx=(4, 8), pady=6)
                    tk.Label(row, text=act["detail"],
                             bg="#111827", fg="#00d4d4",
                             font=("Consolas", 9)).pack(side=tk.RIGHT, padx=12, pady=6)

            # ── Section 2: Flag in MIDI Editor ────────────────────────────
            if _dt_flag_actions:
                if _dt_actions:
                    ttk.Separator(pop, orient="horizontal").pack(fill=tk.X, padx=12, pady=(8, 6))
                tk.Label(pop, text="🔍  Flag in MIDI Editor",
                         bg="#222222", fg="#ff8c00",
                         font=("Segoe UI", 9, "bold")).pack(anchor="w", padx=12, pady=(0, 3))
                tk.Label(pop,
                         text="Flagged notes get an orange outline.  "
                              "Use Reclassify, Dedup, or Vel Filter to fix them.",
                         bg="#222222", fg="#666",
                         font=("Segoe UI", 8), justify=tk.LEFT).pack(anchor="w", padx=16, pady=(0, 4))
                for act in _dt_flag_actions:
                    var = tk.BooleanVar(value=True)
                    cb_vars_flags.append(var)
                    row = tk.Frame(pop, bg="#1a1a35", highlightthickness=1,
                                   highlightbackground="#3a3a66")
                    row.pack(fill=tk.X, padx=12, pady=(0, 3))
                    tk.Checkbutton(row, variable=var,
                                   bg="#1a1a35", selectcolor="#0d1117",
                                   activebackground="#1a1a35").pack(side=tk.LEFT, padx=(8, 0), pady=6)
                    tk.Label(row, text=act["label"],
                             bg="#1a1a35", fg="#c0c0d0",
                             font=("Segoe UI", 9, "bold"), anchor="w").pack(
                        side=tk.LEFT, padx=(4, 8), pady=6)
                    tk.Label(row, text=act["detail"],
                             bg="#1a1a35", fg="#ff8c00",
                             font=("Segoe UI", 8)).pack(side=tk.RIGHT, padx=12, pady=6)

            ttk.Separator(pop, orient="horizontal").pack(fill=tk.X, padx=12, pady=(8, 4))

            all_cb_vars = cb_vars_settings + cb_vars_flags
            sel_row = tk.Frame(pop, bg="#222222")
            sel_row.pack(fill=tk.X, padx=12, pady=(0, 4))
            ttk.Button(sel_row, text="Select All",
                       command=lambda: [v.set(True)  for v in all_cb_vars]).pack(side=tk.LEFT, padx=(0, 6))
            ttk.Button(sel_row, text="Deselect All",
                       command=lambda: [v.set(False) for v in all_cb_vars]).pack(side=tk.LEFT)

            def _do_apply():
                applied_settings = 0
                applied_flags    = 0
                for act, var in zip(_dt_actions, cb_vars_settings):
                    if var.get():
                        try:
                            act["fn"]()
                            applied_settings += 1
                        except Exception:
                            pass
                for act, var in zip(_dt_flag_actions, cb_vars_flags):
                    if var.get():
                        try:
                            act["fn"]()
                            applied_flags += 1
                        except Exception:
                            pass
                if applied_settings:
                    try:
                        self._a2m_update_engine_ui()
                    except Exception:
                        pass
                    try:
                        self._a2m_switch_dedup_mode(
                            new_mode="hybrid" if self.a2m_engine_var.get() == "hybrid" else "spectral",
                            auto=False)
                    except Exception:
                        pass
                    try:
                        self._a2m_toggle_per_inst_dedup()
                    except Exception:
                        pass
                    self._a2m_persist_current_settings()
                total = applied_settings + applied_flags
                msg_parts = []
                if applied_settings:
                    msg_parts.append(
                        f"{applied_settings} setting(s) applied.\n"
                        "Go to Audio→MIDI and rerun the conversion to see the effect.\n"
                        "Settings are saved and will persist between sessions.")
                if applied_flags:
                    msg_parts.append(
                        f"{applied_flags} flag action(s) applied.\n"
                        "Switch to the MIDI Editor to see the orange-outlined notes.\n"
                        "Use Reclassify, Dedup, or Vel Filter to clean them up.")
                self._set_global_status(
                    f"Applied {total} troubleshooter suggestion(s).", 4000)
                pop.destroy()
                if msg_parts:
                    messagebox.showinfo("Suggestions Applied",
                        "\n\n".join(msg_parts), parent=self.root)

            btn_row2 = tk.Frame(pop, bg="#222222")
            btn_row2.pack(fill=tk.X, padx=12, pady=(4, 14))
            ttk.Button(btn_row2, text="✓  Apply Selected",
                       style="Convert.TButton",
                       command=_do_apply).pack(side=tk.LEFT, padx=(0, 8))
            ttk.Button(btn_row2, text="✕  Cancel",
                       command=pop.destroy).pack(side=tk.LEFT)

            # Center over main window
            pop.update_idletasks()
            rx = self.root.winfo_x() + (self.root.winfo_width()  - pop.winfo_width())  // 2
            ry = self.root.winfo_y() + (self.root.winfo_height() - pop.winfo_height()) // 2
            pop.geometry(f"+{rx}+{ry}")

        ttk.Button(dt_btn_row, text="🔬  Analyze Log",
                   style="Convert.TButton",
                   command=_dt_analyze).pack(side=tk.LEFT, padx=(0, 8))
        _dt_apply_btn = ttk.Button(dt_btn_row, text="⚙  Apply / Flag",
                                   command=_dt_open_apply_popup, state="disabled")
        _dt_apply_btn.pack(side=tk.LEFT, padx=(0, 8))
        ttk.Button(dt_btn_row, text="✕  Clear",
                   command=_dt_clear).pack(side=tk.LEFT)

        # v4.4.16 — Help-tab footer credit per OO5 (do NOT modify the About
        # dialog; add a subtle credit line at the bottom of the Help tab
        # content instead). Packed into `main` so it lands as the last item in
        # the scroll container.
        _help_footer_frame = ttk.Frame(main)
        _help_footer_frame.pack(fill=tk.X, pady=(20, 0))
        ttk.Label(_help_footer_frame,
                  text="Created by and for the PD community",
                  style="Sub.TLabel").pack(side=tk.RIGHT)

