        self._viz_speed            = 1.0     # active playback speed (set when play starts)
        self._viz_stretched_path   = None    # cached time-stretched audio file
        self._viz_stretched_speed  = None    # speed at which cache was generated
        self._viz_stretched_src    = None    # source audio path for cache
        self._viz_keypress_lanes   = {}      # lane_idx -> wall-clock time of last keypress
