    # ── Tester helpers ────────────────────────────────────────────────────────
    def _tester_retest(self):
        """Re-run the sync test using the manually adjusted BPM/offset values."""
        # Validate inputs
        try:
            bpm = float(self.tester_bpm_var.get())
        except ValueError:
            messagebox.showerror("Invalid BPM", "Please enter a valid BPM number.")
            return
        try:
            offset = float(self.tester_offset_var.get())
        except ValueError:
            messagebox.showerror("Invalid Offset", "Please enter a valid offset number.")
            return

        midi_path  = self.tester_midi_var.get().strip()
        audio_path = self.tester_audio_var.get().strip()
        drum_path  = self.tester_drum_var.get().strip() or None
        rlrr_path  = self.tester_rlrr_var.get().strip() or None

        if not midi_path or not audio_path:
            messagebox.showerror("Missing Files",
                                 "Please run a test first before re-testing.")
            return

        self.tester_btn.configure(state="disabled", text="Analyzing...")
        self.tester_log.configure(state="normal")
        self.tester_log.delete("1.0", tk.END)
        self.tester_log.configure(state="disabled")
        self.tester_canvas.delete("all")

        reduce = self.tester_reduce_var.get()
        diff   = self.tester_diff_var.get()

        thread = threading.Thread(
            target=self._tester_do_analysis,
            args=(midi_path, audio_path, drum_path, reduce, diff, rlrr_path,
                  bpm, offset),
            daemon=True)
        thread.start()

    def _tester_send_to_creator(self):
        """Send current BPM and offset values to the Single Song Creator."""
        # Parse BPM — required
        bpm_str = self.tester_bpm_var.get().strip()
        if not bpm_str:
            messagebox.showerror("No BPM",
                "Please run a sync test first — the BPM field will be\n"
                "auto-filled with the recommended value after testing.")
            return
        try:
            bpm = float(bpm_str)
        except ValueError:
            messagebox.showerror("Invalid BPM",
                f"'{bpm_str}' is not a valid BPM number.")
            return

        # Parse offset — default to 0.0 if blank
        offset_str = self.tester_offset_var.get().strip()
        try:
            offset = float(offset_str) if offset_str else 0.0
        except ValueError:
            offset = 0.0

        # Set manual BPM mode and populate fields
        self.auto_bpm_var.set(False)
        self.use_midi_bpm_var.set(False)
        self.bpm_var.set(f"{bpm:.2f}")
        self.offset_var.set(f"{offset:.3f}")
        self._toggle_bpm()

        # Carry over files from tester to Single Song Creator
        transferred = []
        midi  = self.tester_midi_var.get().strip()
        audio = self.tester_audio_var.get().strip()
        drum  = self.tester_drum_var.get().strip()

        if midi and os.path.exists(midi):
            self.midi_var.set(midi)
            transferred.append(f"MIDI: {os.path.basename(midi)}")
        if audio and os.path.exists(audio):
            self.audio_var.set(audio)
            transferred.append(f"Audio: {os.path.basename(audio)}")
        if drum and os.path.exists(drum):
            self.drum_audio_var.set(drum)
            transferred.append(f"Drum Audio: {os.path.basename(drum)}")

        # Switch to Single Song Creator tab
        self.notebook.select(0)

        files_str = "\n  ".join(transferred) if transferred else "(no files transferred)"
        messagebox.showinfo("Sent to Song Creator",
            f"The following have been set in the Single Song Creator:\n\n"
            f"  BPM:    {bpm:.2f}\n"
            f"  Offset: {offset:+.3f}s\n"
            f"  {files_str}\n\n"
            f"Manual BPM mode has been enabled.")
    def _tester_browse(self, var, filetypes, config_key=None):
        path = filedialog.askopenfilename(filetypes=filetypes)
        if path:
            var.set(path)
            if config_key:
                self._add_recent_file(config_key, path)

    def _tester_log(self, msg, color=None):
        self.tester_log.configure(state="normal")
        if color:
            tag = f"color_{color.replace('#','')}"
            self.tester_log.tag_configure(tag, foreground=color)
            self.tester_log.insert(tk.END, msg + "\n", tag)
        else:
            self._pretty_log_insert(self.tester_log, msg + "\n")
        self.tester_log.see(tk.END)
        self.tester_log.configure(state="disabled")
        self.root.update_idletasks()

    def _tester_start(self):
        midi_path  = self.tester_midi_var.get().strip()
        audio_path = self.tester_audio_var.get().strip()
        drum_path  = self.tester_drum_var.get().strip() or None
        rlrr_path  = self.tester_rlrr_var.get().strip() or None

        if not midi_path or not audio_path:
            messagebox.showerror("Missing Files",
                                 "Please select a MIDI file and Song Audio file.")
            return
        if not os.path.exists(midi_path):
            messagebox.showerror("File Not Found", f"MIDI not found:\n{midi_path}")
            return
        if not os.path.exists(audio_path):
            messagebox.showerror("File Not Found", f"Audio not found:\n{audio_path}")
            return

        self.tester_btn.configure(state="disabled", text="Analyzing...")
        self.tester_log.configure(state="normal")
        self.tester_log.delete("1.0", tk.END)
        self.tester_log.configure(state="disabled")
        self.tester_canvas.delete("all")

        reduce   = self.tester_reduce_var.get()
        diff     = self.tester_diff_var.get()

        thread = threading.Thread(
            target=self._tester_do_analysis,
            args=(midi_path, audio_path, drum_path, reduce, diff, rlrr_path),
            daemon=True)
        thread.start()

    def _tester_do_analysis(self, midi_path, audio_path, drum_path,
                             reduce=False, difficulty="Expert", rlrr_path=None,
                             override_bpm=None, override_offset=None):
        try:
            import librosa
            import numpy as np
            import mido

            analysis_audio = drum_path if drum_path else audio_path

            self._tester_log("=== Song Tester ===\n", "#b388ff")
            self._tester_log(f"MIDI:  {os.path.basename(midi_path)}")
            self._tester_log(f"Audio: {os.path.basename(analysis_audio)}")
            if rlrr_path:
                self._tester_log(f"RLRR:  {os.path.basename(rlrr_path)}")
            self._tester_log("")

            # ── Parse MIDI for BPM (always needed) ───────────────────────────
            self._tester_log("Parsing MIDI...", "#888888")
            mid = mido.MidiFile(midi_path)
            tpb = mid.ticks_per_beat
            midi_bpm = 120.0
            tempo_us = 500000
            for track in mid.tracks:
                for msg in track:
                    if msg.type == 'set_tempo':
                        tempo_us = msg.tempo
                        midi_bpm = 60_000_000 / msg.tempo

            # ── Load note times — prefer .rlrr if provided ────────────────────
            if rlrr_path and os.path.exists(rlrr_path):
                self._tester_log("  Using .rlrr events for alignment test "
                                 "(most accurate)", "#b388ff")
                with open(rlrr_path) as f:
                    rlrr_data = json.load(f)
                note_events = sorted([float(e["time"])
                                      for e in rlrr_data["events"]])
                # Use rlrr BPM if available
                if rlrr_data.get("bpmEvents"):
                    midi_bpm = rlrr_data["bpmEvents"][0]["bpm"]
                source_label = ".rlrr"
            else:
                self._tester_log("  Using MIDI events for alignment test", "#888888")
                note_events = []
                for track in mid.tracks:
                    abs_tick = 0
                    for msg in track:
                        abs_tick += msg.time
                        if msg.type == 'note_on' and msg.velocity > 0:
                            t = mido.tick2second(abs_tick, tpb, tempo_us)
                            note_events.append(t)
                note_events.sort()
                source_label = "MIDI"

            self._tester_log(f"  BPM: {midi_bpm:.2f}")
            self._tester_log(f"  Total notes ({source_label}): {len(note_events)}")
            self._tester_log(f"  Duration: {note_events[-1]:.1f}s\n")

            # ── Detect audio onsets ───────────────────────────────────────────
            self._tester_log("Detecting audio onsets...", "#888888")
            y, sr = librosa.load(analysis_audio, sr=None)
            audio_duration = len(y) / sr

            # ── Duration mismatch check ───────────────────────────────────────
            midi_duration = note_events[-1] if note_events else 0.0
            duration_diff = abs(midi_duration - audio_duration)
            if duration_diff > 10.0:
                self._tester_log(
                    f"\n  ⚠ DURATION MISMATCH DETECTED\n"
                    f"    MIDI last note:  {midi_duration:.1f}s\n"
                    f"    Audio length:    {audio_duration:.1f}s\n"
                    f"    Difference:      {duration_diff:.1f}s\n\n"
                    f"    This usually means one of the following:\n"
                    f"    • You loaded the wrong audio file for this MIDI\n"
                    f"    • The MIDI was generated from a different version of the song\n"
                    f"    • The audio has a long silence or intro not reflected in the MIDI\n"
                    f"    Check that your MIDI and audio files are for the same song "
                    f"before proceeding.",
                    "#e94560"
                )

            onset_frames = librosa.onset.onset_detect(
                y=y, sr=sr, units='frames', backtrack=True)
            audio_onsets = librosa.frames_to_time(onset_frames, sr=sr)
            self._tester_log(f"  Audio onsets detected: {len(audio_onsets)}")
            self._tester_log(f"  Audio duration: {audio_duration:.1f}s\n")

            # ── BPM check ─────────────────────────────────────────────────────
            self._tester_log("Checking BPM...", "#888888")
            if override_bpm is not None:
                detected_bpm = override_bpm
                self._tester_log(f"  Using override BPM: {detected_bpm:.2f}", "#b388ff")
            else:
                tempo_est, _ = librosa.beat.beat_track(y=y, sr=sr)
                detected_bpm = float(tempo_est) if np.isscalar(tempo_est) else float(tempo_est[0])
            bpm_diff = abs(midi_bpm - detected_bpm)
            bpm_match = bpm_diff < 2.0

            self._tester_log(f"  {source_label} BPM:     {midi_bpm:.2f}")
            if override_bpm is None:
                self._tester_log(f"  Detected BPM: {detected_bpm:.2f}")
            if bpm_match:
                self._tester_log(f"  ✓ BPM match — difference of {bpm_diff:.2f} BPM is acceptable",
                                 "#00d4d4")
            else:
                self._tester_log(f"  ⚠ BPM MISMATCH — difference of {bpm_diff:.2f} BPM",
                                 "#e94560")
                self._tester_log(f"    → Recommended: use manual BPM of {detected_bpm:.2f}",
                                 "#ffcc00")

            # ── Find best offset ──────────────────────────────────────────────
            self._tester_log("\nFinding best offset...", "#888888")
            if override_offset is not None:
                best_offset = override_offset
                note_arr    = np.array(note_events[:min(100, len(note_events))])
                shifted     = note_arr + best_offset
                dists       = [np.min(np.abs(audio_onsets - t)) for t in shifted]
                best_score  = float(np.mean(dists))
                self._tester_log(f"  Using override offset: {best_offset:+.3f}s", "#b388ff")
            else:
                best_offset = 0.0
                best_score  = float('inf')
                note_arr    = np.array(note_events[:min(100, len(note_events))])
                for offset_ms in range(-3000, 3000, 25):
                    offset = offset_ms / 1000.0
                    shifted = note_arr + offset
                    dists = [np.min(np.abs(audio_onsets - t)) for t in shifted]
                    score = np.mean(dists)
                    if score < best_score:
                        best_score  = score
                        best_offset = offset

            self._tester_log(f"  Best offset: {best_offset:+.3f}s")
            self._tester_log(f"  Avg note-to-onset distance: {best_score:.3f}s")
            if best_score < 0.05:
                self._tester_log("  ✓ Excellent alignment", "#00d4d4")
            elif best_score < 0.15:
                self._tester_log("  ✓ Good alignment", "#00d4d4")
            elif best_score < 0.3:
                self._tester_log("  ⚠ Fair alignment — some drift possible", "#ffcc00")
            else:
                self._tester_log("  ✗ Poor alignment — notes may feel off", "#e94560")

            # ── Section-by-section drift ──────────────────────────────────────
            self._tester_log("\nSection drift analysis...", "#888888")
            # Only analyze notes that fall within the audio duration
            # Notes past audio end have no valid onset to match against
            note_times_shifted = np.array(note_events) + best_offset
            note_times_shifted = note_times_shifted[note_times_shifted <= audio_duration]
            section_results = []
            worst_drift = 0.0

            for start in range(0, int(note_times_shifted[-1]) + 1, 20):
                end = start + 20
                section = note_times_shifted[
                    (note_times_shifted >= start) & (note_times_shifted < end)]
                if len(section) >= 3:
                    diffs = [audio_onsets[np.argmin(np.abs(audio_onsets - t))] - t
                             for t in section]
                    avg_drift = float(np.mean(diffs))
                    worst_drift = max(worst_drift, abs(avg_drift))
                    status = "✓" if abs(avg_drift) < 0.15 else \
                             "⚠" if abs(avg_drift) < 0.4 else "✗"
                    color = "#00d4d4" if status == "✓" else \
                            "#ffcc00" if status == "⚠" else "#e94560"
                    section_results.append((start, end, avg_drift, len(section), status, color))
                    self._tester_log(
                        f"  {status} {start:3d}s-{end:3d}s: drift {avg_drift:+.3f}s "
                        f"({len(section)} notes)", color)

            # ── Note density check ────────────────────────────────────────────
            self._tester_log("\nNote density check...", "#888888")

            # If reduction is enabled, estimate the expected reduced note count
            # (skip if rlrr provided — it already has reduction applied)
            effective_note_count = len(note_events)
            if reduce and difficulty != "Expert" and not rlrr_path:
                # Apply the same reduction logic to get the actual expected count
                try:
                    mid_full = mido.MidiFile(midi_path)
                    drum_notes = []
                    for track in mid_full.tracks:
                        abs_tick = 0
                        for msg in track:
                            abs_tick += msg.time
                            if msg.type == 'note_on' and msg.velocity > 0 and msg.note in MIDI_MAP:
                                drum_notes.append({
                                    "name": CLASS_TO_NAME.get(MIDI_MAP[msg.note], ""),
                                    "vel": msg.velocity,
                                    "loc": 0,
                                    "time": "%.4f" % mido.tick2second(abs_tick, tpb, tempo_us)
                                })
                    reduced = reduce_notes_for_difficulty(drum_notes, midi_bpm, difficulty)
                    effective_note_count = len(reduced)
                    self._tester_log(
                        f"  Note reduction active ({difficulty}): "
                        f"{len(note_events)} → {effective_note_count} notes", "#b388ff")
                except Exception:
                    pass  # Fall back to full count if reduction fails

            beat_dur = 60.0 / midi_bpm
            total_dur = note_events[-1] if note_events else 1
            # Generous thresholds — real drum tracks have rests and breaks
            # Only warn if significantly under/over detected
            expected_min = total_dur / beat_dur * 2
            expected_max = total_dur / beat_dur * 8
            warn_min     = expected_min * 0.60   # warn below 60% of floor
            warn_max     = expected_max * 2.0    # warn above 200% of ceiling
            density_ok   = effective_note_count >= warn_min and \
                           effective_note_count <= warn_max

            ratio_pct = effective_note_count / expected_min * 100
            self._tester_log(f"  Notes: {effective_note_count}  "
                             f"({ratio_pct:.0f}% of expected minimum)")

            if effective_note_count < warn_min:
                ratio = effective_note_count / expected_min
                suggested_sensitivity = max(0.1, 0.5 * ratio)
                self._tester_log(
                    f"  ⚠ SIGNIFICANTLY UNDER-DETECTED — only {ratio*100:.0f}% of expected",
                    "#e94560")
                self._tester_log(
                    f"    → Lower Onset Sensitivity to ~{suggested_sensitivity:.2f} "
                    f"in Audio→MIDI tab to detect more hits", "#ffcc00")
            elif effective_note_count > warn_max:
                ratio = effective_note_count / expected_max
                suggested_sensitivity = min(0.9, 0.5 * ratio)
                self._tester_log(
                    f"  ⚠ SIGNIFICANTLY OVER-DETECTED — {ratio*100:.0f}% more than expected",
                    "#e94560")
                self._tester_log(
                    f"    → Raise Onset Sensitivity to ~{suggested_sensitivity:.2f} "
                    f"in Audio→MIDI tab to reduce false hits", "#ffcc00")
            elif effective_note_count < expected_min:
                # Slightly under but within normal range
                self._tester_log(
                    f"  ✓ Slightly below floor ({ratio_pct:.0f}%) but normal — "
                    f"rests and breaks account for this", "#00d4d4")
            else:
                self._tester_log("  ✓ Note density looks good", "#00d4d4")

            # ── Instrument balance analysis ───────────────────────────────────
            self._tester_log("\nInstrument balance check...", "#888888")
            self._tester_log(
                "  ⚠  These are estimates only — always confirm in-game.",
                "#e09a3a")

            # Count notes per instrument from MIDI or rlrr
            inst_counts = {}
            if rlrr_path and os.path.exists(rlrr_path):
                with open(rlrr_path) as _f:
                    _rd = json.load(_f)
                for e in _rd["events"]:
                    name = e["name"].replace("_1", "").replace("_2", "")
                    inst_counts[name] = inst_counts.get(name, 0) + 1
            else:
                note_to_inst = {
                    35: "Kick",      36: "Kick",
                    38: "Snare",     40: "Snare",     37: "Snare",
                    42: "Hi-Hat",    46: "Hi-Hat",    44: "Hi-Hat",
                    49: "Crash",     57: "Crash",     55: "Crash",
                    51: "Ride",      59: "Ride",      53: "Ride",
                    41: "Floor Tom", 43: "Floor Tom",
                    45: "Tom 2",     47: "Tom 2",
                    48: "Tom 1",     50: "Tom 1",
                }
                mid_c = mido.MidiFile(midi_path)
                for track in mid_c.tracks:
                    for msg in track:
                        if msg.type == 'note_on' and msg.velocity > 0:
                            inst = note_to_inst.get(msg.note)
                            if inst:
                                inst_counts[inst] = inst_counts.get(inst, 0) + 1

            total_dur_s = note_events[-1] if note_events else 60
            bps = midi_bpm / 60.0

            # Expected ranges per instrument (notes per beat)
            # These are rough heuristics for rock/metal/pop
            expected = {
                "Kick":      (0.3, 2.5,  "usually 1-2 per beat"),
                "Snare":     (0.2, 1.5,  "usually on beats 2 & 4"),
                "Hi-Hat":    (0.5, 4.0,  "usually 2-4 per beat (dense)"),
                "Crash":     (0.0, 0.5,  "sparse — section transitions"),
                "Ride":      (0.0, 2.0,  "if present, similar density to hi-hat"),
                "Floor Tom": (0.0, 0.8,  "fills and accents"),
                "Tom 1":     (0.0, 0.8,  "fills and accents"),
                "Tom 2":     (0.0, 0.8,  "fills and accents"),
            }

            balance_issues = []
            for inst, (lo, hi, desc) in expected.items():
                count  = inst_counts.get(inst, 0)
                npb    = count / max(1, total_dur_s * bps)

                if count == 0 and lo > 0:
                    self._tester_log(
                        f"  ⚠ {inst:12s}: 0 hits — missing entirely ({desc})",
                        "#e94560")
                    balance_issues.append(f"{inst} missing entirely")
                elif count > 0 and npb < lo * 0.4:
                    self._tester_log(
                        f"  ⚠ {inst:12s}: {count} hits ({npb:.2f}/beat) — "
                        f"unusually low ({desc})", "#ffcc00")
                    balance_issues.append(f"{inst} low ({count} hits)")
                elif count > 0 and npb > hi * 2.5:
                    self._tester_log(
                        f"  ⚠ {inst:12s}: {count} hits ({npb:.2f}/beat) — "
                        f"unusually high, may include misclassified notes ({desc})",
                        "#ffcc00")
                    balance_issues.append(f"{inst} high ({count} hits)")
                elif count > 0:
                    self._tester_log(
                        f"  ✓ {inst:12s}: {count} hits ({npb:.2f}/beat)",
                        "#00d4d4")
                # skip instruments with 0 hits and lo==0 (optional instruments)

            if balance_issues:
                self._tester_log(
                    f"\n  💡 Tip: Open the MIDI Editor tab to inspect and fix "
                    f"misclassified notes before converting.", "#b388ff")

            # ── Overall rating ────────────────────────────────────────────────
            self._tester_log("\n" + "="*45, "#b388ff")
            issues = []
            if duration_diff > 10.0:
                issues.append(
                    f"Duration mismatch — MIDI ends at {midi_duration:.1f}s but "
                    f"audio is {audio_duration:.1f}s ({duration_diff:.1f}s difference). "
                    f"Verify you have the correct audio file for this MIDI.")
            if not bpm_match:
                issues.append(
                    f"BPM mismatch — detected {detected_bpm:.1f} BPM but MIDI is "
                    f"{midi_bpm:.1f} BPM ({bpm_diff:.1f} off). Try 'Use BPM from MIDI "
                    f"file' in the Song Creator, or set BPM manually to {detected_bpm:.1f}.")
            if best_score >= 0.3:
                issues.append(
                    f"Poor alignment — average note-to-onset distance is "
                    f"{best_score:.3f}s (ideal < 0.1s). Try adjusting the offset "
                    f"(recommended: {best_offset:+.3f}s) or check that your audio "
                    f"file matches this MIDI.")
            if worst_drift >= 0.4:
                issues.append(
                    f"Significant drift — notes fall out of sync in at least one "
                    f"section (worst drift: {worst_drift:.2f}s). This may mean the "
                    f"MIDI tempo doesn't match the song's tempo throughout. Consider "
                    f"using a MIDI with a tempo map or manually checking drift sections.")
            if not density_ok:
                issues.append(
                    f"Note density out of expected range. This can happen if the MIDI "
                    f"has too many notes for the audio (over-detected) or too few "
                    f"(under-detected). Check the MIDI Editor for obvious gaps or clusters.")

            if not issues:
                self._tester_log("  RATING: ✓ EXCELLENT — ready to convert!", "#00d4d4")
            elif len(issues) == 1:
                self._tester_log(f"  RATING: ⚠ GOOD — 1 issue to review:", "#ffcc00")
                self._tester_log(f"    • {issues[0]}", "#ffcc00")
            else:
                self._tester_log(f"  RATING: ✗ NEEDS WORK — {len(issues)} issues found:",
                                 "#e94560")
                for issue in issues:
                    self._tester_log(f"    • {issue}", "#e94560")

            self._tester_log("\n  Recommended settings for Song Creator:", "#b388ff")
            self._tester_log(f"    BPM:    {detected_bpm:.2f} (manual)")
            self._tester_log(f"    Offset: {best_offset:+.3f}s")
            self._tester_log("="*45, "#b388ff")

            # Pre-fill the adjuster fields with recommended values
            self.root.after(0, lambda b=detected_bpm, o=best_offset: (
                self.tester_bpm_var.set(f"{b:.2f}"),
                self.tester_offset_var.set(f"{o:.3f}")
            ))

            # ── Store results for auto-fix and flagging ───────────────────────
            # Build per-note flag data for MIDI Editor highlighting
            flagged_notes = {}  # time -> flag type: 'past_end', 'drift', 'balance'

            # Flag notes past audio end
            for t in note_events:
                shifted = t + best_offset
                if shifted > audio_duration:
                    flagged_notes[t] = 'past_end'

            # Flag notes in drifting sections
            for start, end, drift, count, status, color in section_results:
                if abs(drift) >= 0.15:
                    for t in note_events:
                        shifted = t + best_offset
                        if start <= shifted < end and t not in flagged_notes:
                            flagged_notes[t] = 'drift'

            # Store everything the fix functions will need
            self._tester_last_results = {
                "midi_path":     midi_path,
                "audio_path":    audio_path,
                "note_events":   note_events,
                "audio_onsets":  audio_onsets,
                "audio_duration": audio_duration,
                "best_offset":   best_offset,
                "detected_bpm":  detected_bpm,
                "midi_bpm":      midi_bpm,
                "section_results": section_results,
                "issues":        issues,
                "balance_issues": balance_issues,
                "flagged_notes": flagged_notes,
                "rlrr_path":     rlrr_path,
            }

            # Show fix panel only when issues were found
            if issues or balance_issues:
                self.root.after(0, lambda: self.tester_fix_frame.pack(
                    fill=tk.X, pady=(0, 8), before=self.tester_fix_frame.master.winfo_children()[-1]))
            else:
                self.root.after(0, lambda: self.tester_fix_frame.pack_forget())

            # ── Draw timeline ─────────────────────────────────────────────────
            self.root.after(0, lambda: self._tester_draw_timeline(
                note_events, audio_onsets, best_offset,
                section_results, audio_duration))

        except Exception as e:
            import traceback
            self._tester_log(f"\nERROR: {e}", "#e94560")
            self._tester_log(traceback.format_exc())
        finally:
            self.root.after(0, lambda: self.tester_btn.configure(
                state="normal", text="🔬  Run Sync Test"))

    def _tester_draw_timeline(self, note_events, audio_onsets,
                               offset, section_results, audio_duration):
        """Draw a visual timeline of MIDI notes vs audio onsets."""
        canvas = self.tester_canvas
        canvas.delete("all")

        if not note_events or len(audio_onsets) == 0:
            canvas.create_text(150, 100, text="No data to display",
                               fill="#888", font=("Segoe UI", 10))
            return

        # Layout
        W        = canvas.winfo_width() or 300
        px_per_s = 3.0          # pixels per second
        left     = 60
        right    = W - 10
        bar_w    = right - left
        total_h  = int(audio_duration * px_per_s) + 60

        canvas.configure(scrollregion=(0, 0, W, total_h))

        # Background sections (20s blocks)
        for i, (start, end, drift, count, status, color) in enumerate(section_results):
            y1 = int(start * px_per_s) + 30
            y2 = int(end   * px_per_s) + 30
            bg = "#1a2a1a" if status == "✓" else \
                 "#2a2a10" if status == "⚠" else "#2a1010"
            canvas.create_rectangle(left, y1, right, y2, fill=bg, outline="")
            canvas.create_text(left - 4, (y1+y2)//2,
                               text=f"{start}s", fill="#555",
                               font=("Consolas", 7), anchor="e")

        # Legend
        canvas.create_text(left + 10, 12, text="● MIDI notes",
                           fill="#b388ff", font=("Consolas", 8), anchor="w")
        canvas.create_text(left + 100, 12, text="● Audio onsets",
                           fill="#e94560", font=("Consolas", 8), anchor="w")

        # Audio onsets (red dots, left column)
        col_audio = left + int(bar_w * 0.25)
        for t in audio_onsets:
            y = int(t * px_per_s) + 30
            canvas.create_oval(col_audio-2, y-2, col_audio+2, y+2,
                               fill="#e94560", outline="")

        # MIDI notes shifted by best offset (purple dots, right column)
        col_midi = left + int(bar_w * 0.75)
        for t in note_events:
            y = int((t + offset) * px_per_s) + 30
            canvas.create_oval(col_midi-2, y-2, col_midi+2, y+2,
                               fill="#b388ff", outline="")

        # Column labels
        canvas.create_text(col_audio, 22, text="Audio",
                           fill="#e94560", font=("Consolas", 8))
        canvas.create_text(col_midi, 22, text="MIDI",
                           fill="#b388ff", font=("Consolas", 8))

