    OGG_FILE_LIMIT = 10

    def _ogg_add_files(self):
        paths = filedialog.askopenfilenames(
            title="Select audio files to convert",
            filetypes=[("Audio files", "*.mp3 *.wav *.flac *.aac *.m4a"), ("All files", "*.*")]
        )
        current = list(self.ogg_file_listbox.get(0, tk.END))
        added = 0
        for p in paths:
            if len(current) + added >= self.OGG_FILE_LIMIT:
                messagebox.showwarning("File Limit Reached",
                    f"The OGG converter is limited to {self.OGG_FILE_LIMIT} files at a time.\n"
                    f"Convert the current batch first, then add more.")
                break
            if p not in current:
                self.ogg_file_listbox.insert(tk.END, p)
                added += 1

    def _ogg_remove_selected(self):
        selected = list(self.ogg_file_listbox.curselection())
        for i in reversed(selected):
            self.ogg_file_listbox.delete(i)

    def _ogg_clear_files(self):
        self.ogg_file_listbox.delete(0, tk.END)

    def _ogg_browse_output(self):
        path = filedialog.askdirectory()
        if path:
            self.ogg_output_var.set(path)
            save_config({"output_folder_ogg": path})

    def _ogg_log(self, msg):
        self.ogg_log_text.configure(state="normal")
        self._pretty_log_insert(self.ogg_log_text, msg + "\n")
        self.ogg_log_text.see(tk.END)
        self.ogg_log_text.configure(state="disabled")
        self.root.update_idletasks()

    def _ogg_start_convert(self):
        files = list(self.ogg_file_listbox.get(0, tk.END))
        if not files:
            messagebox.showerror("No Files", "Please add at least one audio file to convert.")
            return

        output_base = self.ogg_output_var.get()
        if not output_base:
            messagebox.showerror("No Output Folder", "Please select an output folder.")
            return

        # Disable button and run in background thread
        self.ogg_convert_btn.configure(state="disabled", text="Converting...")
        self.ogg_progress.start(12)
        self.ogg_log_text.configure(state="normal")
        self.ogg_log_text.delete("1.0", tk.END)
        self.ogg_log_text.configure(state="disabled")

        thread = threading.Thread(
            target=self._ogg_do_convert,
            args=(files, output_base),
            daemon=True
        )
        thread.start()

    def _mp3_warning_popup(self):
        """
        Show a warning popup when .mp3 files are selected in the Song Converter.
        Returns True if the user wants to proceed, False to cancel.
        Respects the 'do not show again' preference.
        """
        popup = tk.Toplevel(self.root)
        popup.title("⚠  MP3 File Warning")
        popup.configure(bg="#222222")
        popup.resizable(False, False)
        popup.grab_set()  # Modal

        # Center on parent
        popup.update_idletasks()
        pw, ph = 480, 280
        px = self.root.winfo_x() + (self.root.winfo_width() - pw) // 2
        py = self.root.winfo_y() + (self.root.winfo_height() - ph) // 2
        popup.geometry(f"{pw}x{ph}+{px}+{py}")

        result = [False]

        def on_cancel():
            result[0] = False
            popup.destroy()

        # Bind the X button to cancel so closing the window = cancel
        popup.protocol("WM_DELETE_WINDOW", on_cancel)

        frame = ttk.Frame(popup, padding=20)
        frame.pack(fill=tk.BOTH, expand=True)

        ttk.Label(frame, text="⚠  MP3 File Detected", style="Header.TLabel",
                  font=("Segoe UI", 13, "bold")).pack(anchor="w", pady=(0, 10))

        ttk.Label(frame,
                  text="You have selected one or more .mp3 files for conversion.\n\n"
                       "MP3 files are much more likely to cause note/audio\n"
                       "desynchronization in Paradiddle. You should only use\n"
                       "MP3 files if you have a specific reason to do so and\n"
                       "know what you are doing.\n\n"
                       "Do you want to continue anyway?",
                  style="TLabel", justify=tk.LEFT).pack(anchor="w")

        dont_show_var = tk.BooleanVar(value=False)
        ttk.Checkbutton(frame, text="Do not show this message again",
                        variable=dont_show_var).pack(anchor="w", pady=(10, 0))

        def on_continue():
            if dont_show_var.get():
                save_config({"rlrr_skip_mp3_warning": True})
            result[0] = True
            popup.destroy()

        btn_row = ttk.Frame(frame)
        btn_row.pack(anchor="e", pady=(12, 0))
        ttk.Button(btn_row, text="Cancel", command=on_cancel).pack(side=tk.LEFT, padx=(0, 8))
        ttk.Button(btn_row, text="Continue", style="Convert.TButton",
                   command=on_continue).pack(side=tk.LEFT)

        popup.wait_window()
        return result[0]

    def _ogg_do_convert(self, files, output_base):
        try:
            from pydub import AudioSegment
        except ImportError:
            self.root.after(0, lambda: messagebox.showerror(
                "Missing Dependency",
                "A required audio component is unavailable.\n\n"
                "Please reinstall ParaKit to restore .ogg conversion.\n\n"
                "Also ensure FFmpeg is installed on your system:\n"
                "https://www.gyan.dev/ffmpeg/builds/"
            ))
            self.root.after(0, lambda: self.ogg_convert_btn.configure(
                state="normal", text="🔄  Convert to .ogg"))
            return

        # Create output subfolder
        out_dir = os.path.join(output_base, ".ogg Conversions Here")
        os.makedirs(out_dir, exist_ok=True)

        self._ogg_log("=== .ogg Converter ===\n")
        self._ogg_log(f"Output folder: {out_dir}\n")

        success_count = 0
        fail_count = 0
        converted_paths = []

        for filepath in files:
            filename = os.path.basename(filepath)
            stem = os.path.splitext(filename)[0]
            out_path = os.path.join(out_dir, stem + ".ogg")

            self._ogg_log(f"Converting: {filename}")
            try:
                audio = AudioSegment.from_file(filepath)
                audio.export(out_path, format="ogg", codec="libvorbis")
                self._ogg_log(f"  ✓ Saved: {stem}.ogg")
                success_count += 1
                converted_paths.append(out_path)
            except Exception as e:
                self._ogg_log(f"  ✗ Failed: {e}")
                fail_count += 1

        self._ogg_log(f"\n{'='*50}")
        self._ogg_log(f"Done! {success_count} converted, {fail_count} failed.")
        self._ogg_log(f"Output folder: {out_dir}")
        self._ogg_log(f"{'='*50}")

        # Check if we should skip the popup (user chose "don't show again" on MP3 warning)
        cfg = load_config()
        skip_warning = cfg.get("ogg_skip_mp3_warning", False)
        had_mp3 = any(f.lower().endswith(".mp3") for f in files)

        if skip_warning and had_mp3:
            # Silent mode — show completion popup with path info
            self.root.after(0, lambda: messagebox.showinfo(
                "Conversion Complete",
                f"{success_count} file(s) converted to .ogg.\n\n"
                f"Saved to:\n{out_dir}"
            ))
        elif success_count > 0:
            self.root.after(0, lambda: messagebox.showinfo(
                "Conversion Complete",
                f"{success_count} file(s) converted successfully!\n\n"
                f"Saved to:\n{out_dir}"
            ))

        if fail_count > 0:
            self.root.after(0, lambda: messagebox.showwarning(
                "Some Conversions Failed",
                f"{fail_count} file(s) could not be converted.\nCheck the log for details."
            ))

        self.root.after(0, self.ogg_progress.stop)
        self.root.after(0, lambda: self.ogg_convert_btn.configure(
            state="normal", text="🔄  Convert to .ogg"))

