    def _build_batch_slot(self, parent, slot_num):
        """Build one song slot with all required fields."""
        slot = {
            "midi_var":     tk.StringVar(),
            "audio_var":    tk.StringVar(),
            "drum_var":     tk.StringVar(),
            "cover_var":    tk.StringVar(),
            "title_var":    tk.StringVar(value="Untitled"),
            "artist_var":   tk.StringVar(value="Unknown"),
            "diff_var":     tk.StringVar(value="Expert"),
            "comp_var":     tk.IntVar(value=3),
            "auto_bpm_var": tk.BooleanVar(value=True),
            "bpm_var":      tk.StringVar(),
            "offset_var":   tk.StringVar(),
            "reduce_var":   tk.BooleanVar(value=False),
            "enabled_var":  tk.BooleanVar(value=(slot_num == 1)),
        }
        self._batch_slots.append(slot)

        frame = ttk.LabelFrame(parent, text=f" Song {slot_num} ", padding=10)
        frame.pack(fill=tk.X, pady=(0, 8))

        ttk.Checkbutton(frame, text=f"Enable Song {slot_num}",
                        variable=slot["enabled_var"]
                        ).grid(row=0, column=0, columnspan=3, sticky="w", pady=(0, 6))

        def frow(lbl, var, row, ft, ck=None, s=slot):
            ttk.Label(frame, text=f"{lbl}:").grid(row=row, column=0, sticky="w", padx=(0,5), pady=2)
            ent = ttk.Entry(frame, textvariable=var, width=42)
            ent.grid(row=row, column=1, sticky="ew", padx=(0,5), pady=2)
            btn_frame = ttk.Frame(frame)
            btn_frame.grid(row=row, column=2, pady=2, sticky="w")
            btn = ttk.Button(btn_frame, text="Browse...",
                             command=lambda v=var, f=ft, sl=s: self._batch_slot_browse(v, f, sl))
            btn.pack(side=tk.LEFT)
            if ck:
                self._make_recent_btn(btn_frame, ck, var, ft
                                      ).pack(side=tk.LEFT, padx=(2,0))
            for w in (ent, btn):
                self._enable_drop(w, var, config_key=ck)

        frow("MIDI File *",  slot["midi_var"],  1, [("MIDI","*.mid *.midi"),("All","*.*")],       ck="recent_midi")
        frow("Song Audio *", slot["audio_var"], 2, [("Audio","*.ogg *.mp3 *.wav *.flac"),("All","*.*")], ck="recent_audio")
        frow("Drum Audio",   slot["drum_var"],  3, [("Audio","*.ogg *.mp3 *.wav *.flac"),("All","*.*")], ck="recent_drum_audio")

        # ── Extra Stems ───────────────────────────────────────────────────────
        slot["extra_stems"] = []
        _bso = ttk.Frame(frame)
        _bso.grid(row=4, column=0, columnspan=3, sticky="ew", pady=(2, 2))
        _bso.columnconfigure(0, weight=1)

        def _bupd(s=slot, btn=None):
            if btn:
                btn.configure(state="normal" if len(s["extra_stems"]) < 4 else "disabled")

        def _badd(s=slot, container=_bso):
            if len(s["extra_stems"]) >= 4:
                return
            idx = len(s["extra_stems"]) + 1
            var = tk.StringVar()
            is_song_var = tk.BooleanVar(value=False)
            is_drum_var = tk.BooleanVar(value=True)
            row_f = ttk.Frame(container)
            row_f.pack(fill="x", pady=1)
            ttk.Label(row_f, text=f"Extra Stem {idx}:", width=14,
                      anchor="w").pack(side=tk.LEFT, padx=(0, 4))
            ent = ttk.Entry(row_f, textvariable=var, width=26)
            ent.pack(side=tk.LEFT, padx=(0, 4), fill="x", expand=True)
            ttk.Button(row_f, text="Browse…",
                       command=lambda v=var, sl=s: self._batch_slot_browse(
                           v, [("Audio files", "*.ogg *.mp3 *.wav *.flac"),
                               ("All files", "*.*")], sl)
                       ).pack(side=tk.LEFT, padx=(0, 4))
            ttk.Checkbutton(row_f, text="Drum audio", variable=is_drum_var,
                            command=lambda isd=is_drum_var, iss=is_song_var: (
                                isd.set(True), iss.set(False))
                            ).pack(side=tk.LEFT, padx=(0, 2))
            ttk.Checkbutton(row_f, text="Song audio", variable=is_song_var,
                            command=lambda isd=is_drum_var, iss=is_song_var: (
                                isd.set(False), iss.set(True))
                            ).pack(side=tk.LEFT, padx=(0, 4))
            sd = {"var": var, "is_song_var": is_song_var, "frame": row_f}
            s["extra_stems"].append(sd)

            def _brem(sdd=sd, sl=s):
                sdd["frame"].destroy()
                sl["extra_stems"].remove(sdd)
                _bupd(sl, _b_add_btn)

            ttk.Button(row_f, text="✕", width=2, command=_brem).pack(side=tk.LEFT)
            self._enable_drop(ent, var)
